      {ctx:'Een bedrijf stoot 800 ton COвӮӮ uit. De milieubelasting bedraagt вӮ¬45 per ton.',vr:'Hoeveel milieubelasting betaalt het bedrijf?',a:36000,e:'вӮ¬',u:'800 Г— вӮ¬45 = вӮ¬36.000.'},
      {ctx:'Subsidie voor zonnepanelen: вӮ¬900 per installatie. 150 huishoudens doen mee.',vr:'Totale subsidiekosten overheid?',a:135000,e:'вӮ¬',u:'150 Г— вӮ¬900 = вӮ¬135.000.'},
      {ctx:'COвӮӮ-uitstoot daalt van 1.200 naar 840 ton na invoering milieubelasting.',vr:'Met hoeveel procent daalt de uitstoot?',a:30,e:'%',u:'(1200вҲ’840)/1200 Г— 100 = 30%.'}
