// в•җв•җ NAVIGATIE в•җв•җ
function show(id, skipHash){
  document.querySelectorAll('.screen').forEach(s=>s.classList.remove('active'));
  const el = document.getElementById(id);
  if(!el) return;
  el.classList.add('active');
  window.scrollTo(0,0);
  updateBC();
  // AI Keten Trainer: laad scenario's bij openen
  if(id === 's-ai'){ setTimeout(aiLaadScherm, 50); }
  // Hash-routing: sla huidig scherm op in URL zodat Terug-knop werkt
  // try/catch: history.pushState faalt bij file://-protocol (lokaal openen)
  if(!skipHash){
    try{
      const newHash = '#' + id;
      if(window.location.hash !== newHash){
        history.pushState({screenId: id}, '', newHash);
      }
    }catch(e){}
  }
}

// Terug/Vooruit knop van de browser: herstel het juiste scherm
window.addEventListener('popstate', function(e){
  const screenId = (e.state && e.state.screenId) || (window.location.hash ? window.location.hash.slice(1) : 's-lj');
  // Escaperoom heeft eigen state-beheer: nooit via hash herstarten.
  // Timer, levens en vragen worden niet opnieuw opgebouwd via show() alleen.
  // Stop de ER netjes en stuur naar het oefenmenu.
  if(screenId === 's-er'){
    if(window._erTimerInterval){ clearInterval(window._erTimerInterval); }
    window._erKlaar = true;
    var pbw = document.getElementById('er-progress-wrap');
    if(pbw) pbw.remove();
    var overlay = document.getElementById('er-stop-overlay');
    if(overlay) overlay.style.display = 'none';
    show('s-md', true);
    return;
  }
  show(screenId, true); // skipHash=true om oneindige loop te voorkomen
});
