//  DOWNLOADS вҖ“ filter per onderwerp
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
function toonDownloads(){
  // Bijwerken van de subtitel
  var subEl = document.getElementById('dl-onderwerp-naam');
  var topicNaam = (getTopic && getTopic().t) ? getTopic().t : null;
  if(subEl) subEl.textContent = topicNaam ? 'Downloads voor: ' + topicNaam : 'Werkbladen en materialen';

  // Onderwerp-ID вҶ’ topic-sleutels die in data-topic staan
  var owMap = {
    'schaarste': ['schaarste'],
    'vraag':     ['vraag'],
    'arbeid':    ['arbeidsmarkt'],
    'bedrijf':   ['productie'],
    'overheid':  ['overheid'],
    'milieu':    ['milieu'],
    // tl-havo aliassen (zelfde bestanden, andere niveau-aanduiding)
    'behoeften': ['schaarste']
  };

  var actief = OW ? (owMap[OW] || null) : null;

  // Toon/verberg elke download-sectie op basis van data-topic
  document.querySelectorAll('#s-downloads [data-topic]').forEach(function(el){
    var topics = (el.getAttribute('data-topic') || '').split(',').map(function(s){ return s.trim(); });
    if(!actief){
      // Geen onderwerp bekend: alles tonen
      el.style.display = '';
    } else {
      var match = topics.some(function(t){ return actief.indexOf(t) !== -1; });
      el.style.display = match ? '' : 'none';
    }
  });

  // Toon de 'meer volgen'-banner altijd
  var banner = document.getElementById('dl-meer-banner');
  if(banner) banner.style.display = '';

  show('s-downloads');
}

