var btIdx = 0;
var btGeselecteerd = [];
var btFaseStap = 1; // 1=selecteer, 2=bereken
var btVoltooide = [];

function toonBT(){
  show('s-bt');
  btIdx = 0;
  btGeselecteerd = [];
  btFaseStap = 1;
  btVoltooide = [];
  btBouwVraag();
}

function btStart(){
  btIdx = 0;
  btGeselecteerd = [];
  btFaseStap = 1;
  btVoltooide = [];
  btBouwVraag();
}

function btBouwVraag(){
  var bron = BT_DATA[btIdx];
  if(!bron){ btToonEinde(); return; }

  btGeselecteerd = [];
  btFaseStap = 1;

  // Stap-indicator
  var row = document.getElementById('bt-stap-row');
  if(row){
    var dots = '';
    BT_DATA.forEach(function(b,i){
      var kls = btVoltooide.indexOf(i) > -1 ? 'klaar' : (i===btIdx ? 'actief' : '');
      dots += '<div class="bt-stap-dot '+kls+'">'+(i+1)+'</div>';
    });
    row.innerHTML = dots;
  }

  var vt = document.getElementById('bt-voortgang-txt');
  if(vt) vt.textContent = 'Bron '+(btIdx+1)+' van '+BT_DATA.length;

  // Volgende/opnieuw knoppen
  document.getElementById('bt-volgende-btn').style.display='none';
  document.getElementById('bt-opnieuw-btn').style.display='none';

  var wrap = document.getElementById('bt-vraag-container');
  if(!wrap) return;

  // Bouw tabel HTML
  var koppen = bron.kolommen.map(function(k){ return '<th>'+k+'</th>'; }).join('');
  var rijen = bron.rijen.map(function(rij,ri){
    var cellen = rij.cellen.map(function(cel,ci){
      if(ci === bron.selecteerKolom){
        return '<td class="bt-cel" data-rij="'+rij.id+'"'
          +' role="button" tabindex="0"'
          +' aria-pressed="false"'
          +' aria-label="Selecteer: '+cel+'"'
          +' onclick="btToggleCel(this,\''+rij.id+'\');"'
          +' onkeydown="if(event.key===\'Enter\'||event.key===\' \'){event.preventDefault();btToggleCel(this,\''+rij.id+'\')}"'
          +'>'+cel+'</td>';
      }
      return '<td id="bt-cel-'+rij.id+'-'+ci+'" class="bt-data-cel">'+cel+'</td>';
    }).join('');
    return '<tr id="bt-rij-'+rij.id+'">'+cellen+'</tr>';
  }).join('');

  var tabel = '<table class="bt-tabel"><thead><tr>'+koppen+'</tr></thead><tbody>'+rijen+'</tbody></table>';

  var html = '<div class="bt-bron-wrap">'
    +'<div class="bt-bron-header">рҹ“Ҡ '+bron.titel+'</div>'
    +tabel
    +'</div>'
    +'<div class="bt-instructie">'+bron.selecteerInstructie
    +' <span class="bt-sel-tel" id="bt-tel">0/'+bron.aantalVereist+' geselecteerd</span>'
    +'<button class="bt-legen-btn" onclick="btLeegSelectie()">вң• Wis selectie</button></div>'
    +'<div id="bt-fase2" style="display:none">'
      +'<div class="bt-vraag-box">'
        +'<p style="font-weight:700;margin-bottom:.5rem">вңҸпёҸ '+bron.vraag+'</p>'
        +'<div class="bt-input-rij">'
          +'<label>Jouw antwoord:</label>'
          +'<input type="number" step="0.1" class="bt-invoer" id="bt-invoer" placeholder="..." aria-label="Voer je antwoord in">'
          +'<span style="font-size:.85rem;color:var(--muted)"> '+bron.eenheid+'</span>'
        +'</div>'
        +'<button class="btn" onclick="btControleer()" style="margin-top:.5rem">Controleer вҶ’</button>'
        +'<button class="btn sec" onclick="btToonHint()" style="margin-top:.5rem;margin-left:.5rem">рҹ’Ў Hint</button>'
        +'<div class="bt-hint" id="bt-hint">'+bron.hint+'</div>'
        +'<div class="bt-feedback" id="bt-feedback"></div>'
      +'</div>'
    +'</div>';

  wrap.innerHTML = html;
}

function btToggleCel(el, rijId){
  var bron = BT_DATA[btIdx];
  var idx2 = btGeselecteerd.indexOf(rijId);
  if(idx2 > -1){
    btGeselecteerd.splice(idx2,1);
    el.classList.remove('geselecteerd');
    el.setAttribute('aria-pressed','false');
  } else {
    btGeselecteerd.push(rijId);
    el.classList.add('geselecteerd');
    el.setAttribute('aria-pressed','true');
  }
  // Update teller + live region voor schermlezers
  var tel = document.getElementById('bt-tel');
  if(tel){
    tel.textContent = btGeselecteerd.length+'/'+bron.aantalVereist+' geselecteerd';
    tel.setAttribute('aria-live','polite');
  }

  // Check of het juiste aantal is geselecteerd
  if(btGeselecteerd.length === bron.aantalVereist){
    btControleerSelectie();
  }
}

function btLeegSelectie(){
  btGeselecteerd = [];
  var bron = BT_DATA[btIdx];
  document.querySelectorAll('.bt-cel').forEach(function(el){
    el.classList.remove('geselecteerd','fout-geselecteerd','gemist');
    el.setAttribute('aria-pressed','false');
  });
  var tel = document.getElementById('bt-tel');
  if(tel) tel.textContent = '0/'+bron.aantalVereist+' geselecteerd';
  document.getElementById('bt-fase2').style.display='none';
}

function btControleerSelectie(){
  var bron = BT_DATA[btIdx];
  var relevanteIds = bron.rijen.filter(function(r){ return r.relevant; }).map(function(r){ return r.id; });
  var alleJuist = relevanteIds.every(function(id){ return btGeselecteerd.indexOf(id)>-1; })
    && btGeselecteerd.every(function(id){ return relevanteIds.indexOf(id)>-1; });

  if(alleJuist){
    // Visuele bevestiging en toon rekenopgave
    document.querySelectorAll('.bt-cel.geselecteerd').forEach(function(el){
      el.style.background='#1a7a4a';
      el.style.color='#fff';
    });
    document.getElementById('bt-fase2').style.display='block';
    document.getElementById('bt-fase2').scrollIntoView({behavior:'smooth',block:'nearest'});
  } else {
    // Markeer fouten
    btGeselecteerd.forEach(function(id){
      var el = document.querySelector('[data-rij="'+id+'"]');
      if(el && relevanteIds.indexOf(id)===-1) el.classList.add('fout-geselecteerd');
    });
    // Markeer gemiste relevante cellen als je al het max hebt geselecteerd
    relevanteIds.forEach(function(id){
      if(btGeselecteerd.indexOf(id)===-1){
        var el = document.querySelector('[data-rij="'+id+'"]');
        if(el) el.classList.add('gemist');
      }
    });
    // Kleine shake feedback
    setTimeout(function(){
      document.querySelectorAll('.bt-cel.fout-geselecteerd,.bt-cel.gemist').forEach(function(el){
        el.classList.remove('fout-geselecteerd','gemist');
      });
    }, 1800);
  }
}

function btControleer(){
  var bron = BT_DATA[btIdx];
  var inp = document.getElementById('bt-invoer');
  var val = parseFloat(inp.value.replace(',','.'));
  var fb = document.getElementById('bt-feedback');
  var volgende = document.getElementById('bt-volgende-btn');

  if(isNaN(val)){
    fb.className='bt-feedback fout';
    fb.textContent='Vul een getal in.';
    return;
  }

  if(Math.abs(val - bron.antwoord) <= bron.marge){
    fb.className='bt-feedback goed';
    fb.innerHTML='вң… Goed gedaan! '+bron.uitleg;
    btVoltooide.push(btIdx);
    // Update stap dot
    var dots = document.querySelectorAll('.bt-stap-dot');
    if(dots[btIdx]) dots[btIdx].className='bt-stap-dot klaar';
    if(btIdx < BT_DATA.length-1){
      volgende.style.display='inline-flex';
    } else {
      document.getElementById('bt-opnieuw-btn').style.display='inline-flex';
    }
    inp.disabled = true;
  } else {
    fb.className='bt-feedback fout';
    fb.innerHTML='вқҢ Niet helemaal. Controleer je selectie en berekening. <br><small>'+bron.hint+'</small>';
  }
}

function btToonHint(){
  var hint = document.getElementById('bt-hint');
  if(hint) hint.style.display = hint.style.display==='block'?'none':'block';
}

function btVolgende(){
  btIdx++;
  btGeselecteerd=[];
  btFaseStap=1;
  btBouwVraag();
  var cont = document.getElementById('bt-vraag-container');
  if(cont) cont.scrollIntoView({behavior:'smooth',block:'start'});
}

function btToonEinde(){
  var wrap = document.getElementById('bt-vraag-container');
  if(!wrap) return;
  var score = btVoltooide.length;
  var tot = BT_DATA.length;
  var pct = Math.round(score/tot*100);
  var emoji = pct>=80 ? 'рҹҸҶ' : pct>=50 ? 'рҹ‘Қ' : 'рҹ“ҡ';
  wrap.innerHTML = '<div style="text-align:center;padding:2rem 1rem">'
    +'<div style="font-size:3rem">'+emoji+'</div>'
    +'<h2 style="margin:.5rem 0">'+score+' van '+tot+' bronnen correct</h2>'
    +'<p style="color:var(--muted)">Je hebt alle bronnen doorlopen. Ga terug en oefen verder of druk op Opnieuw.</p>'
    +'</div>';
  document.getElementById('bt-opnieuw-btn').style.display='inline-flex';
  document.getElementById('bt-volgende-btn').style.display='none';
}

// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
//  EINDE BRON-TRAINER
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

function gaTerug(s){if(window.speechSynthesis)window.speechSynthesis.cancel();if(typeof _resetLuister==='function')_resetLuister(_luisterBtn,null,null);show(s);}

function bouwNiveaus(){
  if(!LJ)return;
  const g=document.getElementById('nv-grid');
  g.innerHTML='';
  (NVS[LJ]||[]).forEach(n=>{
    g.innerHTML+=`<button class="cbtn" onclick="kiesNv('${n.id}')">
      ${n.l}<span class="nb ${n.b}">${n.l}</span></button>`;
  });
}
function bouwTopics(){
  if(!LJ||!NV)return;
  const topics=(TP[LJ]||{})[NV]||[];
  const g=document.getElementById('tgrid');
  g.innerHTML='';
  topics.forEach(tp=>{
    const kd=tp.kd?`<span class="kdt">вң“ ${tp.kd}</span>`:'';
    // Voortgangsvinkje op basis van localStorage
    const gedaan = berekenTopicVoortgang(tp.id);
    const heeftGedaan = gedaan.size > 0;
    const allesGedaan = gedaan.size >= OEFENVORMEN.length;
    const vinkje = allesGedaan ? ' tcard-done-all' : heeftGedaan ? ' tcard-started' : '';
    const badge = allesGedaan ? `<span class="tcard-badge tcard-badge--done" aria-label="Volledig voltooid">вң“</span>` :
      heeftGedaan ? `<span class="tcard-badge tcard-badge--started" aria-label="${gedaan.size} oefenvormen gedaan">${gedaan.size}</span>` : '';
    g.innerHTML+=`<button type="button" class="tcard${vinkje}" onclick="kiesOw('${tp.id}')" style="position:relative;text-align:left;width:100%" data-topic-id="${tp.id}" aria-label="${tp.t}: ${tp.s}">
      ${badge}
      <div class="ico">${tp.i}</div>
      <h3>${tp.t}</h3><p>${tp.s}</p>${kd}</button>`;
  });
  document.getElementById('ow-sub').textContent=`Leerjaar ${LJ} вҖ” ${NVS[LJ].find(n=>n.id===NV)?.l}`;
  const hasKD=((TP[LJ]||{})[NV]||[]).some(t=>t.kd);
  document.getElementById('ow-kd').textContent=hasKD?'вң“ Inhoud sluit aan op de kerndoelen KD35 (economische redzaamheid) en KD36 (consument en maatschappij) van het onderbouwcurriculum.':'';
}
function getTopic(){return ((TP[LJ]||{})[NV]||[]).find(t=>t.id===OW)||{};}
