// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

function getData(){
  var base=C[OW]||{};
  // Merge TH niveau-data: voor topics die alleen in TH leven (bijv. milieu)
  // worden vr: en beg: arrays vanuit TH opgehaald als C ze niet heeft.
  var nivKey=getNivKey();
  var thObj=TH[OW]||null;
  if(thObj){
    var thData=thObj[nivKey]||thObj['bb']||thObj['k']||null;
    if(thData){
      if(!base.vr && thData.vr) base=Object.assign({},base,{vr:thData.vr});
      if(!base.beg && thData.beg) base=Object.assign({},base,{beg:thData.beg});
    }
  }
  // Niveau-bewuste escaperoom-lookup: basis en kader krijgen aparte rooms
  if(NV==='basis'||NV==='kader'){
    var prefix=NV==='basis'?'bb':'k';
    var out=Object.assign({},base);
    if(base[prefix+'_er1']) out.er1=base[prefix+'_er1'];
    if(base[prefix+'_er2']) out.er2=base[prefix+'_er2'];
    return out;
  }
  return base;
}
function updateBC(){
  const bc = document.getElementById('breadcrumb');
  const cur = document.querySelector('.screen.active')?.id || '';

  // Schermen zonder breadcrumb
  const geenBC = ['s-lj','s-nv','s-over','s-dash','s-doc','s-ai','s-sim','s-pr'];
  if(!LJ || geenBC.includes(cur)){
    bc.className = 'bc-verborgen';
    bc.style.display = 'none';
    return;
  }

  // Scherm-labels
  const schermLabels = {
    's-ow':'Onderwerpen','s-md':'Oefenen','s-sam':'Samenvatting',
    's-beg':'Begrippen','s-fc':'Flashcards','s-kop':'Koppelen',
    's-inv':'Invulopdracht','s-vr':'Oefenvragen','s-downloads':'Downloads','s-begrippen':'Begrippen','s-rekenen':'Rekenen','s-rk':'Rekensommen','s-escaperooms':'Escaperooms','s-zdw':'Zoek de Denkfout',
    's-wz':'Woordzoeker','s-fm':'Formules','s-er':'Escaperoom',
    's-fn':'Functioneel rekenen','s-po':'Praktijkopdracht',
    's-ex':'Oefenexamens','s-exw':'Examen','s-exr':'Resultaat','s-ehbo':'Examen-EHBO','s-bt':'Bron-Trainer'
  };

  const sep = '<span class="bc-sep">вҖә</span>';
  const item = (label, fn) =>
    `<span class="bc-item" onclick="${fn}">${label}</span>`;
  const huidig = (label) =>
    `<span class="bc-huidig">${label}</span>`;

  let delen = [];
  delen.push(item('рҹҸ  Home', "goHome()"));

  if(LJ){
    const nvLabel = NV ? (NVS[LJ]?.find(n=>n.id===NV)?.l || NV) : null;
    if(cur === 's-ow'){
      delen.push(huidig(`LJ ${LJ} вҖ” ${nvLabel||''}`));
    } else {
      delen.push(item(`LJ ${LJ}${nvLabel?' вҖ” '+nvLabel:''}`, "show('s-ow')"));
    }
  }

  if(OW && cur !== 's-ow'){
    const owLabel = getTopic().t || OW;
    if(cur === 's-md'){
      delen.push(huidig(owLabel));
    } else {
      delen.push(item(owLabel, "show('s-md')"));
    }
  }

  const huidigLabel = schermLabels[cur];
  if(huidigLabel && cur !== 's-ow' && cur !== 's-md'){
    delen.push(huidig(huidigLabel));
  }

  // Bouw HTML met separators
  bc.innerHTML = delen.join(sep);
  bc.className = 'bc-zichtbaar';
  bc.style.display = 'flex';
}

// в•җв•җ SAMENVATTING в•җв•җ
function toonSam(){
  const d=getData();
  document.getElementById('sam-sub').textContent=getTopic().t;
  document.getElementById('sam-c').innerHTML=d.sam||'<p>Geen samenvatting beschikbaar.</p>';
  show('s-sam');
}
// в•җв•җ BEGRIPPEN в•җв•җ
function toonBeg(){
  const d=getData();
  const el=document.getElementById('beg-list');
  el.innerHTML=(d.beg||[]).map((b,i)=>`
    <button type="button" class="bi" onclick="this.classList.toggle('open')" aria-expanded="false" aria-label="${b.t} вҖ” klik om definitie te tonen">
      <div class="trm"><span class="tog">в–ё</span>${b.t}</div>
      <div class="def">${b.d}</div>
    </button>`).join('');
  show('s-beg');
}
// в•җв•җ FLASHCARDS в•җв•җ
function toonFC(){
  const d=getData();const allBeg=d.beg||[];
  if(!allBeg.length){show('s-fc');return;}
  // Niveau-differentiatie: meer begrippen bij hoger niveau
  const nk=getNivKey();
  const maxBeg={bb:4,k:5,tl:6,h:8,v:99}[nk]||6;
  const beg=allBeg.slice(0,Math.min(maxBeg,allBeg.length));
  window._fcBeg=beg;
  if(fcI>=beg.length) fcI=0;
  const b=beg[fcI];
  document.getElementById('fc-t').textContent=b.t;
  document.getElementById('fc-d').textContent=b.d;
  document.getElementById('fc-cnt').textContent=`${fcI+1} / ${beg.length}` + (getNivKey()==='bb'?' (niveau: basis)':getNivKey()==='k'?' (niveau: kader)':'');
  document.getElementById('fc-pb').style.width=`${(fcI+1)/beg.length*100}%`;
  document.getElementById('fcard').classList.remove('flip');
  show('s-fc');
}
function flipCard(){document.getElementById('fcard').classList.toggle('flip');}
function fcN(){const d=getData();fcI=Math.min(fcI+1,(d.beg||[]).length-1);toonFC();}
function fcV(){fcI=Math.max(fcI-1,0);toonFC();}

// в•җв•җ KOPPELEN в•җв•җ
function bouwKop(){
  const d=getData();
  const allesBeg=(d.beg||[]);
  if(!allesBeg.length){
    show('s-kop');
    document.getElementById('k-res').innerHTML='<p>Geen begrippen beschikbaar.</p>';
    return;
  }
  // Max 6 willekeurige begrippen
  const beg=[...allesBeg].sort(()=>Math.random()-.5).slice(0,6);
  window._kopBeg=beg;
  kGoed=0;
  window._kopSel=null; // geselecteerde element (DOM-node)

  // Rechterkolom: shuffle definities
  const defVolgorde=[...beg].sort(()=>Math.random()-.5);

  const kl=document.getElementById('kl');
  const kr=document.getElementById('kr');

  // Linkerkolom: begrippen вҖ” data-bi = begrip-index in beg[]
  kl.innerHTML=beg.map((b,i)=>
    `<div class="ki" data-bi="${i}" data-kant="term" onclick="selKop(this)">${b.t}</div>`
  ).join('');

  // Rechterkolom: definities вҖ” data-bi = index van het bijbehorende begrip in beg[]
  kr.innerHTML=defVolgorde.map((b)=>{
    const bi=beg.findIndex(x=>x.t===b.t);
    return `<div class="ki def" data-bi="${bi}" data-kant="def" onclick="selKop(this)">${b.d}</div>`;
  }).join('');

  document.getElementById('k-res').innerHTML='';
  updKsc();
  show('s-kop');
}

function updKsc(){
  const tot=window._kopBeg?window._kopBeg.length:0;
  document.getElementById('ksc').textContent=`${kGoed} / ${tot} gekoppeld`;
}

function selKop(el){
  // Al goed gekoppeld? Negeer
  if(el.classList.contains('ok')) return;

  const vorige=window._kopSel;

  // Geen vorige selectie вҖ” markeer dit element
  if(!vorige){
    el.classList.add('sel');
    window._kopSel=el;
    return;
  }

  // Zelfde element opnieuw aangeklikt вҖ” deselecteer
  if(vorige===el){
    el.classList.remove('sel');
    window._kopSel=null;
    return;
  }

  // Zelfde kant (beide term of beide def) вҖ” wissel selectie
  if(vorige.dataset.kant===el.dataset.kant){
    vorige.classList.remove('sel');
    el.classList.add('sel');
    window._kopSel=el;
    return;
  }

  // Andere kant вҖ” controleer of bi-waarden overeenkomen
  const biVorige=parseInt(vorige.dataset.bi);
  const biNieuw =parseInt(el.dataset.bi);

  if(biVorige===biNieuw){
    // Goed koppel!
    [vorige,el].forEach(e=>{e.classList.remove('sel');e.classList.add('ok');});
    window._kopSel=null;
    kGoed++;
    updKsc();
    if(kGoed===window._kopBeg.length){
      markeerGedaan('kop');
      document.getElementById('k-res').innerHTML=`
        <div class="sbox">
          <div class="big">рҹҺү</div>
          <p>Alle ${kGoed} begrippen goed gekoppeld!</p>
          <div class="na-oefening-btns">
            <button class="btn" onclick="bouwKop()">рҹ”„ Nieuw spel</button>
            <button class="btn sec" onclick="go('vr')">вңҸпёҸ Oefenvragen</button>
            <button class="btn sec" onclick="gaTerug('s-md')">вҶҗ Terug</button>
          </div>
        </div>`;
    }
  } else {
    // Fout вҖ” rode schudanimatie
    [vorige,el].forEach(e=>{
      e.classList.add('no');
      setTimeout(()=>{e.classList.remove('no','sel');},700);
    });
    window._kopSel=null;
  }
}

// в•җв•җ INVULOEFENING в•җв•җ
function toonInv(){
  const d=getData();const iv=d.iv||[];
  if(!iv.length){show('s-inv');document.getElementById('iv-c').innerHTML='<p>Geen invuloefeningen beschikbaar.</p>';return;}
  if(ivI>=iv.length){
    document.getElementById('iv-c').innerHTML=`<div class="sbox">
      <div class="big">${ivSc}/${iv.length}</div>
      <p>${ivSc>=Math.ceil(iv.length*0.7)?'рҹҺү Super!':'Bijna! Probeer het nog eens.'}</p>
      <div class="na-oefening-btns">
        <button class="btn" onclick="ivI=0;ivSc=0;toonInv()">рҹ”„ Opnieuw</button>
        <button class="btn sec" onclick="go('fc')">рҹғҸ Flashcards</button>
        <button class="btn sec" onclick="gaTerug('s-md')">вҶҗ Terug</button>
      </div>
    </div>`;
    markeerGedaan('iv');
    document.getElementById('iv-chk').style.display='none';
    document.getElementById('iv-nxt').style.display='none';
    show('s-inv');return;
  }
  const item=iv[ivI];
  const zin=item.z.replace('_____','<input class="iinp" id="iv-inp" type="text" placeholder="..."/>');
  document.getElementById('iv-c').innerHTML=`<div class="ibox"><div class="izin">${zin}</div><div class="fb" id="iv-fb"></div></div>`;
  document.getElementById('iv-pb').style.width=`${ivI/iv.length*100}%`;
  document.getElementById('iv-chk').style.display='';
  document.getElementById('iv-nxt').style.display='none';
  const inp=document.getElementById('iv-inp');
  if(inp) inp.addEventListener('keydown',e=>{if(e.key==='Enter')checkInvul();});
  show('s-inv');
}
function checkInvul(){
  const d=getData();const item=(d.iv||[])[ivI];if(!item)return;
  const inp=document.getElementById('iv-inp');if(!inp)return;
  const val=inp.value.trim().toLowerCase();
  const ok=val===item.a.toLowerCase()||val.includes(item.a.toLowerCase())||item.a.toLowerCase().includes(val)&&val.length>=3;
  const fb=document.getElementById('iv-fb');
  if(ok){inp.classList.add('ok');fb.className='fb goed show';fb.textContent=`вң“ Goed! ${item.u}`;ivSc++;}
  else{inp.classList.add('no');fb.className='fb fout show';fb.textContent=`вң— Het antwoord is: "${item.a}". ${item.u}`;}
  inp.disabled=true;
  document.getElementById('iv-chk').style.display='none';
  document.getElementById('iv-nxt').style.display='';
}
function nextInvul(){ivI++;toonInv();}

// в•җв•җ ADAPTIEVE OEFENVRAGEN в•җв•җ
// Werkt met d:-veld (1=basis, 2=midden, 3=moeilijk)
// Begin altijd met d:1 vragen. Na вүҘ70% goed (min. 2 vragen) stap je op naar d:2, dan d:3.
let _vrPool=[];        // gesorteerde vragenpool voor deze sessie
let _vrNiv=1;          // huidig moeilijkheidsniveau (1-3)
let _vrNivGoed=0;      // correct bij huidig niveau
let _vrNivTotaal=0;    // gesteld bij huidig niveau

// в”Җв”Җ Encrypted Answer Keys в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// Antwoordindices (v.c) worden opgeslagen als Base64-strings in de vragendata.
// _dc() decodeert ze runtime, zodat de broncode geen leesbare indices bevat.
// Gebruik: _dc('MQ==') вҶ’ 1  |  _ec(2) вҶ’ 'Mg=='
function _ec(n){ try{return btoa(String(n));}catch(e){return String(n);} }
function _dc(s){
  if(typeof s==='number') return s; // fallback voor ongecodeerde vragen
  try{ return parseInt(atob(s),10); }catch(e){ return parseInt(s,10)||0; }
}
// Patch een vragenobject zodat v.c altijd als integer beschikbaar is
function _patchVraag(v){
  if(v && typeof v.c==='string') v.c=_dc(v.c);
  return v;
}
// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

// в”Җв”Җ Zoek de Denkfout (ZDW) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// Oefeningen waarbij de leerling een foute redenering moet aanklikken.
