function erGameOverMetBonus(reden){
  // Bij tijdslimiet: geen herkansing mogelijk
  if(reden==='tijd'){erGameOver(reden);return;}
  window._erKlaar=true;clearInterval(window._erTimerInterval);
  var pbw=document.getElementById('er-progress-wrap');if(pbw)pbw.remove();
  // Kies een willekeurige bonusvraag
  var bv=ER_BONUS_VRAGEN[Math.floor(Math.random()*ER_BONUS_VRAGEN.length)];
  var opties=bv.o.map(function(o,j){
    return '<button class="er-opt" onclick="erBonusAntwoord('+j+','+bv.c+')" style="margin:.3rem 0"><span class="er-opt-letter">'+['A','B','C','D'][j]+'</span><span class="er-opt-tekst">'+o+'</span></button>';
  }).join('');
  document.getElementById('er-c').innerHTML=
    '<div class="er-gameover">'
    +'<div style="font-size:2.5rem;margin-bottom:.4rem">&#128128;</div>'
    +'<h2 style="color:#ff8888">GEEN LEVENS MEER</h2>'
    +'<p style="font-family:var(--er-font);font-size:.82rem;color:#ffcc44;margin:.6rem 0">Je kunt 1 leven terugverdienen door deze bonusvraag te beantwoorden!</p>'
    +'<div style="background:rgba(0,80,40,.3);border:1px solid #00ff88;border-radius:6px;padding:.9rem 1rem;margin:.8rem 0;text-align:left">'
    +'<div style="font-family:var(--er-font);font-size:.7rem;color:#ffcc44;letter-spacing:.08em;margin-bottom:.5rem">&#9888; BONUSVRAAG вҖ” MOEILIJKHEID: HOOG</div>'
    +'<div class="er-vraag" style="font-size:.9rem">'+bv.q+'</div>'
    +'<div id="er-bonus-opties">'+opties+'</div>'
    +'<div class="er-feedback" id="er-bonus-fb" style="display:none"></div>'
    +'</div>'
    +'<div class="na-oefening-btns" style="margin-top:1rem">'
    +'<button class="btn sec" onclick="erGameOver(\'levens\')">&#8592; Toch stoppen</button>'
    +'</div></div>';
}

function erBonusAntwoord(gekozen,correct){
  var er=getErData();
  document.querySelectorAll('#er-bonus-opties .er-opt').forEach(function(b){b.disabled=true;});
  var fb=document.getElementById('er-bonus-fb');
  if(gekozen===correct){
    window._erLevens=1;
    window._erKlaar=false;
    fb.style.display='block';fb.className='er-feedback er-fb-goed';
    fb.innerHTML='<strong>&#10004;</strong> CORRECT! Je verdient 1 leven terug. De escaperoom gaat verder!';
    setTimeout(function(){
      window._erTijdSec=Math.max(60,window._erTijdSec);
      window._erTimerInterval=setInterval(erTick,1000);
      erUpdateLevens();
      renderEr(er);
    },2000);
  } else {
    var bv=ER_BONUS_VRAGEN.filter(function(v){return v.q===document.querySelector('#er-c .er-vraag').textContent;})[0];
    var uitleg=bv?bv.u:'Helaas, dat was niet het goede antwoord.';
    document.querySelectorAll('#er-bonus-opties .er-opt').forEach(function(b,j){
      if(j===correct)b.classList.add('er-opt-goed');
      else if(j===gekozen)b.classList.add('er-opt-fout');
    });
    fb.style.display='block';fb.className='er-feedback er-fb-fout';
    fb.innerHTML='<strong>&#10008;</strong> Helaas fout. '+uitleg+'<br><span style="color:#ffaaaa;font-size:.8rem">Je kunt de escaperoom opnieuw proberen.</span>';
    setTimeout(function(){erGameOver('levens');},3000);
  }
}

function erGameOver(reden){
  window._erKlaar=true;clearInterval(window._erTimerInterval);
  var pbw=document.getElementById('er-progress-wrap');if(pbw)pbw.remove();
  var boodschap=reden==='tijd'?'&#9200; TIJD IS OM. DE DEUR BLIJFT GESLOTEN.':'&#128128; GEEN LEVENS MEER. JE BENT GEPAKT.';
  document.getElementById('er-c').innerHTML=
    '<div class="er-gameover">'
    +'<div style="font-size:3.5rem;margin-bottom:.5rem">'+(reden==='tijd'?'&#9200;':'&#9760;')+'</div>'
    +'<h2>GAME OVER</h2>'
    +'<p style="font-family:var(--er-font);font-size:.85rem;color:#ff8888;margin:.7rem 0">'+boodschap+'</p>'
    +'<p style="font-family:var(--er-font);font-size:.78rem;color:#5a4a4a;margin-top:.5rem">Je was bij opdracht '+(erI+1)+'.</p>'
    +'<div class="na-oefening-btns" style="margin-top:1.8rem">'
    +'<button class="btn" onclick="toonEr('+erM+')">&#128260; OPNIEUW PROBEREN</button>'
    +'<button class="btn sec" onclick="gaTerug(\'s-md\')">&#8592; TERUG</button>'
    +'</div></div>';
}

