function toonRH(){
  show('s-rh');
  rhTab('procent');
}

function rhTab(tab){
  document.querySelectorAll('.rh-tab').forEach(t=>t.classList.remove('active'));
  const actief=document.querySelector(`.rh-tab[onclick="rhTab('${tab}')"]`);
  if(actief) actief.classList.add('active');
  document.getElementById('rh-inhoud').innerHTML=RH_CONTENT[tab]||'';
}

