// в•җв•җ SESSIE-VOORTGANG (in-memory, gereset bij refresh) в•җв•җ
const GEDAAN = {};

// Laad opgeslagen voortgang
try{
  const _vp=JSON.parse(localStorage.getItem('vla_voortgang')||'{}');
  Object.keys(_vp).forEach(k=>{ GEDAAN[k]=new Set(_vp[k]); });
}catch(e){}

function markeerGedaan(modus){
  if(!OW) return;
  const sleutel = LJ+'_'+NV+'_'+OW;
  if(!GEDAAN[sleutel]) GEDAAN[sleutel] = new Set();
  GEDAAN[sleutel].add(modus);
  // Sla op in localStorage
  try {
    const opgeslagen = JSON.parse(localStorage.getItem('vla_voortgang')||'{}');
    if(!opgeslagen[sleutel]) opgeslagen[sleutel] = [];
    if(!opgeslagen[sleutel].includes(modus)) opgeslagen[sleutel].push(modus);
    localStorage.setItem('vla_voortgang', JSON.stringify(opgeslagen));
  } catch(e){}
  updateVoortgangUI();
  registreerActieveDag(); // nieuw: streak bijhouden
  registreerModuleID(modus); // module mastery ID
  // Check of niveau volledig voltooid is (level-up popup)
  setTimeout(checkNiveauCompleet, 600);
}

function laadVoortgang(){
  try {
    const opgeslagen = JSON.parse(localStorage.getItem('vla_voortgang')||'{}');
    Object.keys(opgeslagen).forEach(sleutel => {
      GEDAAN[sleutel] = new Set(opgeslagen[sleutel]);
    });
  } catch(e){}
}

function resetVoortgang(){
  try {
    localStorage.removeItem('vla_voortgang');
    localStorage.removeItem('vla_activiteit');
    localStorage.removeItem('vla_quiz_scores_v2');
    localStorage.removeItem('vla_flashcard_done');
    localStorage.removeItem('vla_casus_done');
    sessionStorage.removeItem('ehboBekeken');
  } catch(e){}
  Object.keys(GEDAAN).forEach(k => delete GEDAAN[k]);
  window.ltScores = [];
  updateVoortgangUI();
  toonMelding('Voortgang gewist вң“');
}

function toonMelding(tekst){
  let el = document.getElementById('snackbar');
  if(!el){ el=document.createElement('div'); el.id='snackbar'; document.body.appendChild(el); }
  el.textContent = tekst;
  el.className = 'snackbar-show';
  setTimeout(() => el.className = '', 2500);
}

function updateVoortgangUI(){
  const sleutel = `${LJ}_${NV}_${OW}`;
  const gedaan = GEDAAN[sleutel] ? GEDAAN[sleutel].size : 0;
  const totaal = 7; // th, fc, kop, iv, vr, rk, er1
  const strip = document.getElementById('voortgang-strip');
  if(strip){
    strip.innerHTML = gedaan > 0
      ? `<span class="vt-label">вң… ${gedaan} van ${totaal} oefenvormen gedaan deze sessie</span>
         <div class="vt-bar"><div class="vt-fill" style="width:${Math.round(gedaan/totaal*100)}%"></div></div>`
      : '';
  }
  // Zet vinkje op mode-cards
  document.querySelectorAll('[data-modus]').forEach(el => {
    const m = el.getAttribute('data-modus');
    const isDone = GEDAAN[sleutel] && GEDAAN[sleutel].has(m);
    el.classList.toggle('mcard-done', isDone);
  });
}


// в”Җв”Җв”Җ DASHBOARD & STREAK SYSTEEM в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

const ALLE_TOPICS = ['behoeften','vraag','geld','arbeid','inkomen','conjunctuur','overheid','sparen','bedrijf','markt','buitenland','schaarste','groei'];
const TOPIC_LABELS = {behoeften:'Behoeften',vraag:'Vraag & aanbod',geld:'Geld',arbeid:'Arbeid',inkomen:'Inkomen',conjunctuur:'Conjunctuur',overheid:'Overheid',sparen:'Sparen & lenen',bedrijf:'Bedrijf',markt:'Markt',buitenland:'Buitenland',schaarste:'Schaarste',groei:'Groei'};
const TOPIC_ICONS = {behoeften:'рҹӣ’',vraag:'рҹ“Ҳ',geld:'рҹ’¶',arbeid:'рҹ‘·',inkomen:'рҹ’°',conjunctuur:'рҹ“ү',overheid:'рҹҸӣпёҸ',sparen:'рҹҸҰ',bedrijf:'рҹҸӯ',markt:'рҹҸӘ',buitenland:'рҹҢҚ',schaarste:'вҡЎ',groei:'рҹҢұ'};
const OEFENVORMEN = ['th','fc','vr','kop','iv','er1','er2'];
const OEFENVORMEN_LABELS = {th:'Theorie',fc:'Flashcards',vr:'Oefenvragen',kop:'Koppelopdracht',iv:'Invulopdracht',er1:'Escaperoom 1',er2:'Escaperoom 2'};

function getDagSleutel(date){
  const d = date || new Date();
  return d.getFullYear()+'-'+(d.getMonth()+1)+'-'+d.getDate();
}

function registreerActieveDag(){
  // Defer naar idle time: blokkeert de laadtijd niet
  var doe = function(){
    try{
      const data = JSON.parse(localStorage.getItem('vla_activiteit')||'{}');
      data[getDagSleutel()] = true;
      localStorage.setItem('vla_activiteit', JSON.stringify(data));
    }catch(e){}
  };
  if(typeof requestIdleCallback === 'function'){
    requestIdleCallback(doe, {timeout:2000});
  } else {
    setTimeout(doe, 500);
  }
}

function berekenStreak(){
  try{
    const data = JSON.parse(localStorage.getItem('vla_activiteit')||'{}');
    let streak = 0;
    const vandaag = new Date();
    const start = data[getDagSleutel(vandaag)] ? 0 : 1;
    for(let i = start; i < 365; i++){
      const d = new Date(vandaag);
      d.setDate(d.getDate() - i);
      if(data[getDagSleutel(d)]){
        streak++;
      } else {
        // Weekend-vrijstelling: skip zaterdag(6) en zondag(0) bij telling
        const dw = d.getDay();
        if(dw === 6 || dw === 0) continue; // zaterdag of zondag: niet meetellen als break
        break;
      }
    }
    return streak;
  }catch(e){ return 0; }
}

// в•җв•җ updateStreak: wordt bij paginaladen aangeroepen в•җв•җ
// Logica: volgende dag вҶ’ streak loopt door, dag overgeslagen вҶ’ reset naar 1 (als vandaag actief),
// Weekend-vrijstelling: vrijdag вҶ’ maandag telt NIET als overgeslagen dag.
// Zelfde dag вҶ’ niets. Geeft nieuwe streakwaarde terug.
function updateStreak(){
  try{
    const data = JSON.parse(localStorage.getItem('vla_activiteit')||'{}');
    const vandaag = getDagSleutel();
    const gisteren = getDagSleutel(new Date(Date.now() - 864e5));

    // Als vandaag al geregistreerd: geen actie nodig
    if(data[vandaag]) return berekenStreak();

    // Gisteren actief? Streak loopt door
    if(data[gisteren]) return berekenStreak();

    // Weekend-vrijstelling check:
    // Als vandaag maandag is (dag 1) en vrijdag (3 dagen geleden) actief was вҶ’ geen reset
    const nu = new Date();
    const dagVdWeek = nu.getDay(); // 0=zo,1=ma,2=di,...,6=za
    if(dagVdWeek === 1){ // Maandag
      const vrijdag = getDagSleutel(new Date(Date.now() - 3*864e5));
      if(data[vrijdag]) return berekenStreak(); // vrijdagвҶ’maandag = geen break
    }
    // Als vandaag dinsdag is en zaterdag/zondag tussenliggen (ma overgeslagen maar vrijdag actief was)
    if(dagVdWeek === 2){ // Dinsdag
      const vrijdag = getDagSleutel(new Date(Date.now() - 4*864e5));
      const maandag = getDagSleutel(new Date(Date.now() - 864e5));
      if(data[vrijdag] && !data[maandag]) return berekenStreak(); // vrijdagвҶ’dinsdag = geen break
    }

    // Langer dan 1 dag niets gedaan + eerder wГ©l actief? Reset nodig.
    const heeftGeschiedenis = Object.keys(data).length > 0;
    if(heeftGeschiedenis){
      const ouderActief = Object.keys(data).some(k => k < gisteren);
      if(ouderActief && !data[gisteren]){
        return 0;
      }
    }
    return berekenStreak();
  }catch(e){ return 0; }
}

// в•җв•җ NIVEAU VOLTOOIING: level-up popup в•җв•җ
function checkNiveauCompleet(){
  try{
    const opgeslagen = JSON.parse(localStorage.getItem('vla_voortgang')||'{}');
    const getoondKey = 'vla_levelup_getoond';
    const alGetoond = JSON.parse(localStorage.getItem(getoondKey)||'{}');

    // Check: zijn alle VMBO-TL topics Г— oefenvormen voltooid?
    const niveaus = [
      { label:'VMBO-TL', check: k => k.includes('TL') || k.includes('tl') },
      { label:'VMBO-Basis', check: k => k.includes('Basis') || k.includes('basis') || k.includes('kader') },
    ];

    for(const niv of niveaus){
      if(alGetoond[niv.label]) continue;
      const relevante = ALLE_TOPICS.filter(t => {
        // Check of dit topic oefenvormen heeft voor dit niveau
        const sleutels = Object.keys(opgeslagen).filter(k => k.endsWith('_'+t) && niv.check(k));
        return sleutels.length > 0;
      });
      if(relevante.length === 0) continue;

      const alleVolledig = relevante.every(topic => {
        const gedaanSet = new Set();
        Object.keys(opgeslagen).filter(k => k.endsWith('_'+topic) && niv.check(k))
          .forEach(k => (opgeslagen[k]||[]).forEach(v => gedaanSet.add(v)));
        return gedaanSet.size >= OEFENVORMEN.length;
      });

      if(alleVolledig){
        alGetoond[niv.label] = true;
        localStorage.setItem(getoondKey, JSON.stringify(alGetoond));
        toonLevelUpPopup(niv.label);
        return;
      }
    }

    // Fallback: check of 100% totaal behaald
    const totaal = berekenTotaalScore();
    const max = ALLE_TOPICS.length * OEFENVORMEN.length;
    if(totaal >= max && !alGetoond['alles']){
      alGetoond['alles'] = true;
      localStorage.setItem(getoondKey, JSON.stringify(alGetoond));
      toonLevelUpPopup('alles');
    }
  }catch(e){}
}

function toonLevelUpPopup(niveau){
  const popup = document.getElementById('levelup-popup');
  const card = document.getElementById('levelup-card');
  const icon = document.getElementById('levelup-icon');
  const titel = document.getElementById('levelup-titel');
  const tekst = document.getElementById('levelup-tekst');
  if(!popup || !card) return;

  if(niveau === 'alles'){
    icon.textContent = 'рҹҸҶ';
    titel.textContent = 'Wauw вҖ” alles voltooid!';
    tekst.textContent = 'Je hebt elke oefenvorm van vlaconomie.nl afgerond. Je bent examenklaar. Goed gedaan! рҹҺү';
  } else if(niveau === 'VMBO-TL'){
    icon.textContent = 'рҹҺ“';
    titel.textContent = 'VMBO-TL niveau behaald!';
    tekst.textContent = 'Je hebt alle theorie, flashcards, oefenvragen en escaperooms van het VMBO-TL niveau afgerond. Top werk!';
  } else {
    icon.textContent = 'вӯҗ';
    titel.textContent = niveau + ' voltooid!';
    tekst.textContent = 'Je hebt alle oefenvormen van ' + niveau + ' afgerond. Ga zo door!';
  }

  popup.style.display = 'flex';
  // Trigger animatie
  requestAnimationFrame(() => requestAnimationFrame(() => {
    card.style.transform = 'scale(1)';
    card.style.opacity = '1';
  }));

  // Confetti!
  setTimeout(() => confetti100Regen(), 200);
}

function sluitLevelUp(){
  const popup = document.getElementById('levelup-popup');
  const card = document.getElementById('levelup-card');
  if(!popup || !card) return;
  card.style.transform = 'scale(.85)';
  card.style.opacity = '0';
  setTimeout(() => { popup.style.display = 'none'; }, 350);
}

function berekenTopicVoortgang(topic){
  // Telt over alle leerjaar/niveau combinaties hoeveel unieke oefenvormen gedaan
  const gedaanSet = new Set();
  try{
    const opgeslagen = JSON.parse(localStorage.getItem('vla_voortgang')||'{}');
    Object.keys(opgeslagen).forEach(sleutel => {
      if(sleutel.endsWith('_'+topic)){
        (opgeslagen[sleutel]||[]).forEach(v => gedaanSet.add(v));
      }
    });
  }catch(e){}
  return gedaanSet;
}

function berekenTotaalScore(){
  // Score: voor elk topic maximaal 7 punten (1 per oefenvorm)
  let totaal = 0;
  ALLE_TOPICS.forEach(topic => {
    const gedaan = berekenTopicVoortgang(topic);
    totaal += Math.min(gedaan.size, OEFENVORMEN.length);
  });
  return totaal;
}

function toonDashboard(){
  const streak = berekenStreak();
  const totaalScore = berekenTotaalScore();
  const maxScore = ALLE_TOPICS.length * OEFENVORMEN.length; // 13 Г— 7 = 91
  const pct = Math.round(totaalScore / maxScore * 100);

  // Header streak badge
  const headerNum = document.getElementById('header-streak-num');
  if(headerNum) headerNum.textContent = streak > 0 ? streak : '0';

  // Hero
  document.getElementById('dash-streak-num').textContent = streak;
  document.getElementById('dash-totaal-text').textContent = `${totaalScore} van ${maxScore} oefenvormen voltooid (${pct}%)`;
  document.getElementById('dash-totaal-balk').style.width = pct+'%';

  // Badges
  const badges = [];
  if(streak >= 3)  badges.push({icon:'рҹ”Ҙ',label:'3 dagen op rij',kleur:'#ff8c00'});
  if(streak >= 7)  badges.push({icon:'вҡЎ',label:'Weeksteak',kleur:'#f0c040'});
  if(streak >= 14) badges.push({icon:'рҹ’Һ',label:'2 weken!',kleur:'#4fc3f7'});
  if(totaalScore >= 20) badges.push({icon:'рҹҢҹ',label:'20 oefenvormen',kleur:'#ab47bc'});
  if(totaalScore >= 50) badges.push({icon:'рҹҸҶ',label:'Halve weg',kleur:'#26a69a'});
  if(pct === 100)  badges.push({icon:'рҹҺ“',label:'Alles voltooid!',kleur:'#2ecc71'});
  // Altijd minstens "eerste stap" als er iets gedaan is
  if(totaalScore > 0 && badges.length === 0) badges.push({icon:'рҹ‘Ј',label:'Eerste stap',kleur:'#78909c'});

  document.getElementById('dash-badges').innerHTML = badges.map(b =>
    `<span class="dash-badge" style="--badge-kleur:${b.kleur}">${b.icon} ${b.label}</span>`
  ).join('');

  // Per-topic grid
  const grid = document.getElementById('dash-grid');
  grid.innerHTML = ALLE_TOPICS.map(topic => {
    const gedaan = berekenTopicVoortgang(topic);
    const cnt = Math.min(gedaan.size, OEFENVORMEN.length);
    const tp = OEFENVORMEN.length;
    const p = Math.round(cnt/tp*100);
    const kleur = p === 100 ? '#2ecc71' : p >= 50 ? '#f0c040' : p > 0 ? '#4a90d9' : '#e0e0e0';
    const icoonstatus = p === 100 ? 'вң…' : p > 0 ? TOPIC_ICONS[topic] : 'в¬ң';
    return `<div class="dash-topic-card${p===100?' dash-topic-card--done':''}">
      <div class="dash-topic-ico">${icoonstatus}</div>
      <div class="dash-topic-naam">${TOPIC_LABELS[topic]}</div>
      <div class="dash-voortgang-bg">
        <div class="dash-voortgang-fg" style="width:${p}%;background:${kleur}"></div>
      </div>
      <div class="dash-topic-teller">${cnt}/${tp} gedaan</div>
    </div>`;
  }).join('');

  // Weekkalender
  const weekEl = document.getElementById('dash-week');
  let weekHTML = '';
  let activiteit = {};
  try{ activiteit = JSON.parse(localStorage.getItem('vla_activiteit')||'{}'); }catch(e){}
  const dagNamen = ['zo','ma','di','wo','do','vr','za'];
  for(let i=6; i>=0; i--){
    const d = new Date();
    d.setDate(d.getDate() - i);
    const sleutel = getDagSleutel(d);
    const actief = activiteit[sleutel];
    const naam = dagNamen[d.getDay()];
    const isVandaag = i === 0;
    weekHTML += `<div class="dash-dag">
      <div class="dash-dag-naam">${naam}</div>
      <div class="dash-dag-blok${actief?' dash-dag-blok--actief':''}${isVandaag?' dash-dag-blok--vandaag':''}" aria-label="${naam}${actief?' вҖ” geoefend':''}">${actief ? 'вң“' : 'В·'}</div>
    </div>`;
  }
  weekEl.innerHTML = weekHTML;

  show('s-dash');
}

function updateHomeDashPreview(){
  try{
    const opgeslagen = JSON.parse(localStorage.getItem('vla_voortgang')||'{}');
    const heeftData = Object.keys(opgeslagen).length > 0;
    const preview = document.getElementById('home-dash-preview');
    if(!preview) return;
    if(heeftData){
      const streak = berekenStreak();
      const totaal = berekenTotaalScore();
      preview.style.display = 'block';
      const sub = document.getElementById('home-dash-sub');
      const badge = document.getElementById('home-streak-badge');
      if(sub) sub.textContent = `${totaal} oefenvormen voltooid В· ${ALLE_TOPICS.filter(t=>berekenTopicVoortgang(t).size>0).length} onderwerpen begonnen`;
      if(badge && streak > 0){
        badge.innerHTML = streak >= 7
          ? `<span style="font-size:1.8rem">рҹ”Ҙ</span><span style="font-size:1.4rem">${streak}</span><span style="font-size:.7rem;display:block;color:rgba(255,215,0,.8)">dagen</span>`
          : `<span style="font-size:1.5rem">рҹ”Ҙ</span><span>${streak}</span>`;
        badge.style.animation = 'streakPulse 1.5s ease-in-out infinite';
      } else if(badge){ badge.textContent = 'вҶ’'; badge.style.animation = ''; }
    }
  }catch(e){}
}

// в•җв•җ MODULE MASTERY ID-TRACKING в•җв•җ
// Sla per voltooide quiz/escaperoom een unieke ID op in localStorage
// Formaat: 'LJ_NV_OW_modus' bijv. '3_VMBO-TL_markt_vr'
function registreerModuleID(modus){
  try{
    if(!OW || !NV || !LJ) return;
    const id = LJ+'_'+NV+'_'+OW+'_'+modus;
    const behaald = JSON.parse(localStorage.getItem('vla_modules')||'[]');
    if(!behaald.includes(id)){
      behaald.push(id);
      localStorage.setItem('vla_modules', JSON.stringify(behaald));
    }
    // Toon vinkje op menu-kaart als die zichtbaar is
    updateModuleVinkjes();
  }catch(e){}
}

function isModuleBehaald(lj, nv, ow, modus){
  try{
    const behaald = JSON.parse(localStorage.getItem('vla_modules')||'[]');
    return behaald.includes(lj+'_'+nv+'_'+ow+'_'+modus);
  }catch(e){ return false; }
}

function updateModuleVinkjes(){
  // Update topic-kaarten in het menu met vinkjes
  document.querySelectorAll('[data-topic-id]').forEach(el => {
    const topic = el.getAttribute('data-topic-id');
    const gedaan = berekenTopicVoortgang(topic);
    const volledig = gedaan.size >= OEFENVORMEN.length;
    const begonnen = gedaan.size > 0;
    el.classList.toggle('tcard-done-all', volledig);
    el.classList.toggle('tcard-started', begonnen && !volledig);
  });
}

// в•җв•җ ZOEKFUNCTIE IN THEORIE в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

function toggleZoekBalk(){
  const wrap = document.getElementById('zoek-balk-wrap');
  const inp = document.getElementById('zoek-input');
  if(wrap.classList.contains('zichtbaar')){
    wrap.classList.remove('zichtbaar');
    document.getElementById('zoek-resultaten').classList.remove('zichtbaar');
  } else {
    wrap.classList.add('zichtbaar');
    setTimeout(()=>inp.focus(), 80);
  }
}

function wisZoek(){
  const inp = document.getElementById('zoek-input');
  inp.value = '';
  inp.focus();
  document.getElementById('zoek-wis-btn').classList.remove('actief');
  document.getElementById('zoek-resultaten').classList.remove('zichtbaar');
}

function zoekInTheorie(query){
  const wisBtn = document.getElementById('zoek-wis-btn');
  const resultDiv = document.getElementById('zoek-resultaten');
  query = query.trim();
  wisBtn.classList.toggle('actief', query.length > 0);
  if(query.length < 2){
    resultDiv.classList.remove('zichtbaar');
    return;
  }
  // Doorzoek alle theorie-data in C
  const hits = [];
  const qLower = query.toLowerCase();
  const re = new RegExp('('+query.replace(/[.*+?^${}()|[\]\\]/g,'\\$&')+')', 'gi');
  Object.keys(C).forEach(owKey => {
    const owData = C[owKey];
    // Doorzoek elk niveau dat TH-blokken heeft
    const niveaus = ['bb','k','tl','h','v','hv'];
    niveaus.forEach(niv => {
      const blokken = owData[niv];
      if(!Array.isArray(blokken)) return;
      blokken.forEach(blok => {
        const tekst = (blok.t||'') + ' ' + ((blok.c||'').replace(/<[^>]+>/g,' '));
        if(tekst.toLowerCase().includes(qLower)){
          // Extract context snippet
          const idx = tekst.toLowerCase().indexOf(qLower);
          const start = Math.max(0, idx - 60);
          const end = Math.min(tekst.length, idx + 120);
          const snippet = (start>0?'вҖҰ':'') + tekst.slice(start,end).replace(re,'<mark>$1</mark>') + (end<tekst.length?'вҖҰ':'');
          // Topic label zoeken
          let topicLabel = owKey;
          Object.keys(TP).forEach(lj => {
            Object.keys(TP[lj]).forEach(nv => {
              (TP[lj][nv]||[]).forEach(t => { if(t.id===owKey) topicLabel = t.t; });
            });
          });
          // Niveau label
          const nivLabels = {bb:'vmbo basis',k:'vmbo kader',tl:'vmbo TL',h:'havo',v:'vwo',hv:'havo/vwo'};
          hits.push({owKey, niv, blokTitel: blok.t||'', snippet, topicLabel, nivLabel: nivLabels[niv]||niv});
        }
      });
    });
    // Ook SAM (samenvatting) doorzoeken
    if(owData.sam){
      const tekst = owData.sam.replace(/<[^>]+>/g,' ');
      if(tekst.toLowerCase().includes(qLower)){
        const idx = tekst.toLowerCase().indexOf(qLower);
        const start = Math.max(0, idx - 60);
        const end = Math.min(tekst.length, idx + 120);
        const snippet = (start>0?'вҖҰ':'') + tekst.slice(start,end).replace(re,'<mark>$1</mark>') + (end<tekst.length?'вҖҰ':'');
        let topicLabel = owKey;
        Object.keys(TP).forEach(lj => {
          Object.keys(TP[lj]).forEach(nv => {
            (TP[lj][nv]||[]).forEach(t => { if(t.id===owKey) topicLabel = t.t; });
          });
        });
        hits.push({owKey, niv:'sam', blokTitel:'Samenvatting', snippet, topicLabel, nivLabel:'Samenvatting'});
      }
    }
  });
  // Dedupliceer op owKey+niv
  const uniek = [];
  const gezien = new Set();
  hits.forEach(h => {
    const key = h.owKey+'_'+h.niv+'_'+h.blokTitel.slice(0,20);
    if(!gezien.has(key)){ gezien.add(key); uniek.push(h); }
  });
  // Render resultaten (max 8)
  if(uniek.length === 0){
    // Zoek in begrippenlijst als fallback
    const begripsHits=[];
    Object.keys(C).forEach(owKey=>{
      const owData=C[owKey];
      const niveaus=['bb','k','tl','h','v','hv'];
      niveaus.forEach(niv=>{
        const beg=owData.beg||[];
        if(!Array.isArray(beg))return;
        beg.forEach(b=>{
          if(!b||!b.b)return;
          if(b.b.toLowerCase().includes(qLower)||(b.d&&b.d.toLowerCase().includes(qLower))){
            begripsHits.push({begrip:b.b,def:b.d||'',owKey});
          }
        });
      });
    });
    // Dedup
    const bUniek=[];const bGezien=new Set();
    begripsHits.forEach(bh=>{if(!bGezien.has(bh.begrip)){bGezien.add(bh.begrip);bUniek.push(bh);}});
    if(bUniek.length>0){
      const re2=new RegExp('('+query.replace(/[.*+?^${}()|[\]\\]/g,'\\$&')+')','gi');
      resultDiv.innerHTML=bUniek.slice(0,5).map(bh=>`<div class="zoek-begrip-hit"><div class="zbh-label">рҹ’Ў Begrip gevonden</div><div class="zbh-begrip">${bh.begrip.replace(re2,'<mark>$1</mark>')}</div><div class="zbh-def">${(bh.def||'Geen definitie beschikbaar').replace(re2,'<mark>$1</mark>')}</div></div>`).join('');
    } else {
      resultDiv.innerHTML = `<div class="zoek-geen">Geen theorie gevonden voor "<strong>${query}</strong>"</div>`;
    }
  } else {
    resultDiv.innerHTML = uniek.slice(0,8).map(h =>
      `<div class="zoek-hit" role="option" onclick="zoekNavigeerNaar('${h.owKey}','${h.niv}')" tabindex="0" onkeydown="if(event.key==='Enter')zoekNavigeerNaar('${h.owKey}','${h.niv}')">
        <div class="zoek-hit-titel">${h.blokTitel || h.topicLabel}</div>
        <div class="zoek-hit-context">${h.snippet}</div>
        <div class="zoek-hit-pad">рҹ“ҡ ${h.topicLabel} В· ${h.nivLabel}</div>
      </div>`
    ).join('') + (uniek.length > 8 ? `<div class="zoek-geen" style="font-size:.75rem;color:#aaa">${uniek.length-8} meer resultaten вҖ” typ specifieker om te verfijnen</div>` : '');
  }
  resultDiv.classList.add('zichtbaar');
}

function zoekNavigeerNaar(owKey, niv){
  // Sluit zoekbalk
  document.getElementById('zoek-balk-wrap').classList.remove('zichtbaar');
  document.getElementById('zoek-resultaten').classList.remove('zichtbaar');
  // Bepaal leerjaar/niveau op basis van huidig of zoek in TP
  let gevondenLj = null, gevondenNv = null;
  outer: for(const lj of Object.keys(TP)){
    for(const nv of Object.keys(TP[lj])){
      if((TP[lj][nv]||[]).some(t=>t.id===owKey)){
        gevondenLj = lj; gevondenNv = nv; break outer;
      }
    }
  }
  if(gevondenLj) LJ = gevondenLj;
  if(gevondenNv) NV = gevondenNv;
  OW = owKey;
  // Ga naar theorie als niv != sam, anders samenvatting
  if(niv === 'sam'){
    go('sam');
  } else {
    go('th');
  }
  toonMelding(`Naar theorie: ${owKey} (${niv})`);
}



// в”Җв”Җ Koopkracht rekentool в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function berekenKoopkracht(){
  const oudEl   = document.getElementById('kk-oud');
  const nieuwEl = document.getElementById('kk-nieuw');
  const infEl   = document.getElementById('kk-inf');
  const stEl    = document.getElementById('kk-stappen');
  const utEl    = document.getElementById('kk-uitkomst');
  if(!oudEl || !nieuwEl || !infEl || !stEl || !utEl) return;

  const oud  = parseFloat(oudEl.value)  || 0;
  const nieuw= parseFloat(nieuwEl.value)|| 0;
  const inf  = parseFloat(infEl.value)  || 0;

  if(oud <= 0){
    stEl.innerHTML = '<em style="color:#999">Vul een geldig oud loon in.</em>';
    utEl.innerHTML = ''; return;
  }

  const nomStijging = (nieuw - oud) / oud * 100;
  const reeel       = nomStijging - inf;
  const positief    = reeel >= 0;

  stEl.innerHTML =
    '<strong>Stap 1 &mdash; Nominale loonstijging:</strong><br>' +
    '&nbsp;&nbsp;(&euro;' + nieuw.toFixed(0) + ' &minus; &euro;' + oud.toFixed(0) +
    ') &divide; &euro;' + oud.toFixed(0) + ' &times; 100%' +
    ' = <strong>' + nomStijging.toFixed(1) + '%</strong><br><br>' +
    '<strong>Stap 2 &mdash; Trek de inflatie eraf:</strong><br>' +
    '&nbsp;&nbsp;' + nomStijging.toFixed(1) + '% &minus; ' + inf.toFixed(1) + '% inflatie' +
    ' = <strong>' + reeel.toFixed(1) + '% reГ«le koopkrachtverandering</strong>';

  utEl.style.cssText =
    'margin-top:.7rem;border-radius:10px;padding:.8rem 1rem;text-align:center;font-weight:700;font-size:1rem;' +
    (positief
      ? 'background:#d4f7e4;border:2px solid #2ecc71;color:#1a7a4a;'
      : 'background:#fde8d8;border:2px solid #e74c3c;color:#c0392b;');
  utEl.innerHTML =
    (positief ? '&#x1F4C8; Koopkracht stijgt' : '&#x1F4C9; Koopkracht daalt') +
    ' met <strong>' + Math.abs(reeel).toFixed(1) + '%</strong>' +
    (positief
      ? ' &mdash; je kunt <em>meer</em> kopen dan vorig jaar! &#x2705;'
      : ' &mdash; je kunt <em>minder</em> kopen, ook al stijgt je loon. &#x26A0;&#xFE0F;');
}


