// в”Җв”Җ SCHRIJFTRAINER DATA в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
const SCHRIJFTRAINER_VRAGEN = [
  // MARKT (cat 1)
  {cat:1, niv:'VMBO-TL', q:'Leg uit wat er gebeurt met de prijs als de vraag naar een product stijgt, terwijl het aanbod gelijk blijft.', model:'Als de <strong>vraag stijgt</strong> bij een gelijkblijvend aanbod ontstaat er een <strong>tekort</strong>: er zijn meer kopers dan er producten zijn. Verkopers merken dat ze alles kwijtraken en verhogen de prijs. Bij een hogere prijs daalt de gevraagde hoeveelheid en stijgt de aangeboden hoeveelheid, totdat er een nieuw <strong>evenwicht</strong> is bereikt op een hogere prijs.', sleutels:['vraag stijgt','aanbod gelijk','tekort','prijs stijgt','evenwicht','hogere prijs']},
  {cat:1, niv:'VMBO-TL', q:'Een boer heeft een slechte oogst door droogte. Wat is het gevolg voor de prijs van zijn groenten op de markt? Gebruik de begrippen vraag, aanbod en evenwichtsprijs.', model:'Door de droogte is de <strong>oogst kleiner</strong> вҶ’ het <strong>aanbod daalt</strong>. De vraag blijft gelijk. Bij het oude evenwicht is er nu een <strong>tekort</strong>. Consumenten bieden meer om toch groenten te krijgen. Hierdoor stijgt de <strong>evenwichtsprijs</strong>. De aanboddaling verschuift de aanbodlijn naar links вҶ’ nieuwe evenwichtsprijs is hoger.', sleutels:['aanbod daalt','vraag gelijk','tekort','prijs stijgt','evenwichtsprijs','links verschuift']},
  {cat:1, niv:'HAVO', q:'Beschrijf het verschil tussen een beweging langs de vraaglijn en een verschuiving van de vraaglijn. Geef een voorbeeld van elk.', model:'Een <strong>beweging langs de vraaglijn</strong> treedt op als de <strong>prijs verandert</strong>: bij een hogere prijs daalt de gevraagde hoeveelheid, maar de lijn zelf beweegt niet. Een <strong>verschuiving van de vraaglijn</strong> treedt op als een andere factor verandert (inkomen, smaak, verwachtingen, prijs van substituut). Voorbeeld beweging: prijs pizza stijgt вҶ’ minder pizza gevraagd. Voorbeeld verschuiving: inkomen stijgt вҶ’ meer pizza gevraagd bij elke prijs вҶ’ lijn verschuift rechts.', sleutels:['beweging langs','prijsverandering','verschuiving','andere factor','inkomen','substituut','rechts verschuift']},

  // OVERHEID (cat 2)
  {cat:2, niv:'VMBO-TL', q:'Waarom produceert de markt geen vuurtorens? Welke rol speelt de overheid hier en waarom?', model:'Een vuurtoren is een <strong>publiek goed</strong>: het is <strong>niet-uitsluitbaar</strong> (je kunt zeelieden niet uitsluiten van het licht) en <strong>niet-rivaliserend</strong> (als jij het gebruikt, heeft een ander er ook nog profijt van). Bedrijven kunnen er geen winst aan verdienen want iedereen kan meeliften zonder te betalen (<strong>free-riderprobleem</strong>). Daarom faalt de markt en neemt de <strong>overheid</strong> deze productie over en betaalt ze via belastingen.', sleutels:['publiek goed','niet-uitsluitbaar','niet-rivaliserend','free-riderprobleem','marktfalen','overheid','belastingen']},
  {cat:2, niv:'VMBO-TL', q:'Leg het verschil uit tussen een begrotingstekort en de staatsschuld.', model:'Een <strong>begrotingstekort</strong> is het verschil in Г©Г©n jaar: de overheid geeft dat jaar meer uit dan er binnenkomt aan belastingen en premies. De <strong>staatsschuld</strong> is de optelsom van alle tekorten (en overschotten) door de jaren heen. Voorbeeld: elke euro die de overheid bijleent om een tekort te dekken, maakt de staatsschuld groter. De staatsschuld is dus een <strong>bestand</strong> (stock), het tekort is een <strong>stroom</strong> (flow).', sleutels:['begrotingstekort','staatsschuld','jaarlijks verschil','optelsom','lenen','bestand','stroom']},
  {cat:2, niv:'HAVO', q:'Beschrijf hoe de overheid de economie kan stabiliseren via het begrotingsbeleid bij een recessie. Wat zijn de risico\'s van dit beleid?', model:'Bij een <strong>recessie</strong> daalt de vraag: bedrijven verdienen minder, mensen verliezen banen. De overheid kan <strong>expansief begrotingsbeleid</strong> voeren: meer uitgeven (bijv. extra investeringen, hogere uitkeringen) of belastingen verlagen. Hierdoor stijgt de <strong>bestedingen</strong> en worden banen beschermd. Risico\'s: (1) <strong>begrotingstekort stijgt</strong> вҶ’ hogere staatsschuld, (2) <strong>verdringingseffect</strong>: overheidsuitgaven kunnen private investeringen verdringen, (3) te late werking door lange besluitvormingstijd.', sleutels:['recessie','expansief beleid','meer uitgeven','belasting verlagen','bestedingen','begrotingstekort','staatsschuld','verdringingseffect']},

  // ARBEID (cat 3)
  {cat:3, niv:'VMBO-TL', q:'Wat is het verschil tussen conjuncturele en structurele werkloosheid? Geef bij elk type een voorbeeld.', model:'<strong>Conjuncturele werkloosheid</strong> ontstaat als de economie in een dal zit (recessie): bedrijven hebben minder orders en ontslaan personeel. Als de economie aantrekt, verdwijnt dit type. Voorbeeld: autofabrikant ontslaat personeel bij dalende autoverkopen. <strong>Structurele werkloosheid</strong> is blijvend: de vaardigheden van werklozen sluiten niet meer aan bij wat de markt vraagt (technologie, globalisering). Voorbeeld: fabrieksarbeiders vervangen door robots.', sleutels:['conjunctureel','recessie','tijdelijk','structureel','blijvend','mismatch','vaardigheden','voorbeeld']},
  {cat:3, niv:'HAVO', q:'Analyseer de voor- en nadelen van zzp-arbeid voor zowel de werknemer als de overheid.', model:'<strong>Voordelen zzp voor werknemer</strong>: flexibiliteit, hogere netto uurprijs, zelf baas, fiscale voordelen (zelfstandigenaftrek). <strong>Nadelen zzp voor werknemer</strong>: geen WW-recht, geen pensioenopbouw via werkgever, inkomensonzekerheid, geen loondoorbetaling bij ziekte. <strong>Nadelen voor overheid</strong>: minder sociale premies вҶ’ houdbaarheidsprobleem pensioenen en WW-fonds. Minder belastinginkomsten door aftrekposten. Discussie: schijnzelfstandigheid вҖ” sommige zzp\'ers werken feitelijk als werknemer maar zonder bescherming.', sleutels:['voordelen','nadelen','WW','pensioen','fiscaal','overheid','premies','schijnzelfstandigheid']},

  // BUITENLAND (cat 4)
  {cat:4, niv:'VMBO-TL', q:'Leg uit wat comparatief voordeel betekent en waarom het loont om te specialiseren, ook als een land alles goedkoper kan produceren.', model:'<strong>Comparatief voordeel</strong>: een land heeft een voordeel in het product dat het relatief het goedkoopst produceert вҖ” gemeten in <strong>opportuniteitskosten</strong>. Zelfs als land A alles beter maakt dan land B, loont specialisatie. Want als land A zich volledig richt op zijn sterkste product en land B op zijn relatief beste product, is de totale productie hoger dan als beide landen alles zelf maken. Voorbeeld: Nederland bloemen/technologie, Vietnam textiel вҖ” samen productiever.', sleutels:['comparatief voordeel','opportuniteitskosten','relatief','specialiseren','totale productie','voorbeeld']},
  {cat:4, niv:'HAVO', q:'Een sterke euro heeft gevolgen voor de Nederlandse export en import. Analyseer dit effect en geef aan wie er voordeel en nadeel van heeft.', model:'<strong>Sterkere euro</strong>: buitenlanders moeten meer van hun valuta betalen voor Г©Г©n euro вҶ’ Nederlandse exportproducten worden <strong>duurder</strong> voor hen вҶ’ <strong>export daalt</strong>. Importproducten worden goedkoper voor Nederland вҶ’ <strong>import stijgt</strong>. <strong>Nadeel</strong>: exportbedrijven (bijv. ASML, agro-industrie) verdienen minder. <strong>Voordeel</strong>: consumenten die buitenlandse producten kopen betalen minder. Saldo op handelsbalans verslechtert (export daalt, import stijgt).', sleutels:['sterkere euro','export duurder','export daalt','import goedkoper','import stijgt','exportbedrijven','handelsbalans']},

  // SPAREN & CONSUMENT (cat 5)
  {cat:5, niv:'VMBO-TL', q:'Wat is het verschil tussen sparen en beleggen? Noem een voordeel en een nadeel van elk.', model:'<strong>Sparen</strong>: geld op spaarrekening. Voordeel: veilig, zeker rendement (1-3%). Nadeel: laag rendement. <strong>Beleggen</strong>: investeren in aandelen of fondsen. Voordeel: hoger verwacht rendement (gem. 6-8%/jaar). Nadeel: risico op verlies. Vuistregel: spaar eerst een noodfonds (3 maandlasten), beleg daarna pas.', sleutels:['sparen','veilig','laag rendement','beleggen','hoger rendement','risico','noodfonds']},
  {cat:5, niv:'VMBO-TL', q:'Leg uit wat samengestelde rente is en waarom het slim is om vroeg te beginnen met sparen.', model:'<strong>Samengestelde rente</strong>: je ontvangt rente over het totale saldo inclusief eerder ontvangen rente. Formule: Eindwaarde = Hoofdsom x (1 + r)^n. Voorbeeld: \u20ac1.000 bij 5% gedurende 30 jaar = \u20ac4.322 (samengesteld) versus \u20ac2.500 (enkelvoudig). Hoe eerder je begint, hoe langer het effect werkt.', sleutels:['samengestelde rente','rente op rente','formule','hoofdsom','vroeg beginnen','exponentieel']},
  {cat:5, niv:'VMBO-TL', q:'Je koopt online een laptop voor \u20ac800. Na 3 maanden doet het scherm het niet meer. De winkel zegt dat de garantie al voorbij is. Wat zijn jouw rechten?', model:'Je hebt recht op <strong>wettelijke garantie</strong>: het product moet doen wat je er redelijkerwijs van mag verwachten. Dat geldt los van de commerciele garantie van de winkel. Je mag eisen: reparatie, vervanging of terugbetaling. Stap 1: stuur een klachtenbrief. Stap 2: geen reactie? Schakel Consumentenbond of Geschillencommissie in.', sleutels:['wettelijke garantie','non-conformiteit','reparatie','vervanging','consumentenbond','geschillencommissie']},
  {cat:5, niv:'HAVO', q:'Wat is informatieasymmetrie op de verzekeringsmarkt? Leg uit hoe averechtse selectie en moral hazard hieruit voortkomen.', model:'<strong>Informatieasymmetrie</strong>: de klant weet meer over zijn eigen risico dan de verzekeraar. Dit veroorzaakt: (1) <strong>Averechtse selectie</strong>: hoog-risico mensen sluiten vaker een verzekering af. De verzekeraar verhoogt premies, laag-risico klanten haken af. (2) <strong>Moral hazard</strong>: verzekerden nemen meer risico omdat de schade toch vergoed wordt. Oplossing: eigen risico en informatievergaring.', sleutels:['informatieasymmetrie','averechtse selectie','moral hazard','eigen risico','negatieve spiraal']},
  {cat:5, niv:'HAVO', q:'De rente stijgt van 2% naar 5%. Analyseer de gevolgen voor spaarders, leners en de huizenmarkt.', model:'<strong>Spaarders</strong>: positief, hogere rente op spaargeld. <strong>Leners</strong>: negatief, lenen duurder, minder leningen, minder bestedingen. <strong>Huizenmarkt</strong>: negatief. Hogere hypotheekrente \u2192 hogere maandlasten \u2192 minder kopers \u2192 vraag daalt \u2192 huizenprijzen dalen op termijn. Doorstroming stagneert.', sleutels:['spaarders positief','leners negatief','hypotheekrente','vraag daalt','huizenprijzen','doorstroming']},
  // === CAT 6: Natuur & milieu ===
  {cat:6, niv:'VMBO-TL', q:'Leg uit wat een negatief extern effect is. Geef een voorbeeld uit de praktijk.', model:'Een <strong>negatief extern effect</strong> is schade die wordt veroorzaakt door productie of consumptie, maar die <strong>niet in de prijs</strong> van het product zit. De kosten komen bij anderen terecht. Een voorbeeld: een fabriek loost afvalwater in een rivier. De fabriek betaalt daar niet voor, maar vissers en omwonenden ondervinden schade. De prijs van de fabrieksproducten weerspiegelt deze schade dus niet.', sleutels:['negatief extern effect','niet in de prijs','schade bij derden','veroorzaker','marktfalen']},
  {cat:6, niv:'VMBO-TL', q:'Beschrijf twee manieren waarop de overheid milieuschade kan aanpakken. Geef van elke manier een voorbeeld.', model:'De overheid heeft meerdere instrumenten. Ten eerste <strong>milieubelastingen</strong>: door vervuiling duurder te maken, worden bedrijven gestimuleerd schonere methoden te gebruiken. Voorbeeld: de CO\u00b2-heffing in Nederland. Ten tweede <strong>regels en verboden</strong>: de overheid stelt maximale uitstootnormen in. Bedrijven die de norm overschrijden, krijgen boetes. Beide aanpakken proberen de externe kosten van vervuiling te internaliseren.', sleutels:['milieubelasting','regels en normen','internaliseren','vervuiler betaalt','CO\u00b2-heffing']},
  {cat:6, niv:'VMBO-TL', q:'Wat is een circulaire economie? Waarom is dit beter voor het milieu dan een lineaire economie?', model:'In een <strong>lineaire economie</strong> worden grondstoffen gewonnen, gebruikt en daarna weggegooid. Bij een <strong>circulaire economie</strong> worden grondstoffen en producten zo lang mogelijk hergebruikt, gerepareerd of gerecycled. Dit is beter voor het milieu omdat er minder nieuwe grondstoffen gewonnen hoeven te worden, er minder afval is en minder energie nodig is voor productie. Een voorbeeld: telefoons die ontworpen zijn voor reparatie en recycling.', sleutels:['lineair','circulair','hergebruik','recycling','grondstoffen','afval']},
  {cat:6, niv:'HAVO', q:'Leg het begrip marktfalen uit in de context van milieuschade. Waarom lost de markt dit probleem niet vanzelf op?', model:'<strong>Marktfalen</strong> treedt op wanneer de markt geen maatschappelijk optimale uitkomst produceert. Bij milieuschade is de oorzaak het <strong>negatieve externe effect</strong>: de marktprijs bevat alleen de <strong>private kosten</strong>, maar niet de externe kosten. De <strong>sociale kosten</strong> (private + externe) zijn hoger dan de prijs. Daardoor wordt er te veel geproduceerd van het schadelijke goed. De markt lost dit niet vanzelf op, want de vervuiler heeft geen financieel belang bij het beperken van schade die hij zelf niet betaalt.', sleutels:['marktfalen','private kosten','sociale kosten','externe kosten','te veel productie','overheidsingrijpen']},
  {cat:6, niv:'HAVO', q:'Vergelijk milieubelasting met emissierechten (ETS) als beleidsinstrumenten. Wat zijn de voor- en nadelen van elk?', model:'<strong>Milieubelasting</strong>: de overheid legt een belasting op per eenheid vervuiling. Voordeel: zekerheid over de prijs van vervuilen, eenvoudig uitvoerbaar. Nadeel: onzekerheid over de totale uitstootreductie. <strong>Emissierechten (ETS)</strong>: de overheid bepaalt een maximale totale uitstoot en verdeelt rechten; bedrijven mogen rechten kopen en verkopen. Voordeel: totale uitstoot is zeker begrensd, reductie vindt plaats waar het goedkoopst. Nadeel: de prijs van rechten fluctueert, wat investeringszekerheid bemoeilijkt.', sleutels:['milieubelasting','emissierechten','ETS','cap-and-trade','uitstootplafond','prijs zekerheid']},
  // в”Җв”Җ VWO oorzaak-gevolg vragen в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  {cat:1, niv:'VWO', q:'De centrale bank verhoogt de beleidsrente van 1% naar 4%. Analyseer via een oorzaak-gevolg-keten de effecten op consumptie, investeringen, de wisselkoers en de inflatie.', model:'<strong>Oorzaak:</strong> centrale bank verhoogt rente. <strong>Gevolgen (keten):</strong><br>1. Lenen duurder вҶ’ consumenten lenen minder вҶ’ bestedingen dalen (CвҶ“).<br>2. Investeringen duurder voor bedrijven вҶ’ bedrijven stellen investeringen uit (IвҶ“).<br>3. Hogere rente trekt buitenlands kapitaal aan вҶ’ vraag naar euro stijgt вҶ’ euro apprecieert вҶ’ export duurder, import goedkoper (NXвҶ“).<br>4. Lagere vraag (CвҶ“, IвҶ“, NXвҶ“) вҶ’ minder bestedingsdruk вҶ’ inflatie daalt. Conclusie: rentebeleid werkt via meerdere kanalen tegelijk. ECB gebruikt dit als anti-inflatie-instrument.', sleutels:['rente stijgt','lenen duurder','consumptie daalt','investeringen dalen','euro apprecieert','export daalt','inflatie daalt','oorzaak-gevolg']},
  {cat:2, niv:'VWO', q:'De overheid verlaagt het vennootschapsbelastingtarief van 25% naar 15%. Geef een volledige oorzaak-gevolg-analyse voor zowel de korte als de lange termijn.', model:'<strong>Korte termijn:</strong> bedrijven houden meer winst over na belasting вҶ’ hogere dividenden en/of hogere investeringsbudgetten. Lagere belastingopbrengsten voor overheid вҶ’ risico op begrotingstekort.<br><strong>Lange termijn:</strong> hogere investeringen вҶ’ meer kapitaal вҶ’ productiestijging вҶ’ economische groei вҶ’ breder belastingbasis вҶ’ mogelijke compensatie van lagere opbrengst (Laffer-curve). Negatief: race to the bottom tussen landen вҶ’ dalende belastinginkomsten Europees breed. Maatschappelijk debat: wie profiteert вҖ” aandeelhouders of ook werknemers via hogere lonen?', sleutels:['vennootschapsbelasting','winst na belasting','investeringen','begrotingstekort','Laffer-curve','race to the bottom','korte termijn','lange termijn']},
  {cat:3, niv:'VWO', q:'Door technologische automatisering verdwijnen 200.000 maakindustriebanen in vijf jaar. Analyseer de gevolgen voor de arbeidsmarkt, sociale zekerheid en inkomensverdeling.', model:'<strong>Arbeidsmarkt:</strong> vraag naar laaggeschoolde arbeid daalt вҶ’ werkloosheid laaggeschoolden stijgt вҶ’ lonen onder druk. Vraag naar ICT- en data-specialisten stijgt вҶ’ loonstijging bovenaan. <strong>Sociale zekerheid:</strong> meer WW-uitkeringen вҶ’ hogere overheidsuitgaven. Structurele werkloosheid dreigt als omscholing te traag gaat.<br><strong>Inkomensverdeling:</strong> Gini-coГ«fficiГ«nt stijgt (meer ongelijkheid). Kapitaalinkomen stijgt (robots zijn kapitaal), arbeidsinkomen relatief daalt. Beleidsvraag: verhoog vermogensbelasting of introduceer basisinkomen?', sleutels:['automatisering','laaggeschoolden','structurele werkloosheid','WW','omscholing','Gini','kapitaalinkomen','ongelijkheid']},
  {cat:5, niv:'VWO', q:'In een open economie met vrij kapitaalverkeer verhoogt de overheid de overheidsuitgaven met вӮ¬5 miljard. Verklaar via het IS-LM-model (vereenvoudigd) waarom het effect op het BBP kleiner kan zijn dan verwacht.', model:'<strong>Directe impuls:</strong> GвҶ‘ вҶ’ bestedingen stijgen вҶ’ BBP-stijging via multiplier verwacht. <strong>Maar:</strong><br>1. <strong>Verdringingseffect</strong>: overheid leent meer op kapitaalmarkt вҶ’ rente stijgt вҶ’ private investeringen dalen вҶ’ gedeeltelijke compensatie.<br>2. <strong>Open economie</strong>: hogere rente trekt buitenlands kapitaal вҶ’ wisselkoers apprecieert вҶ’ export daalt (NXвҶ“) вҶ’ additionele demping.<br>3. Bij volledig vrij kapitaalverkeer (Mundell-Fleming): expansief begrotingsbeleid heeft nauwelijks BBP-effect omdat verdringingseffect volledig is.<br>Conclusie: de feitelijke multiplier is lager dan de theoretische door crowding out en wisselkoerseffect.', sleutels:['verdringingseffect','crowding out','rente stijgt','wisselkoers','Mundell-Fleming','multiplier','open economie']},

  // в”Җв”Җ LEERJAAR 3 TL / HAVO в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  {cat:1, niv:'3TL/HAVO', q:'Beschrijf de bedrijfskolom voor een kop koffie uit een koffiecup. Welke schakels zijn er en wat is de toegevoegde waarde van de koffiebranderij als die koffiebonen inkoopt voor вӮ¬2 per kg en verkoopt voor вӮ¬7 per kg?', model:'<strong>Bedrijfskolom koffie:</strong><br>1. Koffieboer (primair) вҶ’ verbouwt koffiebessen<br>2. Exporteur/handelaar вҶ’ sorteert en exporteert groene bonen<br>3. Koffiebranderij (secundair) вҶ’ brandt en verpakt<br>4. Groothandel вҶ’ distribueert aan winkels en horeca<br>5. Supermarkt/koffiezaak (detailhandel) вҶ’ verkoopt aan consument<br><br><strong>Toegevoegde waarde branderij:</strong> Verkoopwaarde (вӮ¬7) вҲ’ Inkoopwaarde (вӮ¬2) = <strong>вӮ¬5 per kg</strong>. Die вӮ¬5 dekt loon, energie, verpakking en winst.', sleutels:['bedrijfskolom','primair','secundair','groothandel','detailhandel','toegevoegde waarde','вӮ¬5']},
  {cat:1, niv:'3TL/HAVO', q:'Een sportwinkel verkoopt 150 paar sneakers voor вӮ¬80 per paar. De inkoopprijs per paar is вӮ¬35. Bereken de omzet en de totale toegevoegde waarde. Wat is het verschil tussen omzet en toegevoegde waarde?', model:'<strong>Omzet</strong> = Afzet Г— Verkoopprijs = 150 Г— вӮ¬80 = <strong>вӮ¬12.000</strong><br><strong>Toegevoegde waarde</strong> = (вӮ¬80 вҲ’ вӮ¬35) Г— 150 = вӮ¬45 Г— 150 = <strong>вӮ¬6.750</strong><br><br>Verschil: omzet is alles wat binnenkomt. Toegevoegde waarde is wat de winkel zelf toevoegt: de inkoop van de producent zit er niet meer in. De TV is het deel dat de winkel kan gebruiken voor lonen, huur en winst.', sleutels:['omzet','вӮ¬12.000','toegevoegde waarde','вӮ¬6.750','afzet','verkoopprijs','inkoopprijs']},
  {cat:2, niv:'3TL/HAVO', q:'Leg het begrip averechtse selectie uit op de verzekeringsmarkt. Geef een concreet voorbeeld en leg uit waarom de Nederlandse overheid de zorgverzekering verplicht heeft gesteld.', model:'<strong>Averechtse selectie</strong> (adverse selection): mensen met het hoogste risico zijn het meest geneigd een verzekering af te sluiten, terwijl mensen met laag risico afhaken als de premie te hoog wordt. Gevolg: het verzekerdenbestand verschuift naar hoog-risico вҶ’ premies stijgen verder вҶ’ meer laagrisicoklanten vertrekken вҶ’ spiraal.<br><br><strong>Voorbeeld</strong>: als zorgverzekering vrijwillig is, sluiten mensen die zelden ziek zijn hem niet af. Alleen de zieken betalen mee. De premies worden zo hoog dat de verzekering onbetaalbaar wordt.<br><br><strong>Oplossing overheid</strong>: zorgplicht voor iedereen. Gezonden en zieken betalen mee вҶ’ solidariteit вҶ’ premies blijven betaalbaar.', sleutels:['averechtse selectie','hoogrisicogroep','premie stijgt','spiraal','verplicht','solidariteit','zorgverzekering']},
  {cat:2, niv:'3TL/HAVO', q:'Een laptop kost вӮ¬726 incl. btw (21%). Bereken de prijs excl. btw en het btw-bedrag. Leg daarna uit waarom btw een indirecte belasting is.', model:'Prijs excl. btw = вӮ¬726 Г· 1,21 = <strong>вӮ¬600</strong><br>Btw-bedrag = вӮ¬726 вҲ’ вӮ¬600 = <strong>вӮ¬126</strong><br><br><strong>Indirecte belasting</strong>: je betaalt de belasting niet rechtstreeks aan de Belastingdienst, maar verborgen in de prijs van het product. De winkel int de btw en draagt het af. Jij betaalt indirect вҖ” via je aankoop. Directe belasting (zoals loonbelasting) betaal je wГ©l rechtstreeks, ingehouden op je loon.', sleutels:['вӮ¬600','вӮ¬126','indirecte belasting','via de prijs','winkel draagt af','direct vs indirect']},
  {cat:2, niv:'3TL/HAVO', q:'Nederland hanteert het draagkrachtprincipe bij belastingheffing. Leg uit wat dit inhoudt en bereken de belasting voor iemand die вӮ¬50.000 verdient, als het tarief tot вӮ¬40.000 gelijk is aan 30% en daarboven 50%.', model:'<strong>Draagkrachtprincipe</strong>: wie meer verdient, betaalt niet alleen meer belasting, maar ook een hoger percentage. Brede schouders dragen meer вҖ” niet alleen absoluut maar ook relatief.<br><br><strong>Berekening voor вӮ¬50.000:</strong><br>Schijf 1 (tot вӮ¬40.000): 30% Г— вӮ¬40.000 = вӮ¬12.000<br>Schijf 2 (вӮ¬10.000 boven grens): 50% Г— вӮ¬10.000 = вӮ¬5.000<br>Totale belasting = <strong>вӮ¬17.000</strong><br>Nettoloon = вӮ¬50.000 вҲ’ вӮ¬17.000 = вӮ¬33.000<br>Gemiddeld belastingtarief = вӮ¬17.000 / вӮ¬50.000 = 34%', sleutels:['draagkrachtprincipe','progressief','вӮ¬12.000','вӮ¬5.000','вӮ¬17.000','schijf','marginaal tarief']},
  {cat:3, niv:'3TL/HAVO', q:'Een land heeft 12 miljoen mensen in de potentiГ«le beroepsbevolking. De beroepsbevolking is 9 miljoen; er zijn 720.000 werklozen. Bereken het werkloosheidspercentage. Leg daarna uit of dit conjunctureel of structureel van aard kan zijn.', model:'<strong>Werkloosheidspercentage</strong> = werklozen / beroepsbevolking Г— 100%<br>= 720.000 / 9.000.000 Г— 100% = <strong>8%</strong><br><br><strong>Conjunctureel of structureel?</strong><br>Dat hangt af van de context. Is het land in recessie en daalt de vraag naar producten? вҶ’ Waarschijnlijk conjunctureel (tijdelijk). Heeft het land te maken met automatisering, vergrijzing of een mismatch in vaardigheden? вҶ’ Structureel (blijvend, vereist omscholing).', sleutels:['8%','beroepsbevolking','conjunctureel','structureel','mismatch','recessie','omscholing']},
  {cat:3, niv:'3TL/HAVO', q:'Wat is het verschil tussen conjuncturele en structurele werkloosheid? Beschrijf bij elk type de oorzaak, de duur en de beste beleidsmaatregel.', model:'<strong>Conjuncturele werkloosheid:</strong><br>Oorzaak: economische neergang (recessie) вҶ’ te weinig vraag naar producten вҶ’ bedrijven ontslaan mensen. Duur: tijdelijk вҖ” trekt weg als de economie herstelt. Beleid: stimuleringsbeleid (extra overheidsuitgaven, lage rente) om de vraag aan te jagen.<br><br><strong>Structurele werkloosheid:</strong><br>Oorzaak: mismatch tussen de vaardigheden van werklozen en wat de markt vraagt. Door automatisering, globalisering of veranderende sectoren. Duur: langdurig, lost niet vanzelf op. Beleid: omscholing, investeringen in onderwijs, arbeidsmarkthervorming.', sleutels:['conjunctureel','recessie','tijdelijk','vraagbeleid','structureel','mismatch','blijvend','omscholing']},
  {cat:6, niv:'3TL/HAVO', q:'Leg uit wat een negatief extern effect is. Geef een voorbeeld vanuit de productie en een vanuit de consumptie. Welke twee overheidsmaatregelen kunnen dit probleem aanpakken?', model:'Een <strong>negatief extern effect</strong> is schade die productie of consumptie veroorzaakt bij derden, zonder dat de veroorzaker hiervoor betaalt. De maatschappelijke kosten zijn hoger dan de private kosten вҶ’ te veel productie vanuit maatschappelijk oogpunt.<br><br><strong>Productievoorbeeld</strong>: een chemische fabriek loost vervuild water вҶ’ vissterfte en zieke omwonenden betalen de prijs, niet de fabriek.<br><strong>Consumptievoorbeeld</strong>: autorijden вҶ’ uitlaatgassen вҶ’ longproblemen bij voorbijgangers.<br><br><strong>Maatregelen overheid:</strong><br>1. <em>Milieubelasting</em>: vervuilen duurder maken via een COвӮӮ-heffing вҶ’ internalisering van externe kosten.<br>2. <em>Normen/verboden</em>: wettelijke uitstootnormen met boetes.', sleutels:['negatief extern effect','derden','private kosten','sociale kosten','internalisering','milieubelasting','normen']},
  {cat:6, niv:'3TL/HAVO', q:'Wat wordt bedoeld met "Groen Groeien"? Leg uit waarom reguliere economische groei een probleem is voor het milieu, en beschrijf twee manieren waarop groei en milieubescherming toch samen kunnen gaan.', model:'<strong>Probleem reguliere groei</strong>: meer productie vraagt meer grondstoffen, energie en stoot meer COвӮӮ uit. Externe effecten (milieuschade) zijn niet verrekend in de prijs вҖ” de markt faalt.<br><br><strong>Groen Groeien</strong>: economische groei realiseren terwijl de milieubelasting afneemt of gelijk blijft. Maatschappelijke welvaart stijgt zonder natuur te slopen.<br><br><strong>Twee manieren:</strong><br>1. <em>Circulaire economie</em>: producten ontwerpen voor hergebruik вҶ’ minder grondstoffen nodig, minder afval.<br>2. <em>Duurzame energie</em>: zonne- en windenergie vervangt fossiele brandstoffen вҶ’ groei zonder COвӮӮ-uitstoot.', sleutels:['negatieve externe effecten','marktfalen','Groen Groeien','circulaire economie','duurzame energie','grondstoffen','welvaart zonder milieuschade']},

  // в”Җв”Җ SCHRIJFTRAINER: De wegwerpeconomie (5 niveaus) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  {cat:6, niv:'VMBO-BB', q:'Wat is de wegwerpeconomie? Geef Г©Г©n voorbeeld en leg uit waarom dit slecht is voor het milieu.', model:'De <strong>wegwerpeconomie</strong> is een economie waarbij we producten kopen, een korte tijd gebruiken, en dan weggooien. Voorbeeld: een plastic bekertje of een goedkoop t-shirt. Dit is slecht voor het milieu omdat er steeds nieuwe grondstoffen nodig zijn om nieuwe producten te maken. Grondstoffen zijn schaars вҖ” als we ze weggooien, raken ze op. Bovendien zorgt afval voor vervuiling van de natuur.', sleutels:['wegwerpeconomie','weggooien','grondstof','schaars','milieu','afval']},
  {cat:6, niv:'VMBO-KB', q:'Leg het verschil uit tussen een wegwerpeconomie en een circulaire economie. Geef van elk Г©Г©n concreet voorbeeld.', model:'In een <strong>wegwerpeconomie</strong> worden producten gemaakt, gebruikt en daarna weggegooid. Grondstoffen verdwijnen als afval. Voorbeeld: een plastic fles weggooien. In een <strong>circulaire economie</strong> worden grondstoffen hergebruikt, gerepareerd of gerecycled. Ze blijven in de kringloop. Voorbeeld: een plastic fles inleveren, zodat het plastic opnieuw gebruikt wordt. De circulaire economie is beter voor het milieu omdat er minder nieuwe grondstoffen nodig zijn en er minder afval is.', sleutels:['wegwerpeconomie','circulaire economie','hergebruiken','recycling','grondstoffen','kringloop']},
  {cat:6, niv:'VMBO-TL', q:'Wat is een circulaire economie? Waarom is dit economisch beter dan een wegwerpeconomie? Gebruik de begrippen schaarste, grondstoffen en negatief extern effect.', model:'In een <strong>wegwerpeconomie</strong> worden grondstoffen gewonnen, producten gemaakt, kort gebruikt en daarna weggegooid. Dit veroorzaakt <strong>negatieve externe effecten</strong>: milieuschade die niet in de prijs verrekend is. Bovendien zijn grondstoffen <strong>schaars</strong> вҖ” als ze eenmalig gebruikt worden, raken ze op.<br><br>In een <strong>circulaire economie</strong> blijven grondstoffen in de kringloop via hergebruik, reparatie en recycling. Economisch voordeel: minder grondstoffenverbruik = lagere kosten op lange termijn, minder milieuschade, en grondstoffen blijven beschikbaar voor toekomstige generaties.', sleutels:['wegwerpeconomie','circulaire economie','schaarste','grondstoffen','negatief extern effect','hergebruik','recycling']},
  {cat:6, niv:'HAVO', q:'Analyseer waarom de markt zelf de overgang van een wegwerpeconomie naar een circulaire economie niet oplost. Welke twee overheidsmaatregelen kunnen dit bevorderen?', model:'De markt lost dit niet vanzelf op door <strong>marktfalen</strong>. De prijs van producten bevat niet de <strong>externe kosten</strong> van milieuschade (vervuiling, grondstofverspilling). Voor de producent is weggooien goedkoper dan circulair ontwerpen вҖ” de maatschappelijke kosten worden afgewenteld op derden.<br><br><strong>Twee overheidsmaatregelen:</strong><br>1. <em>Milieubelasting op niet-circulaire producten</em>: weggooien wordt duurder вҶ’ internalisering van externe kosten вҶ’ producenten hebben financieel belang bij circulair ontwerpen.<br>2. <em>Uitgebreide producentenverantwoordelijkheid (UPV)</em>: producenten zijn wettelijk verantwoordelijk voor het innemen en recyclen van hun producten. Dit geeft een directe prikkel voor circulair ontwerp.', sleutels:['marktfalen','externe kosten','internalisering','milieubelasting','UPV','producentenverantwoordelijkheid','circulair ontwerp']},
  {cat:6, niv:'VWO', q:'Evalueer de bewering: "De overgang naar een circulaire economie vereist een fundamentele verandering van businessmodellen, niet alleen van technologie." Gebruik economische argumenten en de R-ladder.', model:'<strong>Stelling klopt</strong>: technologie alleen is onvoldoende als de <em>incentivestructuur</em> niet verandert.<br><br>In een lineair businessmodel verdient de producent aan het <em>verkopen</em> van producten. Hoe sneller het kapotgaat, hoe meer hij verdient (<strong>gepland verval</strong>). Dit is rationeel gedrag, maar maatschappelijk inefficiГ«nt.<br><br>In een circulair businessmodel (<em>product-as-a-service</em>) behoudt de producent eigendom en verkoopt gebruik. Nu heeft hij financieel belang bij lange levensduur, reparatie en materiaalterugwinning. Dit correspondeert met de bovenkant van de <strong>R-ladder</strong>: Refuse, Rethink, Reduce вҖ” vГ©Г©l effectiever dan enkel Recyclen.<br><br>Conclusie: zonder businessmodelverandering recyclen we de symptomen, maar lossen we het structurele probleem niet op. De overheid kan dit bevorderen via UPV, statiegeld en carbon pricing.', sleutels:['businessmodel','incentivestructuur','gepland verval','product-as-a-service','R-ladder','Refuse','Rethink','Reduce','recyclen','carbon pricing','UPV']},

  // в”Җв”Җ SCHRIJFTRAINER: Vleestaks вҖ” goed idee of niet? (5 niveaus) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  {cat:1, niv:'VMBO-BB', q:'Waarom wordt vlees in de winkel goedkoper verkocht dan het eigenlijk kost? Leg dit uit in 3-5 zinnen.', model:'Vlees is goedkoop in de winkel omdat de <strong>milieuschade niet betaald wordt</strong> door de boer of de winkel. De productie van vlees gebruikt veel water en veroorzaakt COвӮӮ. Die schade komt bij de natuur en bij mensen in de toekomst terecht вҖ” niet bij de koper. Als je die schade wГ©l bij de prijs zou optellen, zou vlees veel duurder zijn. De markt laat dit probleem dus liggen.', sleutels:['milieuschade','niet in de prijs','COвӮӮ','te goedkoop','toekomst']},
  {cat:1, niv:'VMBO-KB', q:'Leg uit wat een negatief extern effect is. Beschrijf daarna Г©Г©n negatief extern effect van vleesproductie en hoe de overheid dit kan aanpakken.', model:'Een <strong>negatief extern effect</strong> is schade die door productie of consumptie wordt veroorzaakt bij anderen, zonder dat de veroorzaker daarvoor betaalt. Bij vleesproductie stoot de veehouderij COвӮӮ en methaan uit. Dit draagt bij aan klimaatverandering вҖ” de schade treft iedereen, maar de boer betaalt er niets voor. Oplossing: de overheid kan een belasting opleggen op vlees, waardoor de prijs stijgt en consumenten minder vlees kopen. Zo worden de externe kosten verrekend in de prijs.', sleutels:['negatief extern effect','schade bij anderen','COвӮӮ','methaan','belasting','prijs stijgt']},
  {cat:1, niv:'VMBO-TL', q:'Is een vleestaks een goed idee? Geef economische argumenten vГіГіr en tГ©gen een belasting op vlees. Betrek de begrippen extern effect en maatschappelijke kosten in je antwoord.', model:'<strong>VГіГіr</strong>: vleesproductie veroorzaakt <strong>negatieve externe effecten</strong> (COвӮӮ, methaan, stikstof, waterverbruik). De <strong>maatschappelijke kosten</strong> zijn hoger dan de private kosten. De marktprijs is daardoor te laag вҶ’ te veel vlees wordt geproduceerd. Een vleestaks internationaliseert deze externe kosten: de prijs stijgt, consumptie daalt, het marktfalen wordt gecorrigeerd.<br><br><strong>Tegen</strong>: een vleestaks treft mensen met een laag inkomen harder (zij besteden een groter deel van hun inkomen aan voedsel). Bovendien kan vlees worden vervangen door goedkoop buitenlands vlees zonder taks (koolstoflekkage). Politiek draagvlak ontbreekt vaak.', sleutels:['extern effect','maatschappelijke kosten','marktfalen','internalisering','vleestaks','laag inkomen','koolstoflekkage']},
  {cat:1, niv:'HAVO', q:'Analyseer de vleestaks als maatregel tegen marktfalen. Ga in op: (1) het marktfalen dat het adresseert, (2) de effectiviteit, en (3) twee bezwaren.', model:'<strong>(1) Marktfalen</strong>: vleesproductie veroorzaakt <strong>negatieve externe effecten</strong> вҖ” broeikasgassen, stikstofuitstoot, waterverbruik, landgebruik. De <strong>private kosten</strong> voor de producent zijn lager dan de <strong>maatschappelijke kosten</strong>. De marktprijs is te laag вҶ’ te veel productie vanuit maatschappelijk perspectief. Klassiek marktfalen.<br><br><strong>(2) Effectiviteit</strong>: een pigouviaanse belasting verhoogt de prijs naar het maatschappelijk optimum. Als de prijselasticiteit van de vraag naar vlees вҲ’0,5 is en de prijs met 20% stijgt, daalt de consumptie met 10%. Effectief bij elastische vraag; minder bij inelastische vraag (vlees als basisvoedsel).<br><br><strong>(3) Bezwaren</strong>: (a) <em>Regressief effect</em>: lagere inkomensgroepen besteden proportioneel meer aan vlees вҶ’ taks treft hen zwaarder вҶ’ inkomensongelijkheid neemt toe (oplossing: compenseer via lagere BTW of gerichte teruggave). (b) <em>Koolstoflekkage</em>: als nationale taks invoerders niet treft, verschuift productie naar landen zonder taks вҶ’ globaal COвӮӮ-effect nihil.', sleutels:['negatief extern effect','maatschappelijke kosten','pigouviaans','prijselasticiteit','regressief','koolstoflekkage','optimum']},
  {cat:1, niv:'VWO', q:'Evalueer de vleestaks als beleidsinstrument vanuit welvaartseconomisch perspectief. Vergelijk het met emissierechten (ETS) en bespreek verdelingseffecten.', model:'<strong>Welvaartseconomische rechtvaardiging</strong>: vleesproductie genereert negatieve externaliteiten (broeikasgassen, biodiversiteitsverlies, waterverontreiniging). Maatschappelijke kosten > private kosten вҶ’ overproductie вҶ’ deadweight loss. Een pigouviaanse belasting gelijk aan het marginale externe effect herstelt het maatschappelijk optimum: P = MC + MEC (marginale externe kosten).<br><br><strong>Vergelijking met ETS</strong>: een vleestaks geeft prijszekerheid maar geen zekerheid over de hoeveelheidsreductie. ETS geeft kwantitatieve zekerheid (cap) maar prijsvolatiliteit. Voor een mondiale uitdaging als klimaat verdient ETS de voorkeur qua effectiviteit. Vleestaks is administratief eenvoudiger te implementeren.<br><br><strong>Verdelingseffecten</strong>: een vlakke vleestaks is <em>regressief</em> вҖ” lagere inkomens besteden een groter aandeel van hun budget aan vlees вҶ’ hogere lasten relatief gezien. Oplossing: gebruik taksopbrengsten voor een universele voedselkorting of verlaging van arbeidsbelasting (<em>tax recycling</em>). Tweede bezwaar: koolstoflekkage als buitenlandse producten vrijgesteld blijven. Oplossing: <em>carbon border adjustment mechanism</em> (CBAM).', sleutels:['maatschappelijk optimum','MEC','pigouviaans','ETS','cap','regressief','tax recycling','CBAM','deadweight loss','koolstoflekkage']},

  // в”Җв”Җ SCHRIJFTRAINER: Solidariteit tussen jong en oud (5 niveaus) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  {cat:5, niv:'VMBO-BB', q:'Wat is solidariteit? Leg uit hoe solidariteit werkt bij de AOW. Geef een voorbeeld.', model:'<strong>Solidariteit</strong> betekent dat mensen voor elkaar zorgen, ook als ze er zelf geen direct voordeel van hebben. Bij de <strong>AOW</strong> betalen mensen die nu werken elke maand premie. Dat geld gaat direct naar mensen die nu met pensioen zijn. Voorbeeld: jouw ouders betalen mee aan de AOW van opa en oma. Later, als jij werkt, betaal jij mee aan de AOW van jouw ouders. Zo zorgen generaties voor elkaar.', sleutels:['solidariteit','AOW','werkenden betalen','gepensioneerden','generaties']},
  {cat:5, niv:'VMBO-KB', q:'Leg het omslagstelsel uit. Hoe werkt solidariteit hierin? Noem ook Г©Г©n nadeel van dit systeem.', model:'Bij het <strong>omslagstelsel</strong> betalen werkenden nu premie, en dat geld gaat direct naar de uitkeringen van huidige gepensioneerden. Er wordt niets opgespaard. Solidariteit zit erin dat de werkende generatie de ouderen ondersteunt вҖ” net zoals de vorige generatie dat voor hГ©n deed.<br><br><strong>Nadeel</strong>: als er minder werkenden zijn dan gepensioneerden (door vergrijzing), moeten werkenden meer betalen of gepensioneerden minder ontvangen. Het systeem is kwetsbaar voor demografische veranderingen.', sleutels:['omslagstelsel','werkenden','gepensioneerden','solidariteit','vergrijzing','nadeel']},
  {cat:5, niv:'VMBO-TL', q:'Beschrijf de generatiekloof in het Nederlandse pensioenstelsel. Gebruik de begrippen omslagstelsel, vergrijzing en solidariteit. Is het huidige systeem eerlijk voor jongeren?', model:'In het <strong>omslagstelsel</strong> betalen werkenden premie voor de huidige gepensioneerden. Door <strong>vergrijzing</strong> вҖ” meer ouderen, minder jongeren вҖ” neemt de druk op dit systeem toe. Steeds minder werkenden dragen de kosten van steeds meer gepensioneerden.<br><br><strong>Solidariteit</strong> is de kern: generaties helpen elkaar. Maar de vraag is of dat eerlijk is als jongeren relatief meer betalen dan eerdere generaties.<br><br><strong>Eerlijk?</strong> Er zijn twee kanten. VГіГіr: solidariteit is een maatschappelijke keuze, en elke generatie heeft ooit geprofiteerd van eerdere generaties. Tegen: jongeren van nu hebben minder zekerheid over hun eigen pensioen dan ouderen nu genieten вҖ” dat is een ongelijkheid in zekerheid.', sleutels:['omslagstelsel','vergrijzing','solidariteit','generatiekloof','werkenden','eerlijk']},
  {cat:5, niv:'HAVO', q:'Analyseer de spanning tussen solidariteit en eigen belang in het pensioendebat. Welke rol speelt het omslagstelsel, en hoe pakt de Wet Toekomst Pensioenen dit aan?', model:'<strong>Spanning</strong>: solidariteit vraagt dat werkenden bijdragen aan de AOW van ouderen, ook als zij zelf minder zekerheden opbouwen. Eigen belang van jongeren is een zo hoog mogelijk pensioen voor een zo laag mogelijke premie.<br><br><strong>Omslagstelsel</strong>: werkenden betalen nu voor gepensioneerden. Bij toenemende vergrijzing stijgt de last per werkende вҶ’ intergenerationele spanning.<br><br><strong>Wet Toekomst Pensioenen (2023)</strong>: overgang van collectieve middelloonregelingen naar persoonlijke pensioenpotten. Voordeel: transparanter en eerlijker вҖ” je ziet wat je zelf opbouwt. Nadeel: meer individueel beleggingsrisico, minder collectieve buffers. De solidariteit verschuift van risico-pooling naar meer eigen verantwoordelijkheid.', sleutels:['solidariteit','eigen belang','omslagstelsel','vergrijzing','Wet Toekomst Pensioenen','persoonlijke pensioenpot','intergenerationeel']},
  {cat:5, niv:'VWO', q:'Evalueer de intergenerationele rechtvaardigheid van het Nederlandse pensioenstelsel. Gebruik de begrippen omslagstelsel, kapitaaldekking, actuariГ«le eerlijkheid en impliciete overheidsschuld.', model:'<strong>Intergenerationele rechtvaardigheid</strong>: draagt elk cohort zijn eigen last, of worden kosten doorgeschoven?<br><br><strong>Omslagstelsel (AOW)</strong>: elke generatie betaalt voor de vorige. Dit is een impliciet contract. Probleem: de <em>impliciete overheidsschuld</em> вҖ” de contante waarde van toekomstige AOW-verplichtingen вҖ” is enorm (schattingen: 300вҖ“500% BBP). Dit is niet zichtbaar op de rijksbegroting, maar is een reГ«le last voor toekomstige generaties.<br><br><strong>Kapitaaldekking (2e pijler)</strong>: iedere generatie spaart voor zichzelf. Actuarieel eerlijker вҖ” je ontvangt wat je hebt ingelegd plus rendement. Maar: overgang van omslagstelsel naar kapitaaldekking vergt een transitiegeneratie die dubbel betaalt (voor de ouderen Г©n zichzelf).<br><br><strong>Wet Toekomst Pensioenen (2023)</strong>: persoonlijke pensioenpotten met collectieve risicodeling. Actuarieel eerlijker, maar jongeren dragen meer beleggingsrisico. Solidariteit is beperkt maar niet afgeschaft.<br><br><strong>Conclusie</strong>: het huidige stelsel is niet volledig actuarieel eerlijk voor jongere cohorten вҖ” zij dragen de kosten van vergrijzing zonder proportioneel hogere toekomstige uitkeringen te kunnen verwachten.', sleutels:['intergenerationeel','omslagstelsel','kapitaaldekking','actuariГ«le eerlijkheid','impliciete overheidsschuld','vergrijzing','Wet Toekomst Pensioenen','transitiegeneratie']},

  // в”Җв”Җ SCHRIJFTRAINER: Is de vakbond nog wel van deze tijd? (5 niveaus) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  {cat:3, niv:'VMBO-BB', q:'Wat doet een vakbond? Leg uit waarom werknemers zich aansluiten bij een vakbond. Geef een voorbeeld.', model:'Een <strong>vakbond</strong> is een organisatie die opkomt voor de belangen van werknemers. De vakbond onderhandelt met werkgevers over loon, werktijden en andere arbeidsvoorwaarden. De uitkomst heet een <strong>CAO</strong> (Collectieve Arbeidsovereenkomst). Voorbeeld: de vakbond FNV onderhandelt voor alle mensen die in de supermarkt werken. Ze spreken af dat het loon minimaal вӮ¬14 per uur is en dat werknemers recht hebben op pauzes. Als je lid bent, betaal je een kleine contributie вҖ” maar je profiteert van alle afspraken die de vakbond maakt.', sleutels:['vakbond','werknemers','CAO','onderhandelen','loon','arbeidsvoorwaarden']},
  {cat:3, niv:'VMBO-KB', q:'Leg uit wat een staking is. Wanneer mag een vakbond staken en wat is het doel? Geef een concreet voorbeeld.', model:'Een <strong>staking</strong> is een collectieve werkonderbreking: werknemers stoppen samen met werken om druk te zetten op de werkgever. Het doel is een betere CAO afdwingen вҖ” hogere lonen, betere werktijden of meer veiligheid op het werk.<br><br>Een staking is in Nederland pas toegestaan als <strong>ultimum remedium</strong>: alle andere onderhandelingspogingen zijn mislukt. Je kunt niet zomaar staken als je even niet tevreden bent.<br><br>Voorbeeld: als de vakbond en NS het niet eens worden over loonsverhogingen, kunnen conducteurs en machinisten staken. Dan rijden er geen treinen вҖ” dat zorgt voor publieke druk op NS om toch een betere deal te bieden.', sleutels:['staking','collectief','druk zetten','ultimum remedium','CAO','loon']},
  {cat:3, niv:'VMBO-TL', q:'Is de vakbond nog wel van deze tijd? Geef argumenten vГіГіr en tГ©gen het nut van vakbonden in de moderne arbeidsmarkt. Betrek de begrippen CAO, zzp en individualisering.', model:'<strong>VГіГіr</strong>: vakbonden beschermen werknemers die zelf weinig macht hebben tegenover grote werkgevers. De <strong>CAO</strong> biedt rechtsgelijkheid en voorkomt onderlinge concurrentie op arbeidsvoorwaarden. Zonder vakbonden zouden werkgevers lonen kunnen drukken. Juist in tijden van automatisering en onzekerheid is collectieve bescherming waardevol.<br><br><strong>Tegen</strong>: vakbonden vertegenwoordigen steeds minder werkenden. Door <strong>individualisering</strong> willen veel mensen zelf afspraken maken. De groei van <strong>zzp</strong>-werk valt buiten de CAO-structuur. Jongeren herkennen zich minder in de traditionele vakbeweging. Het lidmaatschap daalt.<br><br><strong>Conclusie</strong>: vakbonden zijn nog steeds relevant, maar moeten vernieuwen om zzp\'ers, flexwerkers en jongeren te bereiken.', sleutels:['vakbond','CAO','zzp','individualisering','collectief','relevant','vernieuwen']},
  {cat:3, niv:'HAVO', q:'Analyseer het free-riderprobleem bij vakbonden. Waarom daalt het lidmaatschap, en wat zijn de economische gevolgen voor de onderhandelingspositie van werknemers?', model:'<strong>Free-riderprobleem</strong>: de uitkomsten van CAO-onderhandelingen gelden automatisch voor alle werknemers in een sector вҖ” ook voor niet-leden. Daardoor is er geen individuele prikkel om lid te worden: je profiteert van de collectieve inspanning zonder bij te dragen.<br><br><strong>Gevolg</strong>: dalend lidmaatschap (van ~40% in 1980 naar ~15% nu). Dit verzwakt de democratische legitimiteit van vakbonden: hoe minder leden, hoe minder ze werkelijk namens de sector spreken. Werkgevers kunnen dit argument gebruiken om lagere loonsverhogingen af te dwingen.<br><br><strong>Bredere economische gevolgen</strong>: zwakkere vakbonden вҶ’ lagere loongroei вҶ’ kleinere binnenlandse vraag вҶ’ mogelijk lagere conjunctuur. Omgekeerd: sterkere vakbonden вҶ’ hogere lonen вҶ’ hogere inflatie als de productiviteit niet meegroeit.', sleutels:['free-rider','CAO voor iedereen','individuele prikkel','lidmaatschap daalt','legitimiteit','loongroei']},
  {cat:3, niv:'VWO', q:'Evalueer de stelling: "Vakbonden zijn in de 21e eeuw meer een rem op economische aanpassing dan een bescherming van werknemers." Gebruik de begrippen Poldermodel, machtsverhoudingen, zzp en institutionele sclerose.', model:'<strong>Pro stelling</strong>: vakbonden vertegenwoordigen voornamelijk vaste werknemers in traditionele sectoren. Ze onderhandelen voor behoud van verworven rechten, waardoor arbeidsmarkthervormingen stranden. Dit heet <em>institutionele sclerose</em>: gevestigde partijen blokkeren noodzakelijke verandering. De groei van zzp en platform-economie (Uber, Deliveroo) valt buiten het CAO-systeem вҖ” vakbonden hebben geen vat op dit segment.<br><br><strong>Contra stelling</strong>: het <strong>Poldermodel</strong> toont dat vakbonden juist stabiliserende kracht zijn. Het Akkoord van Wassenaar (1982) doorverbrak het gevangenendilemma van werkgevers en werknemers. Zonder vakbonden zou de <em>machtsverhouding</em> op de arbeidsmarkt volledig verschuiven naar werkgevers вҶ’ druk op lonen вҶ’ hogere ongelijkheid (dalende arbeidsinkomensquote).<br><br><strong>Nuance</strong>: het probleem is niet vakbonden als instituut, maar hun representativiteitsprobleem. Vernieuwd vakbondsmodel dat zzp, flex en jongeren vertegenwoordigt, lost dit op. Historisch bewijs pleit eerder voor hervorming dan afschaffing.', sleutels:['institutionele sclerose','Poldermodel','machtsverhoudingen','arbeidsinkomensquote','zzp','CAO','vernieuwen','gevangenendilemma']},

  // в”Җв”Җ SCHRIJFTRAINER: De acceptatieplicht in de zorg (5 niveaus) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  {cat:5, niv:'VMBO-BB', q:'Wat betekent de acceptatieplicht bij de zorgverzekering? Leg uit waarom dit belangrijk is. Geef een voorbeeld van wat er zou gebeuren zonder deze regel.', model:'De <strong>acceptatieplicht</strong> betekent dat een zorgverzekeraar iedereen moet aannemen voor de basisverzekering вҖ” ook mensen die al ziek zijn of een hoog risico hebben. De verzekeraar mag niemand weigeren of een hogere premie vragen vanwege zijn gezondheid.<br><br>Dit is belangrijk omdat anders alleen gezonde mensen zich goedkoop kunnen verzekeren. Zieke mensen zouden geen verzekeraar vinden, of een veel te dure premie moeten betalen.<br><br>Voorbeeld: stel dat er geen acceptatieplicht was. Iemand met diabetes zou misschien geweigerd worden. Dan heeft hij geen zorgverzekering, kan hij geen dokter betalen en wordt zijn ziekte erger. De acceptatieplicht voorkomt dit.', sleutels:['acceptatieplicht','niemand weigeren','basisverzekering','gelijke premie','solidariteit']},
  {cat:5, niv:'VMBO-KB', q:'Leg uit wat averechtse selectie is bij verzekeringen. Hoe lost de acceptatieplicht dit op? Gebruik een voorbeeld uit de zorgverzekering.', model:'<strong>Averechtse selectie</strong> betekent dat vooral mensen met een hoog risico een verzekering afsluiten, terwijl gezonde mensen afhaken als de premie te hoog wordt. Gevolg: de premies stijgen steeds verder totdat de verzekering onbetaalbaar wordt.<br><br>Voorbeeld bij zorgverzekering: als de verzekering niet verplicht was, zouden mensen die nauwelijks ziek zijn zich misschien niet verzekeren. Dan blijven alleen de dure, zieke verzekerden over. De premies stijgen вҶ’ meer gezonden stappen op вҶ’ premies stijgen verder вҶ’ de markt stort in.<br><br>De <strong>acceptatieplicht</strong> Г©n de <strong>verzekeringsplicht</strong> lossen dit samen op: iedereen doet mee, dus de premie blijft betaalbaar voor iedereen.', sleutels:['averechtse selectie','hoog risico','verzekeringsplicht','acceptatieplicht','premie betaalbaar']},
  {cat:5, niv:'VMBO-TL', q:'Beschrijf hoe solidariteit werkt in de Nederlandse zorgverzekering. Gebruik de begrippen acceptatieplicht, risicoverevening en averechtse selectie. Vindt jij dit een eerlijk systeem? Geef argumenten.', model:'In de Nederlandse zorgverzekering betaalt iedereen een vaste nominale premie. Verzekeraars moeten iedereen accepteren (<strong>acceptatieplicht</strong>). Ze mogen de premie niet verhogen voor zieke mensen. Hierdoor betalen gezonde mensen indirect mee voor de zorg van zieken вҖ” dat is <strong>solidariteit</strong>.<br><br>Om te voorkomen dat verzekeraars alleen gezonde klanten willen, verdeelt de overheid geld via <strong>risicoverevening</strong>: verzekeraars met veel zieke klanten krijgen compensatie.<br><br><strong>Averechtse selectie</strong> wordt zo voorkomen: ook ongezonde mensen zijn welkom, want de verzekeraar wordt gecompenseerd.<br><br><strong>Is het eerlijk?</strong> VГіГіr: iedereen kan ziek worden, solidariteit beschermt mensen met pech. Tegen: mensen die zelf ongezond leven dragen evenveel bij als mensen die gezond leven вҖ” is dat eerlijk?', sleutels:['solidariteit','acceptatieplicht','risicoverevening','averechtse selectie','nominale premie','eerlijk']},
  {cat:5, niv:'HAVO', q:'Analyseer waarom de zorgverzekeringsmarkt zonder regulering zou falen. Bespreek de rol van acceptatieplicht, verzekeringsplicht en risicoverevening als correctiemechanismen.', model:'<strong>Marktfalen zonder regulering</strong>: op een vrije verzekeringsmarkt treedt <em>averechtse selectie</em> op вҖ” ongezonde mensen verzekeren zich meer, gezonde mensen haken af bij hoge premies. De pool verslechtert вҶ’ premies stijgen вҶ’ spiraal naar markinstorting. Bovendien: informatieasymmetrie (verzekerden weten meer over hun gezondheid dan de verzekeraar).<br><br><strong>Drie correctiemechanismen</strong>:<br>1. <em>Verzekeringsplicht</em>: iedereen is verplicht verzekerd вҶ’ pool bevat ook gezonde mensen вҶ’ premies blijven betaalbaar.<br>2. <em>Acceptatieplicht</em>: verzekeraars kunnen niet selecteren op gezondheid вҶ’ ongezonden worden niet uitgesloten.<br>3. <em>Risicoverevening</em>: overheid herverdeelt premie-inkomsten tussen verzekeraars op basis van het risicoprofiel van hun verzekerden вҶ’ geen financieel voordeel bij selectie op gezondheid.<br><br>Samen lossen deze drie instrumenten het marktfalen op door informatieongelijkheid te neutraliseren en solidariteit institutioneel te verankeren.', sleutels:['averechtse selectie','marktfalen','verzekeringsplicht','acceptatieplicht','risicoverevening','informatieasymmetrie','solidariteit']},
  {cat:5, niv:'VWO', q:'Evalueer de ethische en economische spanningen rond Big Data in de zorgverzekering. Gebruik de begrippen actuariГ«le eerlijkheid, solidariteit, informatieasymmetrie en acceptatieplicht.', model:'<strong>ActuariГ«le eerlijkheid</strong>: premies zijn eerlijk als ze het individuele risico weerspiegelen. Met Big Data (koopgedrag, fitness-trackers, genetica) kunnen verzekeraars risico\'s steeds nauwkeuriger voorspellen. Dit pleit voor individuele differentiatie.<br><br><strong>Economisch probleem</strong>: als iedereen zijn risico nauwkeurig kent, verdwijnt de basis van verzekeren. Verzekering werkt dankzij <em>informatieasymmetrie</em>: niemand weet van tevoren wie ziek wordt. Bij volledige informatie wil een verzekeraar hoog-risicoklanten niet meer accepteren (of voor een prohibitieve premie). De pool implodeert вҖ” mensen met voorspelbaar hoog risico worden onverzekerbaar.<br><br><strong>Solidariteitsargument</strong>: gezondheidsrisico\'s zijn vaak niet zelf gekozen (genetica, armoede, omgeving). Premiedifferentiatie op basis hiervan is moreel problematisch Г©n economisch destabiliserend.<br><br><strong>Conclusie</strong>: de <strong>acceptatieplicht</strong> en het verbod op gebruik van genetische data zijn geen inefficiГ«nte beperkingen вҖ” ze zijn de institutionele voorwaarde voor een sociaal draagbare en economisch stabiele verzekeringsmarkt. Big Data vergroot de spanning, maar de beleidsrespons (AVG, Wet medische keuringen) behoudt bewust informatieasymmetrie als beschermingsmechanisme.', sleutels:['actuariГ«le eerlijkheid','solidariteit','informatieasymmetrie','Big Data','acceptatieplicht','genetische data','AVG','pool']},

  // в”Җв”Җ SCHRIJFTRAINER: Hoe meten we geluk in een land? (5 niveaus) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  {cat:2, niv:'VMBO-BB', q:'Wat meet het BBP? Noem twee dingen die het BBP NIET meet. Leg uit waarom dat een probleem kan zijn.', model:'Het <strong>BBP</strong> (Bruto Binnenlands Product) meet de totale waarde van alles wat in een land in een jaar geproduceerd wordt. Het is een maat voor de economische omvang van een land.<br><br>Het BBP meet <strong>niet</strong>: (1) hoe gelukkig mensen zijn вҖ” een land kan een hoog BBP hebben maar toch veel ontevreden mensen; (2) hoe eerlijk rijkdom verdeeld is вҖ” als Г©Г©n persoon heel veel verdient, stijgt het BBP, maar de rest merkt er niets van.<br><br>Dat is een probleem omdat politici besluiten nemen op basis van het BBP. Als ze alleen naar BBP kijken, vergeten ze dat mensen ook geluk, eerlijkheid en een schoon milieu belangrijk vinden.', sleutels:['BBP','productiewaarde','geluk niet','verdeling niet','probleem']},
  {cat:2, niv:'VMBO-KB', q:'Leg het verschil uit tussen BBP en brede welvaart. Welke indicator van het CBS meet brede welvaart? Noem twee dingen die deze indicator meeneemt die het BBP negeert.', model:'Het <strong>BBP</strong> meet alleen de economische productie van een land вҖ” hoeveel geld er omgaat. <strong>Brede welvaart</strong> gaat verder: het kijkt ook naar hoe mensen het hebben, hoe het milieu ervoor staat en of de welvaart ook voor volgende generaties beschikbaar blijft.<br><br>De <strong>Monitor Brede Welvaart</strong> van het CBS (Centraal Bureau voor de Statistiek) meet brede welvaart in Nederland. Hij neemt mee: (1) <strong>gezondheid</strong> вҖ” hoe lang en gezond leven mensen?; (2) <strong>milieu</strong> вҖ” in hoeverre putten we de natuur uit?<br><br>Dit geeft een realistischer beeld van hoe goed het Г©cht gaat in een land.', sleutels:['BBP','brede welvaart','Monitor Brede Welvaart','CBS','gezondheid','milieu']},
  {cat:2, niv:'VMBO-TL', q:'Het BBP stijgt in Nederland, maar tegelijk neemt de biodiversiteit af en groeit de inkomensongelijkheid. Legt dit een tekortkoming van het BBP bloot? Gebruik de begrippen brede welvaart en Monitor Brede Welvaart in je antwoord.', model:'Ja, dit legt een fundamentele tekortkoming van het BBP bloot. Het BBP meet alleen de <strong>economische productie</strong> вҖ” hoeveel er geproduceerd en verkocht wordt. Het houdt geen rekening met wat dat kost voor de natuur of hoe de opbrengst verdeeld is.<br><br><strong>Brede welvaart</strong> gaat verder: het kijkt ook naar milieu, gezondheid, geluk, veiligheid en sociale gelijkheid. De <strong>Monitor Brede Welvaart</strong> van het CBS combineert twintig indicatoren en geeft een completer beeld.<br><br>Als het BBP stijgt maar biodiversiteit afneemt en ongelijkheid groeit, zegt de Monitor Brede Welvaart: het gaat niet allemaal goed. Dat is precies het punt: BBP-groei is niet hetzelfde als vooruitgang.', sleutels:['BBP','biodiversiteit','ongelijkheid','tekortkoming','brede welvaart','Monitor Brede Welvaart','CBS']},
  {cat:2, niv:'HAVO', q:'Vergelijk het BBP met de Monitor Brede Welvaart als beleidsinstrumenten. Wanneer is elk het meest informatief? Wat zijn de grenzen van brede welvaart als maatstaf?', model:'<strong>BBP als instrument</strong>: geschikt voor kortetermijnconjunctuuranalyse, internationale vergelijking van economische omvang en begrotingsbeleid. Eendimensionaal maar eenvoudig te meten en te vergelijken.<br><br><strong>Monitor Brede Welvaart (CBS)</strong>: beter voor langetermijnbeleid waarbij natuur, gezondheid en sociale cohesie meewegen. Geeft een completer beeld van hoe het met de samenleving gaat вҖ” niet alleen materieel.<br><br><strong>Grenzen van brede welvaart</strong>:<br>1. <em>Normatieve keuzes</em>: welke indicatoren tellen en hoe zwaar? Die keuze is politiek, niet objectief.<br>2. <em>Aggregatieprobleem</em>: hoe combineer je "COвӮӮ-uitstoot" en "geluk" in Г©Г©n getal? EГ©n samengesteld getal verbergt hoe het op deelterreinen gaat.<br>3. <em>Vergelijkbaarheid</em>: BBP is internationaal gestandaardiseerd; brede welvaartsmaatstaven variГ«ren per land, waardoor vergelijking moeilijker is.', sleutels:['BBP','Monitor Brede Welvaart','CBS','normatief','aggregatieprobleem','vergelijkbaarheid','beleid']},
  {cat:2, niv:'VWO', q:'Evalueer de Donuteconomie van Kate Raworth als alternatief voor BBP-gestuurde groeidoelstellingen. Gebruik de begrippen sociaal fundament, ecologisch plafond, brede welvaart en Capability Approach (Sen).', model:'<strong>Raworths Donuteconomie (2012)</strong>: welvaart bestaat niet uit maximale BBP-groei maar uit gedijen <em>tussen</em> een sociaal fundament (basisbehoeften voor iedereen) en een ecologisch plafond (planetaire grenzen). Het doel is niet groeien maar in balans blijven.<br><br><strong>Verhouding tot BBP</strong>: BBP meet omvang, niet richting. Groei kan plaatsvinden door afbraak van natuur of toename van ongelijkheid вҖ” het BBP stijgt toch. De Donut corrigeert dit door beide grenzen explicieter te stellen.<br><br><strong>Verhouding tot Monitor Brede Welvaart</strong>: de Monitor meet hoe het nu gaat op 21 dimensies. De Donut is normatief вҖ” ze stelt een doel en een grens. De Monitor is diagnose; de Donut is prescriptie.<br><br><strong>Capability Approach (Sen)</strong>: Sen (Nobelprijs 1998) vraagt niet "hoeveel hebben mensen?" maar "waartoe zijn mensen in staat?". De Donut\'s sociaal fundament overlapt hiermee: basisbehoeften zijn voorwaarden voor capabilities. Maar de Donut operationaliseert dit in planetaire grenzen вҖ” iets wat Sen niet deed.<br><br><strong>Kritiek</strong>: de Donut is normatief en geeft geen operationeel beleidsinstrument. Amsterdam past het toe, maar het is onduidelijk hoe je afwegingen maakt als het sociaal fundament de ecologische grens overschrijdt.', sleutels:['Donut','Kate Raworth','sociaal fundament','ecologisch plafond','brede welvaart','BBP','Capability Approach','Sen','normatief','Monitor Brede Welvaart']}
];
let stHuidigeVraag = null;
let stCategorie = 0; // 0 = alle

function stSelectCat(cat){
  stCategorie = cat;
  _stVWOonly = false;
  // Update button styles
  document.querySelectorAll('.st-cat-btn').forEach((b,i)=>{
    if(i===cat){
      b.style.background='var(--g)';b.style.color='#fff';b.style.borderColor='var(--g)';
    } else {
      b.style.background='var(--white)';b.style.color='var(--text)';b.style.borderColor='#dde';
    }
  });
  laadNieuweSchrijfvraag();
}

let _stVWOonly = false;

function stSelectVWO(){
  _stVWOonly = true;
  stCategorie = 0;
  document.querySelectorAll('.st-cat-btn').forEach(b=>{
    b.style.background='#fff';b.style.color=b.id==='st-vwo-btn'?'#1a5a8a':'var(--text)';
    b.style.borderColor=b.id==='st-vwo-btn'?'#1a5a8a':'#dde';
  });
  const btn = document.getElementById('st-vwo-btn');
  if(btn){btn.style.background='#1a5a8a';btn.style.color='#fff';}
  laadNieuweSchrijfvraag();
}

function laadNieuweSchrijfvraag(){
  let pool;
  if(_stVWOonly){
    pool = SCHRIJFTRAINER_VRAGEN.filter(v=>v.niv==='VWO');
  } else {
    pool = stCategorie===0 ? SCHRIJFTRAINER_VRAGEN : SCHRIJFTRAINER_VRAGEN.filter(v=>v.cat===stCategorie);
  }
  if(pool.length===0) return;
  stHuidigeVraag = pool[Math.floor(Math.random()*pool.length)];
  renderSchrijfvraag();
}

function renderSchrijfvraag(){
  const container = document.getElementById('st-vraag-container');
  if(!container || !stHuidigeVraag) return;
  const v = stHuidigeVraag;
  const catNamen = {1:'Markt',2:'Overheid',3:'Arbeid',4:'Buitenland'};
  container.innerHTML=`
    <div style="margin-bottom:.8rem">
      <span style="background:#f0f7f3;color:var(--g);font-size:.72rem;font-weight:700;padding:2px 9px;border-radius:20px;border:1px solid #b0d9be">${catNamen[v.cat]||'Algemeen'}</span>
      <span style="background:#eef4ff;color:#1a5a8a;font-size:.72rem;font-weight:700;padding:2px 9px;border-radius:20px;border:1px solid #c5d8f0;margin-left:4px">${v.niv}</span>
    </div>
    <div style="background:#f4f8f4;border-left:4px solid var(--g);border-radius:0 10px 10px 0;padding:14px 16px;font-size:.92rem;line-height:1.6;margin-bottom:.9rem">${v.q}</div>
    <textarea id="st-antwoord" placeholder="Schrijf hier je antwoord. Probeer de begrippen te gebruiken die je kent. Na het klikken zie je het nakijkmodel met sleutelwoorden." style="width:100%;min-height:100px;border:2px solid #dde;border-radius:10px;padding:12px;font-family:'DM Sans',sans-serif;font-size:.9rem;resize:vertical;background:var(--white);color:var(--text)"></textarea>
    <div style="display:flex;gap:.6rem;flex-wrap:wrap;margin-top:.6rem">
      <button onclick="controleerSchrijfAntwoord()" style="background:var(--g);color:#fff;border:none;border-radius:10px;padding:.6rem 1.3rem;font-weight:700;font-family:'Lexend',sans-serif;cursor:pointer;font-size:.88rem">рҹ“Ӣ Toon nakijkmodel</button>
      <button onclick="laadNieuweSchrijfvraag()" style="background:var(--white);border:2px solid #dde;border-radius:10px;padding:.6rem 1.1rem;font-weight:700;font-family:'Lexend',sans-serif;cursor:pointer;font-size:.88rem;color:var(--text)">рҹ”Җ Nieuwe vraag</button>
    </div>
    <div id="st-feedback"></div>`;
}

function controleerSchrijfAntwoord(){
  if(!stHuidigeVraag) return;
  const v = stHuidigeVraag;
  const antwoord = (document.getElementById('st-antwoord')||{}).value || '';
  const gevonden = (v.sleutels||[]).filter(s=>antwoord.toLowerCase().includes(s.toLowerCase()));
  const totaal = (v.sleutels||[]).length;
  const pct = Math.round((gevonden.length/Math.max(totaal,1))*100);
  const kleur = pct>=60?'#1a7a4a':pct>=30?'#b07800':'#b30000';
  const label = pct>=60?'вң… Goed antwoord!':pct>=30?'вҡ пёҸ Gedeeltelijk goed':'вқҢ Kijk nog eens naar de sleutelwoorden';
  const fb = document.getElementById('st-feedback');
  if(!fb) return;
  fb.innerHTML=`
    <div style="margin-top:1rem;border:2px solid ${kleur};border-radius:12px;overflow:hidden">
      <div style="background:${kleur};color:#fff;padding:.55rem 1rem;font-family:'Lexend',sans-serif;font-weight:700;font-size:.85rem">${label} вҖ” ${gevonden.length}/${totaal} sleutelwoorden</div>
      <div style="padding:1rem;background:var(--white)">
        <div style="margin-bottom:.5rem;font-size:.83rem"><strong>Sleutelwoorden die jij hebt gebruikt:</strong><br>${gevonden.length>0?gevonden.map(s=>'<span style="display:inline-block;background:#e8f5e9;color:#1a7a4a;border-radius:6px;padding:2px 8px;font-size:.78rem;font-weight:700;margin:.15rem">'+s+'</span>').join(''):'<span style="color:#888">Geen herkend</span>'}</div>
        <div style="margin-bottom:.7rem;font-size:.83rem"><strong>Nog te noemen:</strong><br>${(v.sleutels||[]).filter(s=>!antwoord.toLowerCase().includes(s.toLowerCase())).map(s=>'<span style="display:inline-block;background:#fff3e0;color:#b07800;border-radius:6px;padding:2px 8px;font-size:.78rem;margin:.15rem">'+s+'</span>').join('')||'<span style="color:#1a7a4a">Alles gevonden! рҹҺү</span>'}</div>
        <div style="background:#f0f7f3;border-radius:8px;padding:10px 14px;font-size:.88rem;line-height:1.6"><strong>рҹ“Ӣ Nakijkmodel:</strong><br>${v.model}</div>
      </div>
    </div>`;
  // Disable textarea
  const ta=document.getElementById('st-antwoord');
  if(ta) ta.disabled=true;
  // Update quiz score tracking
  if(typeof registreerScore==='function') registreerScore('schrijftrainer', pct>=60?1:0, 1, 'Schrijftrainer');
}

// Auto-init schrijftrainer als EHBO geopend wordt
const _origToonEHBO = typeof toonEHBO !== 'undefined' ? toonEHBO : null;
function initSchrijftrainerIfNeeded(){
  if(document.getElementById('st-vraag-container') && !stHuidigeVraag){
    laadNieuweSchrijfvraag();
  }
}

