// State per casus
const casusSt = {idx:0, vraagIdx:0, antwoorden:[], gedaan:false};

function toonCasus(idx){
  casusSt.idx = idx;
  casusSt.vraagIdx = 0;
  casusSt.antwoorden = [];
  casusSt.gedaan = false;
  // Tabs bijwerken
  document.querySelectorAll('.casus-tab-btn').forEach((b,i)=>{
    b.classList.toggle('active', i===idx);
  });
  renderCasus();
}

function renderCasus(){
  const c = CASUS_DATA[casusSt.idx];
  const container = document.getElementById('casus-container');
  if(!container) return;

  // Bouw tabelrijen
  const tHeaderRow = c.tabel.headers.map(h=>`<th style="padding:.5rem .7rem;text-align:left;background:#1a5a8a;color:#fff;font-size:.8rem">${h}</th>`).join('');
  const tBodyRows = c.tabel.rows.map((row,i)=>{
    const bg = i%2===0?'':'background:#f5f8ff';
    return `<tr style="${bg}">${row.map(cell=>`<td style="padding:.45rem .7rem;font-size:.82rem;border-bottom:1px solid #eee">${cell}</td>`).join('')}</tr>`;
  }).join('');

  // Vragen rendering
  let vraagHTML = '';
  if(!casusSt.gedaan){
    const v = c.vragen[casusSt.vraagIdx];
    // Open vraag type
    if(c.type==='open'){
      container.innerHTML+=`
        <div style="margin-top:1rem">
          <div style="font-family:'Lexend',sans-serif;font-weight:700;font-size:.88rem;color:#1a5a8a;margin-bottom:.5rem">Vraag ${casusSt.vraagIdx+1} van ${c.vragen.length}</div>
          <div style="background:#f4f8f4;border-left:4px solid var(--g);border-radius:0 10px 10px 0;padding:14px 16px;font-size:.92rem;line-height:1.6;margin-bottom:1rem">${v.q}</div>
          <textarea id="open-antwoord" placeholder="Typ hier je antwoordвҖҰ" style="width:100%;min-height:120px;border:2px solid #dde;border-radius:10px;padding:12px;font-family:'DM Sans',sans-serif;font-size:.9rem;resize:vertical;background:var(--white);color:var(--text)"></textarea>
          <button onclick="controleerOpenAntwoord()" style="margin-top:.7rem;background:var(--g);color:#fff;border:none;border-radius:10px;padding:.65rem 1.4rem;font-weight:700;font-family:'Lexend',sans-serif;cursor:pointer;font-size:.88rem">вң… Controleer mijn antwoord</button>
        </div>`;
      return;
    }
    const opties = v.o.map((opt,i)=>`
      <button class="casus-opt" onclick="casusStemAntwoord(${i})"
        style="width:100%;text-align:left;padding:.65rem 1rem;margin:.3rem 0;border:2px solid #dde;border-radius:10px;background:#fff;cursor:pointer;font-family:inherit;font-size:.88rem;transition:border-color .15s,background .15s"
        onmouseover="this.style.borderColor='#1a7a4a'" onmouseout="this.style.borderColor='#dde'">
        <span style="font-weight:700;color:#1a5a8a;margin-right:.5rem">${String.fromCharCode(65+i)}.</span>${opt}
      </button>`).join('');

    vraagHTML = `
      <div style="background:#fff;border-radius:14px;box-shadow:0 2px 12px rgba(0,0,0,.08);padding:1.2rem;margin-top:1.2rem">
        <div style="font-size:.75rem;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:.05em;margin-bottom:.5rem">
          Vraag ${casusSt.vraagIdx+1} van ${c.vragen.length}
        </div>
        <div style="font-weight:700;font-size:.95rem;color:#1a1a2e;margin-bottom:.8rem">${v.q}</div>
        ${opties}
      </div>`;
  } else {
    // Resultaten tonen
    const score = casusSt.antwoorden.filter((a,i)=>a===c.vragen[i].c).length;
    const resultRows = c.vragen.map((v,i)=>{
      const goed = casusSt.antwoorden[i] === v.c;
      const icon = goed ? 'вң…' : 'вқҢ';
      const gekozen = v.o[casusSt.antwoorden[i]] || 'вҖ”';
      const correct = v.o[v.c];
      return `
        <div style="background:${goed?'#f0fff8':'#fff5f5'};border:1px solid ${goed?'#b8e4cc':'#f5c5c5'};border-radius:10px;padding:.8rem;margin-bottom:.6rem">
          <div style="font-weight:700;font-size:.88rem;margin-bottom:.3rem">${icon} Vraag ${i+1}: ${v.q}</div>
          ${goed?'':`<div style="font-size:.82rem;color:#c0392b">Jouw antwoord: ${gekozen}</div>`}
          <div style="font-size:.82rem;color:#1a7a4a;font-weight:600">Goed antwoord: ${correct}</div>
          <div style="font-size:.81rem;color:#555;margin-top:.3rem;font-style:italic">${v.u}</div>
        </div>`;
    }).join('');

    vraagHTML = `
      <div style="background:#fff;border-radius:14px;box-shadow:0 2px 12px rgba(0,0,0,.08);padding:1.2rem;margin-top:1.2rem">
        <div style="font-family:'Lexend',sans-serif;font-weight:800;font-size:1.1rem;color:#1a1a2e;margin-bottom:.8rem">
          Jouw score: ${score} / ${c.vragen.length} ${score===c.vragen.length?'рҹҺү':'рҹ’Ә'}
        </div>
        ${resultRows}
        <button onclick="toonCasus(casusSt.idx)" style="margin-top:.6rem;background:var(--g);color:#fff;border:none;border-radius:10px;padding:.6rem 1.2rem;cursor:pointer;font-family:inherit;font-weight:700;font-size:.88rem">рҹ”„ Opnieuw proberen</button>
        <button onclick="(function(){const lbl={0:'Markt',1:'Overheid',2:'Arbeid',3:'Buitenland'};const niv={'bb':'VMBO Basis','k':'VMBO Kader','tl':'VMBO-TL','h':'HAVO','v':'VWO'}[getNivKey()]||'VMBO-TL';genereerPrestatiePDF(score,c.vragen.length,'Casus: '+lbl[casusSt.idx],niv,'Casus-opgaven');})()" style="margin-top:.6rem;background:linear-gradient(135deg,#1a5a8a,#2980b9);color:#fff;border:none;border-radius:10px;padding:.6rem 1.2rem;cursor:pointer;font-family:inherit;font-weight:700;font-size:.88rem">рҹ“„ Prestatie-PDF voor docent</button>
      </div>`;
  }

  container.innerHTML = `
    <div style="background:#fff;border-radius:14px;box-shadow:0 2px 12px rgba(0,0,0,.08);overflow:hidden">
      <div style="background:linear-gradient(135deg,#0f4d2e,#1a7a4a);color:#fff;padding:1rem 1.2rem">
        <div style="font-family:'Lexend',sans-serif;font-weight:800;font-size:1.05rem">рҹ“„ ${c.titel}</div>
      </div>
      <div style="padding:1.1rem 1.2rem;font-size:.88rem;line-height:1.7;color:var(--text);white-space:pre-line">${c.tekst}</div>
    </div>

    <div style="background:#fff;border-radius:14px;box-shadow:0 2px 12px rgba(0,0,0,.08);overflow:hidden;margin-top:1rem">
      <div style="background:#1a5a8a;color:#fff;padding:.7rem 1rem;font-family:'Lexend',sans-serif;font-weight:700;font-size:.88rem">рҹ“Ҡ Tabel bij de casus</div>
      <div style="overflow-x:auto">
        <table style="width:100%;border-collapse:collapse">
          <thead><tr>${tHeaderRow}</tr></thead>
          <tbody>${tBodyRows}</tbody>
        </table>
      </div>
    </div>

    ${vraagHTML}`;
}

function controleerOpenAntwoord(){
  const c = CASUS_DATA[casusSt.idx];
  const v = c.vragen[casusSt.vraagIdx];
  const antwoord = (document.getElementById('open-antwoord')||{}).value || '';
  const sleutels = v.sleutelwoorden || [];
  const gevonden = sleutels.filter(s => antwoord.toLowerCase().includes(s.toLowerCase()));
  const score = Math.round((gevonden.length/Math.max(sleutels.length,1))*100);
  const container = document.getElementById('casus-container');
  // Verwijder bestaande feedback als aanwezig
  const bestaande = container.querySelector('.open-feedback');
  if(bestaande) bestaande.remove();
  // Maak feedback blok
  const kleur = score >= 60 ? '#1a7a4a' : score >= 30 ? '#b07800' : '#b30000';
  const label = score >= 60 ? 'вң… Goed antwoord!' : score >= 30 ? 'вҡ пёҸ Gedeeltelijk' : 'вқҢ Probeer opnieuw';
  const fb = document.createElement('div');
  fb.className = 'open-feedback';
  fb.innerHTML = `
    <div style="margin-top:1rem;border:2px solid ${kleur};border-radius:12px;overflow:hidden">
      <div style="background:${kleur};color:#fff;padding:.6rem 1rem;font-family:'Lexend',sans-serif;font-weight:700;font-size:.88rem">${label} вҖ” ${gevonden.length} van ${sleutels.length} sleutelwoorden gevonden</div>
      <div style="padding:1rem;background:var(--white)">
        <div style="font-size:.82rem;color:var(--muted);margin-bottom:.4rem"><strong>Sleutelwoorden die je noemt:</strong> ${gevonden.length>0?gevonden.map(s=>'<span style="background:#e8f5e9;color:#1a7a4a;border-radius:6px;padding:1px 6px;font-size:.78rem;font-weight:700">'+s+'</span>').join(' '):'(geen herkend)'}</div>
        <div style="font-size:.82rem;color:var(--muted);margin-bottom:.6rem"><strong>Nog te noemen:</strong> ${sleutels.filter(s=>!antwoord.toLowerCase().includes(s.toLowerCase())).map(s=>'<span style="background:#fff3e0;color:#b07800;border-radius:6px;padding:1px 6px;font-size:.78rem">'+s+'</span>').join(' ')||'(alles gevonden!)'}</div>
        <details style="margin-top:.4rem">
          <summary style="cursor:pointer;font-family:'Lexend',sans-serif;font-weight:700;font-size:.83rem;color:#1a5a8a">рҹ“Ӣ Bekijk het nakijkmodel</summary>
          <div style="margin-top:.6rem;background:#f0f7f3;border-radius:8px;padding:10px 14px;font-size:.88rem;line-height:1.6">${v.model}</div>
        </details>
      </div>
    </div>`;
  container.appendChild(fb);
  // Ga naar volgende vraag of resultaat
  casusSt.antwoorden.push(gevonden.length >= sleutels.length/2 ? 1 : 0);
  const btnWrap = document.createElement('div');
  btnWrap.style.cssText='display:flex;gap:.6rem;flex-wrap:wrap;margin-top:.7rem';
  if(casusSt.vraagIdx < c.vragen.length - 1){
    btnWrap.innerHTML=`<button onclick="casusSt.vraagIdx++;toonCasus(casusSt.idx)" style="background:var(--g);color:#fff;border:none;border-radius:10px;padding:.6rem 1.2rem;cursor:pointer;font-family:inherit;font-weight:700;font-size:.88rem">вһЎпёҸ Volgende vraag</button>`;
  } else {
    const goedCount = casusSt.antwoorden.filter(Boolean).length;
    btnWrap.innerHTML=`<div style="width:100%;text-align:center;padding:.8rem;background:#f0faf4;border-radius:10px;font-family:'Lexend',sans-serif;font-weight:700;color:var(--gd)">рҹҸҒ Casus afgerond! Score: ${goedCount}/${c.vragen.length}</div><button onclick="toonCasus(casusSt.idx)" style="background:var(--g);color:#fff;border:none;border-radius:10px;padding:.6rem 1.2rem;cursor:pointer;font-family:inherit;font-weight:700;font-size:.88rem">рҹ”„ Opnieuw</button>`;
  }
  container.appendChild(btnWrap);
  // Disable textarea
  const ta = document.getElementById('open-antwoord');
  if(ta) ta.disabled=true;
  const btn = container.querySelector('button[onclick="controleerOpenAntwoord()"]');
  if(btn) btn.disabled=true;
}

function casusStemAntwoord(idx){
  const c = CASUS_DATA[casusSt.idx];
  casusSt.antwoorden.push(idx);
  const goed = idx === c.vragen[casusSt.vraagIdx].c;

  // Visuele feedback
  const opts = document.querySelectorAll('.casus-opt');
  opts.forEach((btn,i)=>{
    btn.disabled = true;
    if(i===idx){
      btn.style.background = goed ? '#e8fdf0' : '#fdf0f0';
      btn.style.borderColor = goed ? '#1a7a4a' : '#c0392b';
      btn.style.fontWeight = '700';
    }
    if(i===c.vragen[casusSt.vraagIdx].c && !goed){
      btn.style.borderColor = '#1a7a4a';
    }
  });

  // Uitleg toevoegen
  const uitlegEl = document.createElement('div');
  uitlegEl.style.cssText = `margin:.6rem 0 0;padding:.7rem .9rem;border-radius:10px;font-size:.83rem;font-style:italic;color:#444;background:${goed?'#f0fff8':'#fff8e8'};border:1px solid ${goed?'#b8e4cc':'#f0d8a0'}`;
  uitlegEl.innerHTML = `<strong>${goed?'вң… Goed!':'вқҢ Helaas.'}</strong> ${c.vragen[casusSt.vraagIdx].u}`;
  document.querySelector('.casus-opt')?.closest('div')?.appendChild(uitlegEl);

  // Volgende knop
  const volgendBtn = document.createElement('button');
  volgendBtn.style.cssText = 'margin-top:.8rem;background:var(--g);color:#fff;border:none;border-radius:10px;padding:.6rem 1.2rem;cursor:pointer;font-family:inherit;font-weight:700;font-size:.88rem;width:100%';
  const isLaatste = casusSt.vraagIdx >= c.vragen.length - 1;
  volgendBtn.textContent = isLaatste ? 'рҹ“Ҡ Bekijk resultaat' : 'вһЎпёҸ Volgende vraag';
  volgendBtn.onclick = function(){
    if(isLaatste){
      casusSt.gedaan = true;
    } else {
      casusSt.vraagIdx++;
    }
    renderCasus();
  };
  document.querySelector('.casus-opt')?.closest('div')?.appendChild(volgendBtn);
}

function toonCasusScherm(){
  toonCasus(0);
  show('s-casus');
}
