function docTab(naam){
  document.querySelectorAll('.doc-tab-panel').forEach(p=>p.style.display='none');
  document.querySelectorAll('.doc-tab').forEach(b=>b.classList.remove('active'));
  const panel = document.getElementById('doc-tab-'+naam);
  if(panel) panel.style.display='';
  const btn = document.getElementById('dtab-'+naam);
  if(btn) btn.classList.add('active');
  // Didactische interventies: dynamisch opbouwen
  if(naam==='interventies'){
    const p=document.getElementById('doc-tab-interventies');
    if(p){ p.innerHTML=''; bouwInterventiesDashboard(p); }
    return;
  }
  // Eigen vragen: toon opgeslagen lijst
  if(naam==='eigen-vragen'){
    eigenVragenToonLijst();
    return;
  }
  // Zorg dat kerndoelentabel gevuld is
  if(naam==='slo-domeinen'){
    const p=document.getElementById('doc-tab-slo-domeinen');
    if(p && !p.dataset.gevuld){
      p.innerHTML=genereerSLODomeinenTabel();
      p.dataset.gevuld='1';
    }
    return;
  }
  if(naam==='kerndoelen'){
    const tbody = document.getElementById('doc-table-body');
    if(tbody && !tbody.innerHTML.trim()){
      const rijen = Object.keys(DOC_KD).map((topic,i) => {
        const kd = DOC_KD[topic];
        const bg = i%2===0 ? '' : 'background:#f9fbff';
        return '<tr style="'+bg+'">'+
          '<td style="padding:.5rem .8rem;font-weight:600;border-bottom:1px solid #eee">' + DOC_LABELS[topic] + '</td>'+
          '<td style="padding:.5rem .8rem;color:#555;border-bottom:1px solid #eee;font-size:.8rem">' + (kd.bb||'вҖ”') + '</td>'+
          '<td style="padding:.5rem .8rem;color:#555;border-bottom:1px solid #eee;font-size:.8rem">' + (kd.tl||'вҖ”') + '</td>'+
          '<td style="padding:.5rem .8rem;color:#555;border-bottom:1px solid #eee;font-size:.8rem">' + (kd.vwo||'вҖ”') + '</td>'+
        '</tr>';
      }).join('');
      tbody.innerHTML = rijen;
    }
  }
}


// в”Җв”Җ Procentuele verandering widget в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function renderPctWidget(containerId, opties){
  const el = document.getElementById(containerId);
  if(!el) return;
  const opts = opties || {};
  const titel  = opts.titel  || 'Procentuele verandering berekenen';
  const oudVal = opts.oud    || '';
  const nieuwVal = opts.nieuw || '';
  const eenheid = opts.eenheid || '';

  const uid = containerId + '_pct';
  el.innerHTML = `
    <div class="pct-widget">
      <div class="pct-widget-titel">&#x1F9EE; ${titel}</div>
      <div class="pct-widget-grid">
        <div>
          <label for="${uid}_oud">Oude waarde${eenheid?' ('+eenheid+')':''}</label>
          <input id="${uid}_oud" type="number" value="${oudVal}" placeholder="bijv. 2000"
            oninput="berekenPct('${uid}')">
        </div>
        <div>
          <label for="${uid}_nieuw">Nieuwe waarde${eenheid?' ('+eenheid+')':''}</label>
          <input id="${uid}_nieuw" type="number" value="${nieuwVal}" placeholder="bijv. 2120"
            oninput="berekenPct('${uid}')">
        </div>
        <div>
          <label for="${uid}_dec">Decimalen</label>
          <input id="${uid}_dec" type="number" value="1" min="0" max="4" style="max-width:70px"
            oninput="berekenPct('${uid}')">
        </div>
      </div>
      <div id="${uid}_stappen" class="pct-stappen">
        <em style="color:#aaa">Vul een oude en nieuwe waarde in om de berekening te zien.</em>
      </div>
      <div id="${uid}_uitkomst" class="pct-uitkomst nul" style="display:none"></div>
      <div id="${uid}_bar_wrap" class="pct-bar-wrap" style="display:none">
        <div class="pct-bar-labels">
          <span>Oude waarde</span><span id="${uid}_bar_pctlabel">0%</span><span>Nieuwe waarde</span>
        </div>
        <div class="pct-bar-outer">
          <div class="pct-bar-mid" id="${uid}_bar_mid" style="left:50%"></div>
          <div class="pct-bar-fill nul" id="${uid}_bar_fill" style="width:50%;margin-left:0">
            <span class="pct-bar-val" id="${uid}_bar_val"></span>
          </div>
        </div>
      </div>
      <div class="pct-formule-hint">Formule: (nieuw &minus; oud) &divide; oud &times; 100%</div>
    </div>`;

  // Direct berekenen als waarden al meegegeven
  if(oudVal && nieuwVal) berekenPct(uid);
}

function berekenPct(uid){
  const oudEl   = document.getElementById(uid + '_oud');
  const nieuwEl = document.getElementById(uid + '_nieuw');
  const decEl   = document.getElementById(uid + '_dec');
  const stEl    = document.getElementById(uid + '_stappen');
  const utEl    = document.getElementById(uid + '_uitkomst');
  if(!oudEl || !nieuwEl || !stEl || !utEl) return;

  const oud  = parseFloat(oudEl.value);
  const nieuw= parseFloat(nieuwEl.value);
  const dec  = Math.max(0, Math.min(4, parseInt(decEl?.value) || 1));

  if(isNaN(oud) || isNaN(nieuw) || oud === 0){
    stEl.innerHTML = '<em style="color:#aaa">Vul geldige waarden in (oud mag niet 0 zijn).</em>';
    utEl.style.display = 'none';
    return;
  }

  const teller   = nieuw - oud;
  const uitkomst = (teller / oud) * 100;
  const pos      = uitkomst > 0;
  const nul      = uitkomst === 0;

  stEl.innerHTML =
    '<strong>Stap 1 &mdash; Bepaal het verschil (teller):</strong><br>' +
    '&nbsp;&nbsp;nieuw &minus; oud = ' +
    nieuw.toLocaleString('nl') + ' &minus; ' + oud.toLocaleString('nl') +
    ' = <code>' + teller.toLocaleString('nl') + '</code><br><br>' +
    '<strong>Stap 2 &mdash; Deel door de oude waarde:</strong><br>' +
    '&nbsp;&nbsp;<code>' + teller.toLocaleString('nl') + '</code> &divide; ' +
    oud.toLocaleString('nl') + ' = <code>' + (teller/oud).toFixed(dec+2) + '</code><br><br>' +
    '<strong>Stap 3 &mdash; Vermenigvuldig met 100%:</strong><br>' +
    '&nbsp;&nbsp;<code>' + (teller/oud).toFixed(dec+2) + '</code> &times; 100% = ' +
    '<strong>' + uitkomst.toFixed(dec) + '%</strong>';

  utEl.style.display = 'block';
  utEl.className = 'pct-uitkomst ' + (nul ? 'nul' : pos ? 'pos' : 'neg');
  utEl.innerHTML =
    (nul  ? '&mdash; Geen verandering (0,0%)' :
     pos  ? '&#x25B2; Stijging van <strong>+' + uitkomst.toFixed(dec) + '%</strong> &#x2705;' :
             '&#x25BC; Daling van <strong>' + uitkomst.toFixed(dec) + '%</strong> &#x26A0;&#xFE0F;');

  // в”Җв”Җ Visuele bar bijwerken в”Җв”Җ
  const barWrap = document.getElementById(uid + '_bar_wrap');
  const barFill = document.getElementById(uid + '_bar_fill');
  const barVal  = document.getElementById(uid + '_bar_val');
  const barMid  = document.getElementById(uid + '_bar_mid');
  const barPct  = document.getElementById(uid + '_bar_pctlabel');
  if(barWrap && barFill){
    barWrap.style.display = 'block';
    const clamp = Math.min(Math.abs(uitkomst), 100);
    const halfW = 50; // middelpunt in %
    if(nul){
      barFill.style.width = '2px';
      barFill.style.marginLeft = halfW + '%';
      barFill.className = 'pct-bar-fill nul';
    } else if(pos){
      barFill.style.marginLeft = halfW + '%';
      barFill.style.width = (clamp / 2) + '%';
      barFill.className = 'pct-bar-fill pos';
    } else {
      const w = (clamp / 2);
      barFill.style.marginLeft = (halfW - w) + '%';
      barFill.style.width = w + '%';
      barFill.className = 'pct-bar-fill neg';
    }
    if(barVal) barVal.textContent = (pos ? '+' : '') + uitkomst.toFixed(dec) + '%';
    if(barMid) barMid.style.left = halfW + '%';
    if(barPct) barPct.textContent = (pos ? '+' : '') + uitkomst.toFixed(dec) + '%';
  }
}


