// в•җв•җ EXAMEN LOGICA в•җв•җ
let exJaar = null;
let exVraagNr = 0;
let exAntwoorden = [];

function toonExamenKeuze(){
  const sub = document.getElementById('ex-sub');
  if(sub) sub.textContent = `Leerjaar 4 вҖ” ${NV} вҖ” Kies een examenjaar`;
  show('s-ex');
}

function startExamen(jaar){
  exJaar = jaar;
  exVraagNr = 0;
  const ex = EXAMENS[jaar];
  exAntwoorden = new Array(ex.vragen.length).fill(null);
  document.getElementById('exw-title').textContent = ex.titel;
  document.getElementById('exw-sub').textContent = `Economie В· vmbo ${NV} В· ${ex.vragen.length} vragen`;
  toonExamenVraag();
  show('s-exw');
}

function toonExamenVraag(){
  const ex = EXAMENS[exJaar];
  const q = ex.vragen[exVraagNr];
  const totaal = ex.vragen.length;

  document.getElementById('ex-voortgang').innerHTML =
    `Vraag ${exVraagNr+1} van ${totaal} &nbsp;|&nbsp; Beantwoord: ${exAntwoorden.filter(a=>a!==null).length}`;

  const gekozen = exAntwoorden[exVraagNr];
  const letters = ['A','B','C','D'];
  const opties = q.o.map((opt,i)=>`
    <div class="ex-opt ${gekozen===i?'ex-opt-sel':''}"
         role="radio"
         aria-checked="${gekozen===i?'true':'false'}"
         tabindex="${gekozen===i?'0':gekozen===null&&i===0?'0':'-1'}"
         data-optie="${i}"
         onclick="kiesExAntwoord(${i})"
         onkeydown="_exOptKey(event,${i})"
         aria-label="Optie ${letters[i]}: ${opt.replace(/"/g,'&quot;')}">
      <span class="ex-opt-letter" aria-hidden="true">${letters[i]}</span>
      <span>${opt}</span>
    </div>`).join('');

  document.getElementById('ex-vraag-wrap').innerHTML = `
    ${q.ctx||''}
    <div class="ex-vraag-nr">Vraag ${q.nr}</div>
    <div class="ex-vraag-tekst">${q.v}</div>
    <div class="ex-opties" role="radiogroup" aria-label="Kies jouw antwoord">${opties}</div>`;

  document.getElementById('ex-vorige').style.display = exVraagNr > 0 ? 'inline-block' : 'none';
  const isLaatste = exVraagNr === totaal - 1;
  document.getElementById('ex-volgende').style.display = isLaatste ? 'none' : 'inline-block';
  document.getElementById('ex-afronden').style.display = isLaatste ? 'inline-block' : 'none';
}

function kiesExAntwoord(i){
  exAntwoorden[exVraagNr] = i;
  toonExamenVraag();
  // Focus behouden op geselecteerde optie na herrender
  var opts = document.querySelectorAll('.ex-opties [role="radio"]');
  if(opts[i]) opts[i].focus();
}

// Keyboard navigatie voor examen-opties (pijltjestoetsen + Enter/Spatie)
function _exOptKey(e, i){
  var ex = EXAMENS[exJaar];
  var aantalOpties = ex.vragen[exVraagNr].o.length;
  if(e.key === 'ArrowDown' || e.key === 'ArrowRight'){
    e.preventDefault();
    var volgende = (i + 1) % aantalOpties;
    kiesExAntwoord(volgende);
  } else if(e.key === 'ArrowUp' || e.key === 'ArrowLeft'){
    e.preventDefault();
    var vorige = (i - 1 + aantalOpties) % aantalOpties;
    kiesExAntwoord(vorige);
  } else if(e.key === 'Enter' || e.key === ' '){
    e.preventDefault();
    kiesExAntwoord(i);
  }
}

function exVolgende(){
  const ex = EXAMENS[exJaar];
  if(exVraagNr < ex.vragen.length - 1){ exVraagNr++; toonExamenVraag(); }
}

function exVorige(){
  if(exVraagNr > 0){ exVraagNr--; toonExamenVraag(); }
}

function exAfronden(){
  const ex = EXAMENS[exJaar];
  const vragen = ex.vragen;
  let goed = 0;
  vragen.forEach((q,i)=>{ if(exAntwoorden[i]===q.a) goed++; });
  const pct = Math.round((goed/vragen.length)*100);
  const cijfer = Math.max(1, Math.min(10, Math.round(1 + (goed/vragen.length)*9)));

  const kleur = cijfer >= 6 ? '#1a6b3a' : '#b30000';
  document.getElementById('ex-score-wrap').innerHTML = `
    <div style="text-align:center;padding:1.8rem 1.5rem;background:#f9f9f9;border-radius:16px;margin-bottom:1.2rem">
      <div class="ex-score-ring" style="color:${kleur};margin:0 auto .9rem">${cijfer}</div>
      <div style="font-size:1.05rem;font-weight:700;color:#1a1a1a;margin-bottom:.5rem">
        ${goed} van de ${vragen.length} vragen goed
      </div>
      <div style="background:#e8e8e8;border-radius:20px;height:10px;max-width:220px;margin:0 auto .6rem;overflow:hidden">
        <div style="height:100%;width:${pct}%;background:${kleur};border-radius:20px;transition:width .8s ease"></div>
      </div>
      <div style="font-size:.88rem;color:#888;margin-bottom:.6rem">${pct}% goed</div>
      <div style="font-size:.95rem;font-weight:600;color:${kleur}">
        ${cijfer>=6?'вң… Geslaagd! Goed gedaan.':'вқҢ Onvoldoende. Bekijk de uitleg hieronder.'}
      </div>
    </div>`;

  const review = vragen.map((q,i)=>{
    const jouw = exAntwoorden[i];
    const gd = jouw === q.a;
    return `<div class="ex-review-item ${gd?'ex-goed':'ex-fout'}">
      <div class="ex-rev-header">
        <span>${gd?'вң…':'вқҢ'} Vraag ${q.nr}</span>
        <span>${gd?'Goed':'Fout вҖ” jij koos: '+(jouw!==null?['A','B','C','D'][jouw]:'вҖ”')+', goed: '+['A','B','C','D'][q.a]}</span>
      </div>
      <div class="ex-rev-vraag">${q.v}</div>
      ${!gd?`<div class="ex-rev-uitleg"><b>Uitleg:</b> ${q.u}</div>`:''}
    </div>`;
  }).join('');

  document.getElementById('ex-review').innerHTML = `<h3 style="margin:1.5rem 0 1rem">Vraag voor vraag:</h3>${review}`;
  show('s-exr');
}


