// в”Җв”Җ LEERTRAJECT в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
//  LEERTRAJECT вҖ” dynamisch, gebonden aan huidig LJ + NV
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

// в”Җв”Җ Stap-templates per oefenvorm в”Җв”Җ
// Elke stap wordt gegenereerd vanuit de TP-topics van het huidige niveau.
// Volgorde per onderwerp: th вҶ’ fc вҶ’ vr вҶ’ rk (indien beschikbaar) вҶ’ er1
// Daarna: rekenhulp, rekentrainer, formulekaart

const LT_MODUS_CFG = [
  { modus:'th',  emoji:'рҹ“ҡ', label:'Theorie',        sub:t=>`Lees de uitleg over ${t.toLowerCase()}` },
  { modus:'fc',  emoji:'рҹғҸ', label:'Flashcards',     sub:t=>`Oefen de begrippen van ${t.toLowerCase()} met flashcards` },
  { modus:'vr',  emoji:'вңҸпёҸ', label:'Oefenvragen',    sub:t=>`Beantwoord de meerkeuzevragen over ${t.toLowerCase()}` },
  { modus:'rk',  emoji:'рҹ”ў', label:'Rekensommen',    sub:t=>`Maak de rekensommen bij ${t.toLowerCase()}` },
  { modus:'er1', emoji:'рҹ”җ', label:'Escaperoom',     sub:t=>`Los de escaperoom op over ${t.toLowerCase()}` },
];

// Extra vaste stappen aan het einde van elk leertraject
const LT_EXTRA_STAPPEN = [
  { id:'lt-rekentrainer', emoji:'вҸұпёҸ', titel:'Rekentrainer',    sub:'Oefen de Big Five rekenvaardigheden',  special:'rekentrainer' },
  { id:'lt-rekenhulp',    emoji:'рҹҶҳ', titel:'Rekenhulp',       sub:'Bekijk stappenplannen bij rekenproblemen', special:'rekenhulp' },
];

// Niveau-label voor weergave
const LT_NIV_LABELS = {
  basis:'vmbo basis', kader:'vmbo kader', tl:'vmbo tl',
  'tl-havo':'tl / havo', 'havo-vwo':'havo / vwo'
};

// в”Җв”Җ Bouw leertraject voor huidig LJ+NV в”Җв”Җ
function ltBouwStappen(){
  if(!LJ || !NV) return [];
  const topics = (TP[LJ]||{})[NV] || [];
  const nivLabel = LT_NIV_LABELS[NV] || NV;
  const stappen = [];

  topics.forEach(topic => {
    const tNaam = topic.t;
    LT_MODUS_CFG.forEach(cfg => {
      // Sla rekensommen over als dit topic geen rekenstof heeft
      // (milieu, loopbaan hebben geen rk in het leerpad voor basis/kader)
      if(cfg.modus === 'rk' && ['milieu','loopbaan','schaarste'].includes(topic.id)) return;
      // Sla escaperoom over voor havo-vwo tenzij er1 bestaat
      if(cfg.modus === 'er1' && NV === 'havo-vwo') return;
      stappen.push({
        id: `${cfg.modus}-${topic.id}`,
        emoji: cfg.emoji,
        titel: `${cfg.label}: ${tNaam}`,
        sub: cfg.sub(tNaam),
        niv: nivLabel,
        ow: topic.id,
        modus: cfg.modus,
      });
    });
  });

  // Voeg vaste extra stappen toe
  LT_EXTRA_STAPPEN.forEach(s => stappen.push({...s, niv: nivLabel}));

  return stappen;
}

function ltGetVoortgang(){
  try{
    const raw = localStorage.getItem('lt_voortgang_v2');
    return raw ? JSON.parse(raw) : {};
  } catch(e){ return {}; }
}

function ltSlaVoortgangOp(stapId, gedaan){
  try{
    const v = ltGetVoortgang();
    v[stapId] = gedaan;
    localStorage.setItem('lt_voortgang_v2', JSON.stringify(v));
    renderLeertraject();
  } catch(e){ console.warn('localStorage niet beschikbaar'); }
}

function ltAllesWissen(){
  if(!confirm('Weet je zeker dat je de leertraject-voortgang wilt wissen?')) return;
  try{ localStorage.removeItem('lt_voortgang_v2'); } catch(e){}
  renderLeertraject();
}

function toonLeertraject(){
  // Als nog geen LJ/NV gekozen: stuur naar niveau-keuze
  if(!LJ || !NV){
    alert('Kies eerst je leerjaar en niveau, dan zie je jouw persoonlijke leertraject.');
    show('s-lj');
    return;
  }
  show('s-leertraject');
  renderLeertraject();
}

function renderLeertraject(){
  const container = document.getElementById('lt-stappen-container');
  if(!container) return;

  const stappen = ltBouwStappen();
  const v = ltGetVoortgang();
  const gedaanCount = stappen.filter(s => v[s.id]).length;
  const pct = stappen.length ? Math.round((gedaanCount / stappen.length) * 100) : 0;
  const nivLabel = (LT_NIV_LABELS[NV] || NV || '').toUpperCase();

  // Update header
  const pctEl = document.getElementById('lt-pct-getal');
  if(pctEl) pctEl.textContent = pct + '%';
  const txtEl = document.getElementById('lt-voortgang-tekst');
  if(txtEl){
    if(!LJ || !NV)
      txtEl.textContent = 'Kies je leerjaar en niveau voor een persoonlijk leerpad';
    else if(pct === 100)
      txtEl.textContent = `рҹҺү Alles afgerond voor ${nivLabel}! Goed bezig!`;
    else if(pct > 60)
      txtEl.textContent = `${gedaanCount} van ${stappen.length} stappen klaar вҖ” bijna!`;
    else if(pct > 0)
      txtEl.textContent = `${gedaanCount} van ${stappen.length} stappen klaar вҖ” ga zo door!`;
    else
      txtEl.textContent = `${stappen.length} stappen voor ${nivLabel} вҖ” begin bij stap 1`;
  }

  // Update niveau-label in de header
  const subEl = document.querySelector('#s-leertraject .ssub');
  if(subEl && LJ && NV)
    subEl.textContent = `Leerjaar ${LJ} В· ${nivLabel} вҖ” doorloop de stappen van theorie naar oefening`;

  if(!stappen.length){
    container.innerHTML = '<p style="color:var(--muted);text-align:center;padding:2rem">Kies een leerjaar en niveau om je leertraject te zien.</p>';
    return;
  }

  // Groepeer stappen per onderwerp
  const groepen = {};
  const volgorde = [];
  stappen.forEach(stap => {
    const key = stap.ow || stap.id;
    if(!groepen[key]){ groepen[key] = []; volgorde.push(key); }
    groepen[key].push(stap);
  });

  let html = '';
  let stapNr = 0;

  volgorde.forEach(key => {
    const stappenInGroep = groepen[key];
    const eersteStap = stappenInGroep[0];
    const groepGedaan = stappenInGroep.filter(s => v[s.id]).length;
    const groepTotaal = stappenInGroep.length;
    const groepPct = Math.round(groepGedaan / groepTotaal * 100);
    const groepKleur = groepPct === 100 ? '#27ae60' : groepPct > 0 ? '#f59e0b' : '#dde';

    // Groepsheader (onderwerpnaam)
    const groepLabel = eersteStap.special
      ? (eersteStap.emoji + ' ' + eersteStap.titel)
      : `рҹ“– ${eersteStap.titel.split(': ')[1] || key}`;

    html += `<div class="lt-groep" style="margin-bottom:1.2rem">
      <div style="display:flex;align-items:center;gap:.6rem;margin-bottom:.5rem">
        <div style="font-family:'Lexend',sans-serif;font-weight:800;font-size:.88rem;color:var(--fg)">${groepLabel}</div>
        <div style="margin-left:auto;font-size:.75rem;color:${groepKleur};font-weight:700">${groepGedaan}/${groepTotaal}</div>
        <div style="width:60px;height:6px;background:#eee;border-radius:3px;overflow:hidden">
          <div style="width:${groepPct}%;height:100%;background:${groepKleur};border-radius:3px;transition:width .4s"></div>
        </div>
      </div>`;

    stappenInGroep.forEach((stap, gi) => {
      stapNr++;
      const isGedaan = !!v[stap.id];
      const isSpecial = !!stap.special;

      // Bepaal of stap bereikbaar is (vorige stap in zelfde groep afgerond, of eerste)
      const vorigeGedaan = gi === 0 || !!v[stappenInGroep[gi-1].id];
      const bereikbaar = isGedaan || vorigeGedaan;

      const bgKleur = isGedaan ? '#f0fdf4' : bereikbaar ? 'var(--bg2)' : 'var(--bg2)';
      const borderKleur = isGedaan ? '#27ae60' : bereikbaar ? 'var(--border)' : '#eee';
      const opacity = bereikbaar ? '1' : '0.55';

      html += `<div class="lt-stap" style="
          display:flex;align-items:center;gap:.7rem;
          background:${bgKleur};border:1.5px solid ${borderKleur};
          border-radius:10px;padding:.7rem .9rem;margin-bottom:.4rem;
          cursor:${bereikbaar ? 'pointer' : 'default'};
          opacity:${opacity};
          transition:box-shadow .15s,transform .15s"
        onclick="${bereikbaar ? `ltStapKlik('${stap.id}')` : ''}"
        onmouseover="${bereikbaar ? "this.style.boxShadow='0 3px 12px rgba(0,0,0,.1)';this.style.transform='translateY(-1px)'" : ''}"
        onmouseout="${bereikbaar ? "this.style.boxShadow='';this.style.transform=''" : ''}">

        <div style="
          width:28px;height:28px;border-radius:50%;flex-shrink:0;
          display:flex;align-items:center;justify-content:center;
          background:${isGedaan ? '#27ae60' : bereikbaar ? 'var(--white)' : '#f0f0f0'};
          border:2px solid ${isGedaan ? '#27ae60' : bereikbaar ? '#ccc' : '#eee'};
          font-size:${isGedaan ? '.85rem' : '.75rem'};
          font-weight:700;color:${isGedaan ? '#fff' : '#aaa'}">
          ${isGedaan ? 'вң“' : stapNr}
        </div>

        <div style="flex:1;min-width:0">
          <div style="font-size:.87rem;font-weight:700;color:var(--fg);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">
            ${stap.emoji} ${stap.titel}
          </div>
          <div style="font-size:.76rem;color:var(--muted);margin-top:.1rem">${stap.sub}</div>
        </div>

        <button
          onclick="event.stopPropagation(); ltSlaVoortgangOp('${stap.id}', ${!isGedaan})"
          style="
            padding:.3rem .65rem;border-radius:8px;font-size:.72rem;font-weight:700;
            font-family:'Lexend',sans-serif;cursor:pointer;flex-shrink:0;white-space:nowrap;
            border:1.5px solid ${isGedaan ? '#27ae60' : '#dde'};
            background:${isGedaan ? '#27ae60' : 'transparent'};
            color:${isGedaan ? '#fff' : '#aaa'}"
          title="${isGedaan ? 'Klik om te ontkoppelen' : 'Markeer als gedaan'}">
          ${isGedaan ? 'вң“ Klaar' : 'Vink af'}
        </button>
      </div>`;
    });

    html += '</div>'; // einde lt-groep
  });

  container.innerHTML = html;
}

// в”Җв”Җ Navigatie vanuit leertraject-stap в”Җв”Җ
function ltStapKlik(stapId){
  const stappen = ltBouwStappen();
  const stap = stappen.find(s => s.id === stapId);
  if(!stap) return;

  // Speciale bestemmingen
  if(stap.special === 'rekentrainer'){ show('s-rekentrainer'); return; }
  if(stap.special === 'rekenhulp')  { go('rh'); return; }
  if(stap.special === 'ehbo')       { if(typeof toonEHBO === 'function') toonEHBO(); return; }
  if(stap.special === 'ex')         { go('ex'); return; }

  // Onderwerp + modus navigatie вҖ” gebruik huidig LJ en NV (niet overschrijven)
  if(stap.ow && stap.modus){
    OW = stap.ow;
    const mdTitle = document.getElementById('md-title');
    if(mdTitle) mdTitle.textContent = stap.titel.split(': ')[1] || stap.ow;
    // Markeer automatisch als gedaan na klik
    const v = ltGetVoortgang();
    if(!v[stap.id]){
      // Sla op na 3 seconden (geeft leerling tijd om daadwerkelijk te starten)
      setTimeout(() => {
        ltSlaVoortgangOp(stap.id, true);
      }, 3000);
    }
    go(stap.modus);
  }
}

// в”Җв”Җ EXPORTEER RESULTATEN в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// Score tracking: quiz results worden bijgehouden in ltScores
// в”Җв”Җ PERSISTENTE VOORTGANG (localStorage) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
var VLA_SCORES_KEY = 'vla_quiz_scores_v2';
var VLA_FC_KEY = 'vla_flashcard_done';
var VLA_CASUS_KEY = 'vla_casus_done';

function laadPersistenteScores(){
  try {
    var opgeslagen = JSON.parse(localStorage.getItem(VLA_SCORES_KEY)||'[]');
    // Maximaal 200 recente pogingen bewaren
    window.ltScores = Array.isArray(opgeslagen) ? opgeslagen.slice(-200) : [];
  } catch(e){ window.ltScores = []; }
}

function slaScoreOp(module, goed, totaal, naam){
  try {
    var entry = {
      id: module,
      module: naam||module,
      goed: goed,
      totaal: totaal,
      pct: totaal>0?Math.round((goed/totaal)*100):0,
      tijdstip: new Date().toLocaleTimeString('nl-NL',{hour:'2-digit',minute:'2-digit'}),
      datum: new Date().toLocaleDateString('nl-NL')
    };
    window.ltScores.push(entry);
    localStorage.setItem(VLA_SCORES_KEY, JSON.stringify(window.ltScores.slice(-200)));
  } catch(e){}
}

// Laad bij start
laadPersistenteScores();
window.ltScores = window.ltScores || [];

function registreerScore(module, goed, totaal, naam){
  slaScoreOp(module, goed, totaal, naam);
}

// в”Җв”Җ EIGEN VRAGEN (docent) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
var EQ_KEY = 'vla_eigen_vragen_v1';

function eigenVragenLaad(){
  try { return JSON.parse(localStorage.getItem(EQ_KEY)||'[]'); } catch(e){ return []; }
}
function eigenVragenSla(arr){
  try { localStorage.setItem(EQ_KEY, JSON.stringify(arr)); } catch(e){}
}

function eigenVraagOpslaan(){
  var type = document.getElementById('eq-type').value;
  var vraag = (document.getElementById('eq-vraag').value||'').trim();
  var uitleg = (document.getElementById('eq-uitleg').value||'').trim();
  var niveau = parseInt(document.getElementById('eq-niveau').value||'2');
  var foutEl = document.getElementById('eq-fout');
  foutEl.style.display = 'none';

  if(!vraag){ foutEl.textContent = 'Vul een vraag in.'; foutEl.style.display = ''; return; }

  var entry = { id: 'eq_'+Date.now(), typ: type, q: vraag, u: uitleg, d: niveau };

  if(type === 'mc'){
    var opts = ['eq-o0','eq-o1','eq-o2','eq-o3'].map(id => (document.getElementById(id).value||'').trim());
    if(opts.filter(Boolean).length < 2){ foutEl.textContent = 'Vul minstens 2 antwoordopties in.'; foutEl.style.display = ''; return; }
    var correctRadio = document.querySelector('input[name="eq-correct"]:checked');
    if(!correctRadio){ foutEl.textContent = 'Selecteer het juiste antwoord.'; foutEl.style.display = ''; return; }
    entry.o = opts;
    entry.c = parseInt(correctRadio.value);
  }

  var arr = eigenVragenLaad();
  arr.push(entry);
  eigenVragenSla(arr);
  eigenVraagFormLeeg();
  eigenVragenToonLijst();
  toonMelding('Vraag opgeslagen вң“');
}

function eigenVraagFormLeeg(){
  ['eq-vraag','eq-uitleg','eq-o0','eq-o1','eq-o2','eq-o3'].forEach(id => {
    var el = document.getElementById(id);
    if(el) el.value = '';
  });
  var r = document.querySelector('input[name="eq-correct"]:checked');
  if(r) r.checked = false;
  var fEl = document.getElementById('eq-fout');
  if(fEl) fEl.style.display = 'none';
}

function eigenVraagVerwijder(id){
  var arr = eigenVragenLaad().filter(q => q.id !== id);
  eigenVragenSla(arr);
  eigenVragenToonLijst();
}

function eigenVragenToonLijst(){
  var arr = eigenVragenLaad();
  var lijstEl = document.getElementById('eq-lijst');
  var aantalEl = document.getElementById('eq-aantal');
  if(!lijstEl) return;
  if(aantalEl) aantalEl.textContent = arr.length;
  if(!arr.length){
    lijstEl.innerHTML = '<div style="font-size:.82rem;color:#bbb;padding:.4rem 0">Nog geen vragen opgeslagen.</div>';
    return;
  }
  lijstEl.innerHTML = arr.map(q =>
    '<div style="background:#f8faff;border-radius:10px;padding:.65rem .9rem;display:flex;justify-content:space-between;align-items:flex-start;gap:.5rem">'
    +'<div style="flex:1"><div style="font-size:.84rem;font-weight:600">'+ddEsc(q.q.substring(0,80))+(q.q.length>80?'вҖҰ':'')+'</div>'
    +'<div style="font-size:.74rem;color:#aaa;margin-top:.15rem">'+(q.typ==='mc'?'Meerkeuze':'Open vraag')+' В· вӯҗ'.repeat(q.d||2)+'</div></div>'
    +'<button onclick="eigenVraagVerwijder(\''+q.id+'\')" style="background:none;border:none;color:#e74c3c;cursor:pointer;font-size:.85rem;padding:0" title="Verwijder">рҹ—‘пёҸ</button>'
    +'</div>'
  ).join('');
}

// Koppel eigen vragen aan getData() zodat ze in quiz verschijnen
var _origGetData = null;
function koppelEigenVragen(){
  if(_origGetData) return; // al gekoppeld
  _origGetData = window.getData || null;
  if(!_origGetData) return;
  window.getData = function(){
    var data = _origGetData.apply(this, arguments);
    var eigen = eigenVragenLaad();
    if(eigen.length && data && data.vr){
      data = Object.assign({}, data, { vr: [...data.vr, ...eigen] });
    }
    return data;
  };
}
setTimeout(koppelEigenVragen, 500);

function bouwInterventiesDashboard(container){
  // Lees bestaande analytics uit localStorage
  var scores = window.ltScores || [];
  var da = {};
  try{ da = JSON.parse(localStorage.getItem('docent_analytics')||'{}'); }catch(e){}
  var fc = da.foutenCategorie || {};
  var crD = da.causaal || {};

  // SLO-eindterm-mapping voor interventies
  var INTERVENTIE_MAP = {
    'markt':    { term:'EC/K/3 вҖ“ Vraag & aanbod', kleur:'#1a5a8a', tip:'Veel leerlingen verwarren "verschuiving van de lijn" met "beweging langs de lijn". Gebruik de Markt Simulator (nieuw!) om dit visueel te oefenen.', actie:'show("s-sim");simUpdate()' },
    'overheid': { term:'EC/K/6 вҖ“ Overheidsbeleid', kleur:'#2e7d32', tip:'Fiscaal vs. monetair beleid wordt regelmatig verwisseld. Laat leerlingen ketens redeneren: welke instelling doet wat, via welk instrument?', actie:'show("s-ai")' },
    'arbeid':   { term:'EC/K/5A вҖ“ Arbeid', kleur:'#7b1fa2', tip:'Onderscheid structurele vs. conjuncturele werkloosheid geeft veel fouten. Casus met scenario aanbevolen.', actie:'show("s-casus")' },
    'buitenland':{ term:'EC/K/7 вҖ“ Internationaal', kleur:'#e65100', tip:'Wisselkoersredenering (sterkere euro вҶ’ duurdere export) is het vaakst fout op CE. Gebruik de AI Redeneer-Trainer.', actie:'show("s-ai")' },
    'geld':     { term:'EC/V/1 вҖ“ Geld & inflatie', kleur:'#c62828', tip:'BBP nominaal vs. reГ«el en koopkrachtberekeningen vragen extra oefening bij TL/HAVO.', actie:'show("s-rk")' },
    'bedrijf':  { term:'EC/K/5B вҖ“ Bedrijf', kleur:'#00695c', tip:'Break-evenberekeningen worden veelal goed gemaakt; toegevoegde waarde keten vaker fout. Toets met rekenvragen.', actie:'show("s-rk2")' }
  };

  var html = '<div style="background:#fff;border-radius:14px;box-shadow:0 2px 12px rgba(0,0,0,.07);overflow:hidden;margin-bottom:1.2rem">'
    +'<div style="background:linear-gradient(135deg,#0d47a1,#1565c0);color:#fff;padding:1rem 1.2rem;font-family:\'Lexend\',sans-serif;font-weight:800;font-size:.95rem">рҹҺҜ Didactische Interventie-Suggesties</div>'
    +'<div style="padding:1rem 1.2rem;font-size:.83rem;color:#555;border-bottom:1px solid #eee">Op basis van de oefendata van leerlingen worden hieronder gerichte interventies voorgesteld per SLO-eindterm. Klik op de actieknop om direct naar het relevante oefenonderdeel te gaan.</div>'
    +'</div>';

  // Per onderwerp een kaart
  var owKeys = Object.keys(INTERVENTIE_MAP);
  html += '<div style="display:grid;gap:.9rem;margin-bottom:1.2rem">';
  owKeys.forEach(function(ow){
    var info = INTERVENTIE_MAP[ow];
    // Zoek quizscore voor dit onderwerp
    var owScore = scores.find(function(s){ return s.id && s.id.indexOf(ow) > -1; });
    var pct = owScore && owScore.totaal > 0 ? Math.round((owScore.goed/owScore.totaal)*100) : null;
    var statusKleur = pct === null ? '#aaa' : pct >= 70 ? '#27ae60' : pct >= 40 ? '#e67e22' : '#c0392b';
    var statusTxt = pct === null ? 'вҖ“ Nog niet geoefend' : pct+'% correct';
    html += '<div style="background:#fff;border-radius:12px;box-shadow:0 1px 8px rgba(0,0,0,.06);overflow:hidden;border-left:5px solid '+info.kleur+'">';
    html += '<div style="padding:.8rem 1rem;display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:.5rem">';
    html += '<div><div style="font-weight:800;font-family:\'Lexend\',sans-serif;font-size:.88rem;color:'+info.kleur+'">'+ddEsc(info.term)+'</div>';
    html += '<div style="font-size:.78rem;color:'+statusKleur+';font-weight:700;margin-top:.2rem">'+statusTxt+'</div></div>';
    html += '<button onclick="'+info.actie+'" style="background:'+info.kleur+';color:#fff;border:none;border-radius:20px;padding:.4rem 1rem;font-size:.78rem;font-weight:700;font-family:\'Lexend\',sans-serif;cursor:pointer">вҶ’ Oefenen</button>';
    html += '</div>';
    html += '<div style="padding:.6rem 1rem .9rem;font-size:.83rem;color:#444;background:#fafbff;border-top:1px solid #f0f0f0">рҹ’Ў '+ddEsc(info.tip)+'</div>';
    html += '</div>';
  });
  html += '</div>';

  // Klasbrede foutenstatus
  var fcArr = Object.values(fc).sort(function(a,b){ return b.fouten - a.fouten; });
  if(fcArr.length){
    html += '<div style="background:#fff;border-radius:12px;box-shadow:0 1px 8px rgba(0,0,0,.06);padding:1rem 1.2rem;margin-bottom:1rem">';
    html += '<div style="font-weight:800;font-family:\'Lexend\',sans-serif;font-size:.88rem;margin-bottom:.7rem;color:#1a2e4a">вҡ пёҸ Vaakst gemaakte fouten (klasbreed)</div>';
    html += '<table style="width:100%;border-collapse:collapse;font-size:.83rem"><thead><tr style="background:#f8f9fa"><th style="padding:.5rem .7rem;text-align:left;font-size:.75rem;color:#555">Categorie</th><th style="text-align:center;padding:.5rem .7rem;font-size:.75rem;color:#555">Fouten</th><th style="text-align:left;padding:.5rem .7rem;font-size:.75rem;color:#555">Aanbevolen actie</th></tr></thead><tbody>';
    fcArr.slice(0,6).forEach(function(f){
      var kleur = f.fouten >= 10 ? '#c0392b' : f.fouten >= 5 ? '#e67e22' : '#27ae60';
      var actie = f.fouten >= 5 ? 'Klassikale herhaling aanbevolen' : 'Individueel oefenen';
      html += '<tr><td style="padding:.45rem .7rem">'+ddEsc(f.naam)+'</td><td style="padding:.45rem .7rem;text-align:center;font-weight:700;color:'+kleur+'">'+f.fouten+'</td><td style="padding:.45rem .7rem;font-size:.78rem;color:#666">'+actie+'</td></tr>';
    });
    html += '</tbody></table></div>';
  }

  // AI Trainer resultaten
  var crArr = Object.values(crD).sort(function(a,b){ return (a.successen/Math.max(a.totaal,1)) - (b.successen/Math.max(b.totaal,1)); });
  if(crArr.length){
    html += '<div style="background:#fff;border-radius:12px;box-shadow:0 1px 8px rgba(0,0,0,.06);padding:1rem 1.2rem">';
    html += '<div style="font-weight:800;font-family:\'Lexend\',sans-serif;font-size:.88rem;margin-bottom:.7rem;color:#1a2e4a">рҹӨ– AI Redeneer-Trainer вҖ” zwakste domeinen</div>';
    crArr.slice(0,4).forEach(function(cr){
      var pct2 = cr.totaal > 0 ? Math.round((cr.successen/cr.totaal)*100) : 0;
      var kleur2 = pct2 >= 70 ? '#27ae60' : pct2 >= 40 ? '#e67e22' : '#c0392b';
      html += '<div style="display:flex;justify-content:space-between;align-items:center;padding:.4rem 0;border-bottom:1px solid #f5f5f5;font-size:.83rem">';
      html += '<span>'+ddEsc(cr.naam)+'</span>';
      html += '<span style="font-weight:700;color:'+kleur2+'">'+pct2+'% ('+cr.totaal+' poging'+(cr.totaal===1?'':'en')+')</span>';
      html += '</div>';
    });
    html += '</div>';
  }

  if(!fcArr.length && !crArr.length && scores.length === 0){
    html += '<div style="text-align:center;padding:2rem;color:var(--muted);font-size:.88rem">рҹ“ӯ Nog geen oefendata beschikbaar. Leerlingen moeten eerst oefenen voor interventie-suggesties.</div>';
  }

  container.innerHTML = html;
}

