// BEGRIPPEN TOOLTIP SYSTEEM
// Bouwt een lookup-tabel uit alle beg-arrays in C{}
// en wrapet <strong> termen in theorie-tekst met tooltip
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
(function(){
  // Bouw centrale lookup: term (lowercase) вҶ’ definitie
  const BL = {};
  if(typeof C !== 'undefined'){
    Object.values(C).forEach(topic => {
      if(topic && topic.beg){
        topic.beg.forEach(b => { if(b.t && b.d) BL[b.t.toLowerCase()] = {term:b.t, def:b.d}; });
      }
    });
  }
  window._BEGRIP_LOOKUP = BL;

  // Wikkel bekende termen in de theorie-blokken
  function wrapBegrippen(container){
    if(!container || !Object.keys(BL).length) return;
    // Doorloop alle tekst-elementen in theorie
    container.querySelectorAll('p,li,h3,h4').forEach(el => {
      // Skip als al gewrapped
      if(el.querySelector('.begrip')) return;
      let html2 = el.innerHTML;
      Object.values(BL).forEach(({term, def}) => {
        // Alleen termen van 4+ tekens omwikkelen, hoofdlettergevoelig voor nette output
        if(term.length < 4) return;
        const escaped = term.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
        const rx = new RegExp('(<strong[^>]*>)?' + escaped + '(</strong>)?', 'g');
        html2 = html2.replace(rx, (match, pre, post) => {
          // Alleen eerste voorkomen als al een .begrip-button erin zit: skip
          if(match.includes('begrip')) return match;
          const inner = match.replace(/<\/?(strong)[^>]*>/gi,'');
          return '<button class="begrip" tabindex="0" aria-label="' + term + ': ' + def.replace(/"/g,"'") + '">'
            + '<strong>' + inner + '</strong>'
            + '<span class="bg-tt">' + def + '</span>'
            + '</button>';
        });
      });
      el.innerHTML = html2;
    });
  }

  // Roep aan telkens als theorie geladen wordt
  window._wrapBegrippen = wrapBegrippen;

  // Observer: reageer op nieuwe theorie-content
  const obs = new MutationObserver(muts => {
    muts.forEach(m => m.addedNodes.forEach(n => {
      if(n.nodeType === 1){
        const c = n.classList && n.classList.contains('th-blok') ? n.parentElement : n;
        if(c && c.id === 'th-content') wrapBegrippen(c);
        else if(n.classList && n.classList.contains('th-blok')) wrapBegrippen(n.closest('#th-content'));
      }
    }));
  });
  document.addEventListener('DOMContentLoaded', () => {
    const thContent = document.getElementById('th-content');
    if(thContent) obs.observe(thContent, {childList:true, subtree:false});
  });
})();

