// в•җв•җ FOUTE VRAGEN SYSTEEM в•җв•җ
function getFouteVragen(){
  try{return JSON.parse(localStorage.getItem('fouteVragen')||'[]');}catch(e){return [];}
}
function slaFoutVraagOp(v){
  const fv=getFouteVragen();
  // Verwijder dubbelen op basis van vraag-tekst
  const bestaatAl=fv.some(x=>x.q===v.q);
  if(!bestaatAl){fv.push(v);if(fv.length>100)fv.shift();}
  localStorage.setItem('fouteVragen',JSON.stringify(fv));
}
function verwijderFoutVraag(vraagTekst){
  const fv=getFouteVragen().filter(x=>x.q!==vraagTekst);
  localStorage.setItem('fouteVragen',JSON.stringify(fv));
}
function updateZwakkePuntenKnop(){
  const fv=getFouteVragen();
  const wrap=document.getElementById('zwakke-punten-wrap');
  const badge=document.getElementById('zwakke-punten-badge');
  if(!wrap) return;
  if(fv.length>0){
    wrap.style.display='block';
    if(badge) badge.textContent=fv.length;
  } else {
    wrap.style.display='none';
  }
}

// Start een mini-quiz met alleen de foute vragen
let _zwakkePool=[];
let _zwakkeI=0;
let _zwakkeSc=0;
function startZwakkePuntenQuiz(){
  const fv=getFouteVragen();
  if(!fv.length) return;
  _zwakkePool=[...fv].sort(()=>Math.random()-.5);
  _zwakkeI=0;
  _zwakkeSc=0;
  toonZwakkeVraag();
}
function toonZwakkeVraag(){
  const el=document.getElementById('vr-c');
  const nxt=document.getElementById('vr-nxt');
  if(!el) {
    // Niet op quiz-scherm: navigeer eerst
    const sc=document.getElementById('s-vr');
    if(sc){
      document.querySelectorAll('.screen').forEach(s=>s.classList.remove('active'));
      sc.classList.add('active');
    }
  }
  if(_zwakkeI>=_zwakkePool.length){
    // Klaar
    const el2=document.getElementById('vr-c');
    if(el2) el2.innerHTML=`<div class="sbox">
      <div class="big">${_zwakkeSc}/${_zwakkePool.length}</div>
      <p>${_zwakkeSc===_zwakkePool.length?'рҹҺү Perfect! Alle zwakke punten beheerst!':'Blijf oefenen вҖ” je komt er!'}</p>
      <div class="na-oefening-btns">
        <button class="btn" onclick="startZwakkePuntenQuiz()">рҹ”„ Opnieuw</button>
        <button class="btn sec" onclick="goHome()">вҶҗ Terug naar home</button>
      </div>
    </div>`;
    if(nxt) nxt.style.display='none';
    markeerGedaan&&markeerGedaan('vr');
    return;
  }
  const v=_zwakkePool[_zwakkeI];
  if(el) el.innerHTML=`<div class="vbox">
    <div class="vnr">Zwak punt ${_zwakkeI+1} van ${_zwakkePool.length} <span class="vr-niv niv1" style="background:#fde8d8;color:#c0522a">рҹҺҜ Herhaling</span></div>
    <div class="vtxt">${v.q}</div>
    <div class="aops">${v.o.map((o,i)=>`<button class="abtn" onclick="antwoordZwak(${i})">${o}</button>`).join('')}</div>
    <div class="fb" id="vr-fb"></div>
  </div>`;
  const pb=document.getElementById('vr-pb');
  if(pb) pb.style.width=`${_zwakkeI/_zwakkePool.length*100}%`;
  if(nxt) nxt.style.display='none';
  const sc2=document.getElementById('s-vr');
  if(sc2 && !sc2.classList.contains('active')){
    document.querySelectorAll('.screen').forEach(s=>s.classList.remove('active'));
    sc2.classList.add('active');
  }
}
function antwoordZwak(i){
  const v=_zwakkePool[_zwakkeI]; if(!v) return;
  document.querySelectorAll('.abtn').forEach((b,idx)=>{
    b.disabled=true;
    if(idx===v.c) b.classList.add('ok');
    else if(idx===i) b.classList.add('no');
  });
  const goed=i===v.c;
  const fb=document.getElementById('vr-fb');
  if(goed){
    _zwakkeSc++;
    fb.className='fb goed show';
    fb.textContent=`вң“ Goed! ${v.u}`;
    verwijderFoutVraag(v.q);
  } else {
    fb.className='fb fout show';
    fb.textContent=`вң— Nog niet. ${v.u}`;
  }
  const nxt=document.getElementById('vr-nxt');
  if(nxt){nxt.style.display='';nxt.onclick=()=>{_zwakkeI++;toonZwakkeVraag();}}
}

// в•җв•җ SMART LEVEL ADVIES в•җв•җ
// Bijhouden: per niveau 100%-scores achter elkaar
let _basisStreakCount=0;
function checkSmartLevel(score,totaal,niveau){
  if(!niveau) return;
  const niveauStr=(niveau+'').toLowerCase();
  const isBasis=(niveauStr.includes('basis')||niveauStr.includes('kader')||niveauStr.includes('1'));
  if(!isBasis||totaal<3) return;
  if(score===totaal){
    _basisStreakCount++;
    if(_basisStreakCount>=3){
      setTimeout(()=>{
        const toast=document.getElementById('smart-level-toast');
        if(toast){toast.style.display='block';}
        _basisStreakCount=0;
      },800);
    }
  } else {
    _basisStreakCount=0;
  }
}

