// -- Samengestelde rente --
function berekenRente(){
  var hs=parseFloat(document.getElementById('rente-hs').value)||1000;
  var pct=parseFloat(document.getElementById('rente-pct').value)||4;
  var n=parseInt(document.getElementById('rente-jaar').value)||10;
  var type=document.getElementById('rente-type').value;
  var r=pct/100;
  var eind=type==='samen'?hs*Math.pow(1+r,n):hs*(1+r*n);
  var eindSamen=hs*Math.pow(1+r,n);
  var eindEnk=hs*(1+r*n);
  var totRente=eind-hs;
  var voordeel=eindSamen-eindEnk;
  function fmt(v){return v.toLocaleString('nl-NL',{minimumFractionDigits:2,maximumFractionDigits:2});}
  var e1=document.getElementById('r-rente-eind');
  var e2=document.getElementById('r-rente-totaal');
  var e3=document.getElementById('r-rente-enkelvoudig');
  var e4=document.getElementById('r-rente-voordeel');
  if(e1) e1.textContent='\u20ac'+fmt(eind);
  if(e2) e2.textContent='\u20ac'+fmt(totRente);
  if(e3) e3.textContent='\u20ac'+fmt(eindEnk);
  if(e4){e4.textContent=(voordeel>=0?'+':'')+'\u20ac'+fmt(voordeel);e4.style.color=voordeel>0?'#1a7a4a':'#b30000';}
  var wrap=document.getElementById('rente-grafiek');
  if(!wrap||!wrap.offsetWidth) return;
  var punten=[];
  for(var i=0;i<=n;i++) punten.push({samen:hs*Math.pow(1+r,i),enk:hs*(1+r*i)});
  var maxVal=Math.max(punten[n].samen,punten[n].enk,1);
  var w=wrap.offsetWidth||280;
  var h=120;
  var bars='';
  var stap=Math.max(1,Math.floor(n/12));
  for(var j=0;j<=n;j+=stap){
    var x=Math.round((j/n)*(w-30))+15;
    var hS=Math.round((punten[j].samen/maxVal)*(h-25))+10;
    var hE=Math.round((punten[j].enk/maxVal)*(h-25))+10;
    bars+='<line x1="'+x+'" y1="'+(h-hE)+'" x2="'+x+'" y2="'+h+'" stroke="#cbd5e1" stroke-width="4" stroke-linecap="round"/>';
    bars+='<line x1="'+x+'" y1="'+(h-hS)+'" x2="'+x+'" y2="'+h+'" stroke="#1a7a4a" stroke-width="4" stroke-linecap="round" opacity="0.8"/>';
  }
  wrap.innerHTML='<svg width="100%" height="'+h+'" viewBox="0 0 '+w+' '+h+'" preserveAspectRatio="none">'+bars+'<rect x="4" y="2" width="90" height="26" rx="4" fill="rgba(255,255,255,.85)"/><text x="8" y="12" fill="#1a7a4a" font-size="9" font-family="sans-serif" font-weight="bold">Samengesteld</text><text x="8" y="24" fill="#94a3b8" font-size="9" font-family="sans-serif">Enkelvoudig</text></svg>';
}

