// в”Җв”Җ BTW & Marge в”Җв”Җ
function berekenBTW(){
  const ink = parseFloat(document.getElementById('btw-ink').value)||0;
  const tarief = parseFloat(document.getElementById('btw-tarief').value)||0;
  const marge = parseFloat(document.getElementById('btw-marge').value)||0;
  const opslag = ink*(marge/100);
  const vkpEx = ink+opslag;
  const btwBed = vkpEx*(tarief/100);
  const vkpIn = vkpEx+btwBed;
  const fmt = v => '\u20ac\u00a0'+v.toFixed(2).replace('.',',');
  document.getElementById('r-ink').textContent = fmt(ink);
  document.getElementById('r-opslag').textContent = fmt(opslag);
  document.getElementById('r-vkp-ex').textContent = fmt(vkpEx);
  document.getElementById('r-btwbed').textContent = '\u20ac\u00a0'+btwBed.toFixed(2).replace('.',',')+' ('+tarief+'%)';
  document.getElementById('r-vkp-in').textContent = fmt(vkpIn);
}

// в”Җв”Җ Marktgrafiek в”Җв”Җ
function updateMarkt(val){
  val = parseInt(val);
  const pct = val;
  document.getElementById('markt-label').textContent = (pct>0?'+':'')+pct+'%';
  // Schuif vraaglijn: shift x-coordinaten naar rechts proportioneel
  const shift = pct * 0.8; // max 80px
  const vn = document.getElementById('svg-vn');
  const vnLabel = document.getElementById('svg-vn-label');
  const epOld = document.getElementById('svg-ep-old');
  const epNew = document.getElementById('svg-ep-new');
  const badge = document.getElementById('svg-badge-bg');
  const badgeTxt = document.getElementById('svg-badge-txt');
  const hline = document.getElementById('svg-ep-hline');
  const vline = document.getElementById('svg-ep-vline');
  const plabel = document.getElementById('svg-ep-plabel');
  const qlabel = document.getElementById('svg-ep-qlabel');
  const result = document.getElementById('markt-result');
  const rTxt = document.getElementById('r-markt-txt');
  const rUitleg = document.getElementById('r-markt-uitleg');

  if(pct===0){
    // Reset
    vn.setAttribute('opacity','0'); vnLabel.setAttribute('opacity','0');
    epNew.setAttribute('opacity','0'); badge.setAttribute('opacity','0'); badgeTxt.setAttribute('opacity','0');
    epOld.setAttribute('opacity','1');
    // Reset oud evenwicht
    hline.setAttribute('x1','40'); hline.setAttribute('x2','180'); hline.setAttribute('y1','100'); hline.setAttribute('y2','100');
    hline.setAttribute('stroke','#f4a261'); hline.setAttribute('opacity','1');
    vline.setAttribute('x1','180'); vline.setAttribute('x2','180'); vline.setAttribute('y1','175'); vline.setAttribute('y2','100');
    vline.setAttribute('stroke','#f4a261'); vline.setAttribute('opacity','1');
    plabel.setAttribute('fill','#f4a261'); plabel.setAttribute('opacity','1');
    qlabel.setAttribute('fill','#f4a261'); qlabel.setAttribute('opacity','1');
    result.style.display='none';
    return;
  }

  // Nieuwe vraaglijn: x-coГ¶rdinaten +shift
  const nx1 = 60+shift, nx2 = 300+shift;
  vn.setAttribute('x1', nx1); vn.setAttribute('y1','30');
  vn.setAttribute('x2', nx2); vn.setAttribute('y2','170');
  vn.setAttribute('opacity','0.55');
  vnLabel.setAttribute('x', nx2+5); vnLabel.setAttribute('y','173');
  vnLabel.setAttribute('opacity','0.8');

  // Nieuw evenwichtspunt: snijpunt nieuwe V met A
  // A: x1=60,y1=170,x2=300,y2=30  вҶ’ y = 170 - (x-60)*(140/240)
  // Vn: x1=nx1,y1=30,x2=nx2,y2=170 вҶ’ y = 30 + (x-nx1)*(140/(nx2-nx1))
  // Snijpunt: 170-(x-60)*(7/12) = 30+(x-nx1)*(140/(nx2-nx1))
  // Beide lijnen hebben dezelfde helling maar gespiegeld, vereenvoudigd:
  const aSlope = (30-170)/(300-60); // -7/12
  const vSlope = (170-30)/(nx2-nx1); // 7/12
  // y = 170 + aSlope*(x-60)  en  y = 30 + vSlope*(x-nx1)
  // 170+aSlope*(x-60) = 30+vSlope*(x-nx1)
  const cx = (30+vSlope*nx1 - 170 - aSlope*60)/(vSlope-aSlope);
  const cy = 170+aSlope*(cx-60);

  epNew.setAttribute('cx', cx.toFixed(1));
  epNew.setAttribute('cy', cy.toFixed(1));
  epNew.setAttribute('opacity','1');
  epOld.setAttribute('opacity','0.3');

  // Update lijnen naar nieuw evenwicht
  hline.setAttribute('x1','40'); hline.setAttribute('x2',cx.toFixed(1));
  hline.setAttribute('y1',cy.toFixed(1)); hline.setAttribute('y2',cy.toFixed(1));
  hline.setAttribute('stroke','#0369a1');
  vline.setAttribute('x1',cx.toFixed(1)); vline.setAttribute('x2',cx.toFixed(1));
  vline.setAttribute('y1','175'); vline.setAttribute('y2',cy.toFixed(1));
  vline.setAttribute('stroke','#0369a1');
  plabel.setAttribute('fill','#0369a1');
  qlabel.setAttribute('fill','#0369a1');

  badge.setAttribute('opacity','1');
  badgeTxt.setAttribute('opacity','1');

  result.style.display='';
  const stijgingP = Math.round(pct*0.6);
  const stijgingQ = Math.round(pct*0.4);
  rTxt.textContent = 'P* stijgt ~'+stijgingP+'% В· Q* stijgt ~'+stijgingQ+'%';
  rUitleg.textContent = 'Door meer vraag verschuift de vraaglijn naar rechts (V\u2192V\u2032). Bij hetzelfde aanbod stijgt de evenwichtsprijs (P*) en neemt de evenwichtshoeveelheid (Q*) toe.';
}

// в”Җв”Җ Markt v2: twee sliders (vraag + aanbod) в”Җв”Җ
function updateMarkt2(){
  var vVal = parseInt(document.getElementById('markt-slider').value)||0;
  var aVal = parseInt(document.getElementById('aanbod-slider').value)||0;
  document.getElementById('markt-label').textContent = (vVal>=0?'+':'')+vVal+'%';
  document.getElementById('aanbod-label').textContent = (aVal>=0?'+':'')+aVal+'%';
  document.getElementById('markt-slider').setAttribute('aria-valuenow', vVal);
  document.getElementById('aanbod-slider').setAttribute('aria-valuenow', aVal);

  // SVG coГ¶rdinaten: Y=10 is hoog (hoge prijs), Y=180 is laag (lage prijs)
  // Vraaglijn origineel: (60,30)вҶ’(300,175) = negatief verband
  // Aanbodlijn origineel: (60,175)вҶ’(300,30) = positief verband

  var vShift = vVal * 0.7;  // max ~42px
  var aShift = aVal * 0.7;

  var svgVn = document.getElementById('svg-vn');
  var svgVnLabel = document.getElementById('svg-vn-label');
  var svgAn = document.getElementById('svg-an');
  var svgAnLabel = document.getElementById('svg-an-label');
  var epOld = document.getElementById('svg-ep-old');
  var epNew = document.getElementById('svg-ep-new');
  var badge = document.getElementById('svg-badge-bg');
  var badgeTxt = document.getElementById('svg-badge-txt');
  var hline = document.getElementById('svg-ep-hline');
  var vline = document.getElementById('svg-ep-vline');
  var plabel = document.getElementById('svg-ep-plabel');
  var qlabel = document.getElementById('svg-ep-qlabel');
  var result = document.getElementById('markt-result2');
  var rP = document.getElementById('r-markt-p');
  var rQ = document.getElementById('r-markt-q');
  var rUitleg = document.getElementById('r-markt-uitleg2');

  var changed = (vVal !== 0 || aVal !== 0);

  // Nieuwe V-lijn coГ¶rdinaten (horizontale verschuiving)
  var vx1 = 60+vShift, vx2 = 300+vShift;
  var vy1 = 30, vy2 = 175;

  // Nieuwe A-lijn coГ¶rdinaten (horizontale verschuiving)
  var ax1 = 60+aShift, ax2 = 300+aShift;
  var ay1 = 175, ay2 = 30;

  if(vVal !== 0){
    svgVn.setAttribute('x1',vx1); svgVn.setAttribute('y1',vy1);
    svgVn.setAttribute('x2',vx2); svgVn.setAttribute('y2',vy2);
    svgVn.setAttribute('opacity','0.6');
    svgVnLabel.setAttribute('x',vx2+5); svgVnLabel.setAttribute('y','178');
    svgVnLabel.setAttribute('opacity','0.9');
  } else {
    svgVn.setAttribute('opacity','0'); svgVnLabel.setAttribute('opacity','0');
  }

  if(aVal !== 0){
    svgAn.setAttribute('x1',ax1); svgAn.setAttribute('y1',ay1);
    svgAn.setAttribute('x2',ax2); svgAn.setAttribute('y2',ay2);
    svgAn.setAttribute('opacity','0.6');
    svgAnLabel.setAttribute('x',ax2+5); svgAnLabel.setAttribute('y','28');
    svgAnLabel.setAttribute('opacity','0.9');
  } else {
    svgAn.setAttribute('opacity','0'); svgAnLabel.setAttribute('opacity','0');
  }

  if(!changed){
    // Reset to original equilibrium
    epOld.setAttribute('opacity','1'); epNew.setAttribute('opacity','0');
    badge.setAttribute('opacity','0'); badgeTxt.setAttribute('opacity','0');
    hline.setAttribute('x1','40'); hline.setAttribute('x2','180');
    hline.setAttribute('y1','102'); hline.setAttribute('y2','102');
    hline.setAttribute('stroke','#f4a261'); hline.setAttribute('opacity','1');
    vline.setAttribute('x1','180'); vline.setAttribute('x2','180');
    vline.setAttribute('y1','180'); vline.setAttribute('y2','102');
    vline.setAttribute('stroke','#f4a261'); vline.setAttribute('opacity','1');
    plabel.setAttribute('fill','#f4a261'); qlabel.setAttribute('fill','#f4a261');
    result.style.display='none';
    return;
  }

  // Bereken nieuw snijpunt
  // Actieve V: origineel of verschoven
  var cvx1 = vVal!==0 ? vx1 : 60, cvx2 = vVal!==0 ? vx2 : 300;
  var cvy1=30, cvy2=175;
  // Actieve A: origineel of verschoven
  var cax1 = aVal!==0 ? ax1 : 60, cax2 = aVal!==0 ? ax2 : 300;
  var cay1=175, cay2=30;

  var vSlope = (cvy2-cvy1)/(cvx2-cvx1);
  var aSlope = (cay2-cay1)/(cax2-cax1);
  // y = cvy1 + vSlope*(x-cvx1)  en  y = cay1 + aSlope*(x-cax1)
  var cx = (cay1 - aSlope*cax1 - cvy1 + vSlope*cvx1)/(vSlope - aSlope);
  var cy = cvy1 + vSlope*(cx-cvx1);

  // Begrens tot grafiekgebied
  cx = Math.max(50, Math.min(310, cx));
  cy = Math.max(15, Math.min(170, cy));

  epNew.setAttribute('cx', cx.toFixed(1)); epNew.setAttribute('cy', cy.toFixed(1));
  epNew.setAttribute('opacity','1'); epOld.setAttribute('opacity','0.3');

  hline.setAttribute('x1','40'); hline.setAttribute('x2',cx.toFixed(1));
  hline.setAttribute('y1',cy.toFixed(1)); hline.setAttribute('y2',cy.toFixed(1));
  hline.setAttribute('stroke','#0369a1'); hline.setAttribute('opacity','1');
  vline.setAttribute('x1',cx.toFixed(1)); vline.setAttribute('x2',cx.toFixed(1));
  vline.setAttribute('y1','180'); vline.setAttribute('y2',cy.toFixed(1));
  vline.setAttribute('stroke','#0369a1'); vline.setAttribute('opacity','1');
  plabel.setAttribute('fill','#0369a1'); qlabel.setAttribute('fill','#0369a1');
  qlabel.setAttribute('x',cx.toFixed(1));

  badge.setAttribute('opacity','1'); badgeTxt.setAttribute('opacity','1');

  // Interpreteer richting voor uitleg (Y negatief = hogere prijs in SVG)
  var origEqY = 102, origEqX = 180;
  var pRichting = cy < origEqY ? 'gestegen вҶ‘' : cy > origEqY ? 'gedaald вҶ“' : 'onveranderd';
  var qRichting = cx > origEqX ? 'gestegen вҶ‘' : cx < origEqX ? 'gedaald вҶ“' : 'onveranderd';

  var pPct = Math.abs(Math.round((origEqY - cy)/origEqY*100));
  var qPct = Math.abs(Math.round((cx - origEqX)/origEqX*100));

  rP.textContent = pRichting + (pPct>0 ? ' (~'+pPct+'%)':'');
  rQ.textContent = qRichting + (qPct>0 ? ' (~'+qPct+'%)':'');

  // Genereer economische uitleg
  var uitleg = '';
  if(vVal>0 && aVal===0) uitleg = 'De vraaglijn schuift naar rechts: meer consumenten willen het product bij elke prijs. Het tekort drijft de evenwichtsprijs omhoog.';
  else if(vVal<0 && aVal===0) uitleg = 'De vraaglijn schuift naar links: minder consumenten willen het product. Het overschot drukt de evenwichtsprijs omlaag.';
  else if(aVal>0 && vVal===0) uitleg = 'De aanbodlijn schuift naar rechts: producenten bieden meer aan (bijv. lagere kosten). Bij gelijkblijvende vraag daalt de evenwichtsprijs.';
  else if(aVal<0 && vVal===0) uitleg = 'De aanbodlijn schuift naar links: producenten bieden minder aan (bijv. hogere kosten of minder producenten). Dat drijft de prijs omhoog.';
  else if(vVal>0 && aVal>0) uitleg = 'Vraag EN aanbod stijgen. Het effect op de prijs hangt af van welke verschuiving groter is. De hoeveelheid neemt zeker toe.';
  else if(vVal<0 && aVal<0) uitleg = 'Vraag EN aanbod dalen. De hoeveelheid neemt zeker af. Het prijseffect hangt af van de relatieve omvang van de verschuivingen.';
  else if(vVal>0 && aVal<0) uitleg = 'Meer vraag Г©n minder aanbod: dubbel opwaartse druk op de prijs. De hoeveelheid kan stijgen of dalen, afhankelijk van de grootte van de verschuivingen.';
  else uitleg = 'Minder vraag Г©n meer aanbod: dubbel neerwaartse druk op de prijs. De hoeveelheid kan stijgen of dalen.';

  rUitleg.textContent = uitleg;
  result.style.display='';
}

function resetMarkt2(){
  document.getElementById('markt-slider').value=0;
  document.getElementById('aanbod-slider').value=0;
  updateMarkt2();
}

// в”Җв”Җ Elasticiteit в”Җв”Җ
function berekenElas(){
  const p1=parseFloat(document.getElementById('el-p1').value)||0;
  const p2=parseFloat(document.getElementById('el-p2').value)||0;
  const q1=parseFloat(document.getElementById('el-q1').value)||0;
  const q2=parseFloat(document.getElementById('el-q2').value)||0;
  if(!p1||!q1||p1===p2){return;}
  const dp=(p2-p1)/p1*100;
  const dq=(q2-q1)/q1*100;
  const pev=dq/dp;
  const absPev=Math.abs(pev);

  const fmtPct=v=>(v>=0?'+':'')+v.toFixed(1).replace('.',',')+'%';
  const fmtN=v=>v.toFixed(2).replace('.',',');
  document.getElementById('r-el-dp').textContent=fmtPct(dp);
  document.getElementById('r-el-dq').textContent=fmtPct(dq);
  document.getElementById('r-el-pev').textContent=fmtN(pev);

  const res=document.getElementById('elas-result');
  const uitleg=document.getElementById('r-el-uitleg');
  const oordeel=document.getElementById('r-el-oordeel');

  if(absPev>1){
    oordeel.textContent='\u2705 Elastisch (|PEV| > 1)';
    res.className='lab-result elastisch';
    uitleg.textContent='De vraag reageert sterk op de prijsverandering. Kopers wijken makkelijk uit naar alternatieven. Voorbeelden: luxeproducten, vakantievluchten.';
  } else if(absPev<1){
    oordeel.textContent='\u26a0\ufe0f Inelastisch (|PEV| < 1)';
    res.className='lab-result inelastisch';
    uitleg.textContent='De vraag reageert weinig op de prijsverandering. Kopers hebben weinig keuze of het product is noodzakelijk. Voorbeelden: medicijnen, benzine, brood.';
  } else {
    oordeel.textContent='\u2194\ufe0f Eenheidselastisch (|PEV| = 1)';
    res.className='lab-result';
    uitleg.textContent='De procentuele verandering in hoeveelheid is precies gelijk aan de procentuele verandering in prijs. Zeldzaam in de praktijk.';
  }

  // Stapsgewijze uitleg
  const s1=document.getElementById('elas-stap1');
  const s2=document.getElementById('elas-stap2');
  const s3=document.getElementById('elas-stap3');
  const s4=document.getElementById('elas-stap4');
  if(s1) s1.innerHTML=`<strong>Stap 1 вҖ” Bereken de procentuele prijsverandering (О”P%):</strong><br>
    (${p2.toFixed(2)} вҲ’ ${p1.toFixed(2)}) Г· ${p1.toFixed(2)} Г— 100 = <strong>${fmtPct(dp)}</strong>`;
  if(s2) s2.innerHTML=`<strong>Stap 2 вҖ” Bereken de procentuele hoeveelheidsverandering (О”Q%):</strong><br>
    (${q2} вҲ’ ${q1}) Г· ${q1} Г— 100 = <strong>${fmtPct(dq)}</strong>`;
  if(s3) s3.innerHTML=`<strong>Stap 3 вҖ” Bereken de PEV:</strong><br>
    PEV = О”Q% Г· О”P% = ${fmtPct(dq)} Г· ${fmtPct(dp)} = <strong>${fmtN(pev)}</strong>`;
  if(s4) s4.innerHTML=`<strong>Conclusie:</strong> |PEV| = ${fmtN(absPev)} вҶ’ ${absPev>1?'<span style="color:#15803d">Elastisch</span> вҖ” vraag reageert sterk':absPev<1?'<span style="color:#c2410c">Inelastisch</span> вҖ” vraag reageert weinig':'<span style="color:#0369a1">Eenheidselastisch</span>'}. ${absPev>1?'Een prijsstijging leidt tot een groter procentueel verlies in verkopen (omzet daalt).':absPev<1?'Een prijsstijging leidt tot een kleiner procentueel verlies in verkopen (omzet stijgt).':'Omzet blijft gelijk bij prijsverandering.'}`;
}

