function ddStatCard(titel,waarde,sub,kleur){
  return '<div style="background:#f8f9fa;border:1.5px solid #eee;border-radius:10px;padding:.9rem .75rem;text-align:center">'
    +'<div style="font-size:.72rem;color:#888;margin-bottom:.25rem">'+titel+'</div>'
    +'<div style="font-size:1.6rem;font-weight:900;color:'+kleur+'">'+waarde+'</div>'
    +'<div style="font-size:.68rem;color:#aaa;margin-top:.2rem">'+sub+'</div>'
    +'</div>';
}

function ddEsc(s){ return (s||'').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }

// в”Җв”Җ Export / Klascode в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function ddExport(){
  var da=ddGetData();
  var json=JSON.stringify(da);
  // Base64 encoden
  var b64;
  try{ b64=btoa(unescape(encodeURIComponent(json))); }
  catch(e){ b64=btoa(json.replace(/[^\x00-\x7F]/g,'?')); }
  var code='VLA-'+b64.substring(0,200); // max leesbare code
  document.getElementById('dd-export-tekst').value=code;
  // QR via Google Charts API
  var qrWrap=document.getElementById('dd-qr-wrap');
  var qrData=encodeURIComponent(code.substring(0,300));
  qrWrap.innerHTML='<img src="https://chart.googleapis.com/chart?chs=160x160&cht=qr&chl='+qrData+'&choe=UTF-8" alt="QR-code klasdata" style="border-radius:8px;border:1px solid #eee">';
  document.getElementById('dd-export-overlay').style.display='flex';
}

function ddKopieer(){
  var t=document.getElementById('dd-export-tekst');
  t.select();
  try{ document.execCommand('copy'); }
  catch(e){ navigator.clipboard&&navigator.clipboard.writeText(t.value); }
  // Korte bevestiging
  var btn=event.target;
  var oud=btn.textContent;
  btn.textContent='вң… Gekopieerd!';
  setTimeout(function(){btn.textContent=oud;},2000);
}

// в”Җв”Җ Wis data в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
function ddWis(){
  if(!confirm('Weet je het zeker? Alle analytics-data van dit apparaat wordt gewist. Dit kun je niet terugdraaien.')) return;
  try{ localStorage.removeItem('docent_analytics'); }catch(e){}
  ddRender();
  // Korte melding
  var body=document.getElementById('dd-body');
  var melding=document.createElement('div');
  melding.textContent='вң… Data gewist. Klaar voor de volgende klas.';
  melding.style.cssText='background:#e8f5e9;color:#1a7a4a;padding:.7rem 1rem;border-radius:8px;font-size:.85rem;font-weight:700;margin-top:.8rem;text-align:center';
  body.appendChild(melding);
  setTimeout(function(){melding.remove();},3000);
}
