var _crScenarioIdx = 0;
var _crVolgorde = [];
var _crGeprobeerd = 0;

function crInit(){
  var container = document.getElementById('cr-container');
  if(!container) return;
  var scenario = CR_SCENARIOS[_crScenarioIdx];
  _crVolgorde = [];
  _crGeprobeerd = 0;

  // Shuffle de kaartjes voor de bank
  var bank = scenario.keten.slice().sort(function(){ return Math.random() - 0.5; });

  var html = '<div class="cr-wrap">';
  html += '<div class="cr-titel">'+escHtml(scenario.titel)+'</div>';
  html += '<div class="cr-scenario-titel">'+escHtml(scenario.beschrijving)+'</div>';

  // Scenario keuze knoppen
  html += '<div style="display:flex;gap:.4rem;flex-wrap:wrap;margin-bottom:.9rem">';
  CR_SCENARIOS.forEach(function(sc, idx){
    var actief = idx === _crScenarioIdx ? 'style="background:var(--g);color:#fff;border-color:var(--g)"' : '';
    html += '<button class="cr-btn sec" '+actief+' onclick="crKiesScenario('+idx+')" style="font-size:.75rem;padding:.3rem .7rem">'+escHtml(sc.titel.replace('Scenario: ',''))+'</button>';
  });
  html += '</div>';

  html += '<div style="font-size:.8rem;font-weight:700;color:#555;margin-bottom:.3rem">рҹҺҜ Jouw keten (sleep hier de kaartjes naartoe):</div>';
  html += '<div class="cr-keten" id="cr-keten" ondragover="crDragOver(event)" ondrop="crDrop(event,\'keten\')" ondragleave="crDragLeave(event)">';
  html += '<span style="color:#bbb;font-size:.8rem;font-style:italic" id="cr-keten-placeholder">Sleep kaartjes hierheen in de juiste volgorde...</span>';
  html += '</div>';

  html += '<div style="font-size:.8rem;font-weight:700;color:#555;margin-bottom:.3rem;margin-top:.4rem">рҹ“Ұ Beschikbare kaartjes:</div>';
  html += '<div class="cr-bank" id="cr-bank">';
  bank.forEach(function(kaartje, idx){
    html += '<span class="cr-kaartje" draggable="true" id="crk-'+idx+'" data-txt="'+encodeURIComponent(kaartje)+'"'
      + ' ondragstart="crDragStart(event)" onclick="crKlikKaartje(this)">'
      + 'вҳ° '+escHtml(kaartje)+'</span>';
  });
  html += '</div>';

  html += '<div class="cr-acties">';
  html += '<button class="cr-btn" onclick="crControleer()">вң… Controleer volgorde</button>';
  html += '<button class="cr-btn sec" onclick="crReset()">рҹ”„ Opnieuw</button>';
  html += '<button class="cr-btn sec" onclick="crToon()">рҹ’Ў Toon juiste volgorde</button>';
  html += '</div>';

  html += '<div class="cr-feedback" id="cr-fb"></div>';

  // Score teller
  html += '<div id="cr-score-wrap" style="margin-top:.6rem;display:none">';
  html += '<div class="cr-score" id="cr-score"></div>';
  html += '</div>';

  html += '</div>'; // cr-wrap

  container.innerHTML = html;

  // Touch support voor mobiel
  crInitTouch();
}

function crKiesScenario(idx){
  _crScenarioIdx = idx;
  crInit();
}

var _crDragEl = null;
var _crDragFrom = null;

function crDragStart(e){
  _crDragEl = e.currentTarget || e.target;
  while(_crDragEl && !_crDragEl.classList.contains('cr-kaartje')) _crDragEl = _crDragEl.parentElement;
  _crDragFrom = _crDragEl ? _crDragEl.parentElement.id : null;
  e.dataTransfer.effectAllowed = 'move';
  e.dataTransfer.setData('text/plain', _crDragEl ? _crDragEl.id : '');
  var el = _crDragEl;
  setTimeout(function(){ if(el) el.style.opacity = '0.4'; }, 0);
}

function crDragOver(e){
  e.preventDefault();
  e.dataTransfer.dropEffect = 'move';
  var t = e.currentTarget;
  t.classList.add('dragover');
}

function crDragLeave(e){
  e.currentTarget.classList.remove('dragover');
}

function crDrop(e, zone){
  e.preventDefault();
  e.currentTarget.classList.remove('dragover');
  if(!_crDragEl) return;
  _crDragEl.style.opacity = '';
  var placeholder = document.getElementById('cr-keten-placeholder');
  if(placeholder) placeholder.remove();

  if(zone === 'keten'){
    document.getElementById('cr-keten').appendChild(_crDragEl);
  } else {
    document.getElementById('cr-bank').appendChild(_crDragEl);
  }
  _crDragEl = null;
}

// Klik-gebaseerde fallback voor mobiel
var _crGekozen = null;
function crKlikKaartje(el){
  if(!_crGekozen){
    // Eerste klik: selecteer kaartje
    document.querySelectorAll('.cr-kaartje').forEach(function(k){ k.style.outline = ''; });
    el.style.outline = '3px solid var(--g)';
    _crGekozen = el;
  } else if(_crGekozen === el){
    // Tweede klik op zelfde: deselecteer
    el.style.outline = '';
    _crGekozen = null;
  } else {
    // Tweede klik: verplaats geselecteerde naar zelfde container als doel, voor doel
    var doelParent = el.parentElement;
    var vanParent = _crGekozen.parentElement;
    var placeholder = document.getElementById('cr-keten-placeholder');
    if(placeholder && vanParent.id === 'cr-bank' && doelParent.id === 'cr-keten'){
      placeholder.remove();
    }
    doelParent.insertBefore(_crGekozen, el);
    _crGekozen.style.outline = '';
    _crGekozen = null;
  }
}

function crInitTouch(){
  // Klik op lege keten: verplaats geselecteerde kaartje erin
  var keten = document.getElementById('cr-keten');
  if(keten){
    keten.addEventListener('click', function(e){
      if(e.target === keten && _crGekozen){
        var placeholder = document.getElementById('cr-keten-placeholder');
        if(placeholder) placeholder.remove();
        keten.appendChild(_crGekozen);
        _crGekozen.style.outline = '';
        _crGekozen = null;
      }
    });
  }
}

function crControleer(){
  var ketenEl = document.getElementById('cr-keten');
  var kaartjes = ketenEl.querySelectorAll('.cr-kaartje');
  var scenario = CR_SCENARIOS[_crScenarioIdx];
  var juist = scenario.keten;
  var fb = document.getElementById('cr-fb');

  if(kaartjes.length === 0){
    fb.className = 'cr-feedback show fout';
    fb.innerHTML = 'вҡ пёҸ Sleep eerst de kaartjes naar de keten!';
    return;
  }

  if(kaartjes.length < juist.length){
    fb.className = 'cr-feedback show fout';
    fb.innerHTML = 'вҡ пёҸ Je hebt nog niet alle kaartjes in de keten geplaatst. Er missen er nog '+( juist.length - kaartjes.length)+'.';
    return;
  }

  _crGeprobeerd++;
  var aantalGoed = 0;
  var kaartjesArr = Array.from(kaartjes);
  kaartjesArr.forEach(function(k, idx){
    var txt = decodeURIComponent(k.dataset.txt || '');
    k.classList.remove('cr-goed','cr-fout');
    if(idx < juist.length && txt === juist[idx]){
      k.classList.add('cr-goed');
      k.innerHTML = 'вң“ ' + escHtml(txt);
      aantalGoed++;
    } else {
      k.classList.add('cr-fout');
      k.innerHTML = 'вң— ' + escHtml(txt);
    }
  });

  if(aantalGoed === juist.length){
    fb.className = 'cr-feedback show goed';
    fb.innerHTML = 'рҹҺү <strong>Geweldig!</strong> Je hebt de economische kettingreactie helemaal goed! Je begrijpt hoe oorzaken leiden tot gevolgen in de economie.';
    // Registreer in analytics
    crRegistreerAnalytics(scenario.id, true, _crGeprobeerd);
    document.getElementById('cr-score-wrap').style.display = '';
    document.getElementById('cr-score').textContent = _crGeprobeerd === 1 ? 'вӯҗ Perfect in 1 poging!' : 'вң… Gelukt in ' + _crGeprobeerd + ' pogingen';
  } else {
    fb.className = 'cr-feedback show fout';
    fb.innerHTML = 'вқҢ <strong>' + aantalGoed + ' van de ' + juist.length + ' kaartjes staan op de juiste plek.</strong> De rode kaartjes staan fout. Probeer het opnieuw!';
    crRegistreerAnalytics(scenario.id, false, _crGeprobeerd);
  }
}

function crToon(){
  var scenario = CR_SCENARIOS[_crScenarioIdx];
  var fb = document.getElementById('cr-fb');
  fb.className = 'cr-feedback show goed';
  fb.innerHTML = '<strong>рҹ’Ў Juiste volgorde:</strong><br>'
    + scenario.keten.map(function(k, i){
        return '<span style="display:inline-block;background:#d8f0e8;border:1px solid #a8d8a8;border-radius:6px;padding:.2rem .55rem;margin:.2rem;font-size:.8rem">'
          + (i+1)+'. '+escHtml(k)+'</span>'
          + (i < scenario.keten.length - 1 ? ' <span style="color:#888">вҶ’</span>' : '');
      }).join(' ');
  crRegistreerAnalytics(scenario.id, false, _crGeprobeerd + 1);
}

function crReset(){
  crInit();
}

function crRegistreerAnalytics(scenarioId, succes, pogingen){
  try{
    var da = JSON.parse(localStorage.getItem('docent_analytics')||'{}');
    if(!da.causaal) da.causaal = {};
    if(!da.causaal[scenarioId]) da.causaal[scenarioId] = {naam: scenarioId, pogingen:[], successen:0, totaal:0};
    da.causaal[scenarioId].totaal++;
    da.causaal[scenarioId].pogingen.push(pogingen);
    if(succes) da.causaal[scenarioId].successen++;
    if(da.causaal[scenarioId].pogingen.length > 50) da.causaal[scenarioId].pogingen.shift();
    localStorage.setItem('docent_analytics', JSON.stringify(da));
  }catch(e){}
}

function escHtml(s){
  return (s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

// Registreer 'cr' als geldige go()-modus
(function(){
  var origGo = window.go;
  window.go = function(modus){
    if(modus === 'cr'){
      document.querySelectorAll('.screen').forEach(function(s){ s.classList.remove('active'); });
      var s = document.getElementById('s-cr');
      if(s){ s.classList.add('active'); crInit(); }
      return;
    }
    if(typeof origGo === 'function') origGo(modus);
  };
})();


// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
// MODULE 2: ADAPTIEVE FEEDBACK LOOP вҖ” Fouten-Tracker & Hulp-Overlay
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

// Foutenteller per categorie (in geheugen + localStorage)
var _foutTracker = (function(){
  try{ return JSON.parse(localStorage.getItem('ft_fouten')||'{}'); }catch(e){ return {}; }
})();

// CategorieГ«n + bijbehorende pro-tips
var HULP_TIPS = {
  'Procenten': {
    titel: 'Procentenberekening',
    tip: 'Let op: een percentage bereken je altijd als: (deel Г· geheel) Г— 100. Bijvoorbeeld: 30 van 120 = (30 Г· 120) Г— 100 = 25%. Schrijf de formule altijd eerst op!'
  },
  'Nieuw-Oud': {
    titel: 'Nieuw-Oud methode',
    tip: 'Onthoud: Nieuw-Oud geeft je de VERANDERING. Je deelt altijd door het OUDE getal: ((Nieuw вҲ’ Oud) Г· Oud) Г— 100%. Het "Oud" getal is je startpunt!'
  },
  'Wisselkoersen': {
    titel: 'Wisselkoersen',
    tip: 'Goedkopere munt вҶ’ export aantrekkelijker (buitenlanders betalen minder in hun eigen valuta). Duurdere munt вҶ’ import goedkoper. Teken een pijltjeschema: munt omhoog = export omlaag.'
  },
  'Breakevenpoint': {
    titel: 'Breakevenpoint (BEP)',
    tip: 'BEP = Vaste kosten Г· (Verkoopprijs вҲ’ Variabele kosten per stuk). Eerst bereken je de dekkingsbijdrage per stuk, dan deel je de vaste kosten daardoor. Stap voor stap!'
  },
  'Inflatie': {
    titel: 'Inflatie & koopkracht',
    tip: 'Als inflatie stijgt maar je loon niet, daalt je koopkracht. ReГ«le koopkracht = nominale stijging вҲ’ inflatie%. Bij inflatie van 3% en loonstijging 2% = koopkracht daalt met 1%.'
  },
  'Belastingen': {
    titel: 'BTW berekeningen',
    tip: 'BTW bereken je over de prijs EXCLUSIEF btw. Prijs inclusief 21% btw: vermenigvuldig met 1,21. Terug naar exclusief: deel door 1,21. Let op: NOOIT btw-bedrag als grondslag gebruiken!'
  },
  'Arbeidsmarkt': {
    titel: 'Vraag & aanbod arbeid',
    tip: 'Te veel aanbod van arbeid = werkloosheid (aanbod > vraag). Te weinig aanbod = krapte (vraag > aanbod). Teken altijd een S&D diagram in je hoofd: waar snijden de lijnen?'
  },
  'Samengestelde rente': {
    titel: 'Samengestelde rente',
    tip: 'Samengestelde rente (compound interest): rente op rente. Formule: Eindkapitaal = Startkapitaal Г— (1 + r)^n. Elke jaar groeit het saldo, dus ook de rentebasis. Gebruik een stappenplan!'
  }
};

// Detecteer categorie op basis van vraag/uitleg tekst
function detecteerCategorie(vraagTekst, uitlegTekst){
  var tekst = ((vraagTekst||'') + ' ' + (uitlegTekst||'')).toLowerCase();
  if(tekst.includes('wisselkoers') || tekst.includes('valuta') || tekst.includes('euro') && tekst.includes('dollar')) return 'Wisselkoersen';
  if(tekst.includes('breakevenpoint') || tekst.includes('bep') || tekst.includes('break-even') || tekst.includes('vaste kosten') && tekst.includes('dekkingsbijdrage')) return 'Breakevenpoint';
  if(tekst.includes('nieuw') && tekst.includes('oud') && (tekst.includes('%') || tekst.includes('procent'))) return 'Nieuw-Oud';
  if(tekst.includes('btw') || tekst.includes('belasting') && tekst.includes('tarief')) return 'Belastingen';
  if(tekst.includes('inflatie') || tekst.includes('koopkracht') || tekst.includes('reeel') || tekst.includes('reГ«le')) return 'Inflatie';
  if(tekst.includes('samengestelde') || tekst.includes('compound') || tekst.includes('rente op rente')) return 'Samengestelde rente';
  if(tekst.includes('arbeidsmarkt') || tekst.includes('werkloosheid') || tekst.includes('vacature') || tekst.includes('arbeidsvraag')) return 'Arbeidsmarkt';
  if(tekst.includes('%') || tekst.includes('procent') || tekst.includes('percentage')) return 'Procenten';
  return null;
}

function registreerFout(vraagTekst, uitlegTekst){
  var cat = detecteerCategorie(vraagTekst, uitlegTekst);
  if(!cat) return;

  if(!_foutTracker[cat]) _foutTracker[cat] = 0;
  _foutTracker[cat]++;

  // Sla ook op in docent_analytics
  try{
    var da = JSON.parse(localStorage.getItem('docent_analytics')||'{}');
    if(!da.foutenCategorie) da.foutenCategorie = {};
    if(!da.foutenCategorie[cat]) da.foutenCategorie[cat] = {naam:cat, fouten:0, eerste: new Date().toLocaleDateString('nl-NL')};
    da.foutenCategorie[cat].fouten++;
    da.foutenCategorie[cat].laatste = new Date().toLocaleDateString('nl-NL');
    localStorage.setItem('docent_analytics', JSON.stringify(da));
  }catch(e){}

  // Sla foutenteller op
  try{ localStorage.setItem('ft_fouten', JSON.stringify(_foutTracker)); }catch(e){}

  // Toon overlay als drempel bereikt (meer dan 2 fouten in deze categorie)
  if(_foutTracker[cat] > 2 && HULP_TIPS[cat]){
    toonHulpOverlay(cat);
    _foutTracker[cat] = 0; // Reset teller na tonen overlay
    try{ localStorage.setItem('ft_fouten', JSON.stringify(_foutTracker)); }catch(e){}
  }
}

function toonHulpOverlay(cat){
  var tip = HULP_TIPS[cat];
  if(!tip) return;
  document.getElementById('ho-kategorie').textContent = 'рҹ“ҡ Categorie: ' + cat;
  document.getElementById('ho-titel').textContent = 'рҹ’Ў Pro-tip: ' + tip.titel;
  document.getElementById('ho-tip').textContent = tip.tip;
  var overlay = document.getElementById('hulp-overlay');
  if(overlay) overlay.classList.add('show');
}

function sluitHulpOverlay(){
  var overlay = document.getElementById('hulp-overlay');
  if(overlay) overlay.classList.remove('show');
}

// Sluit overlay bij klik buiten het venster
document.addEventListener('click', function(e){
  var overlay = document.getElementById('hulp-overlay');
  if(overlay && overlay.classList.contains('show') && e.target === overlay){
    sluitHulpOverlay();
  }
});

// в”Җв”Җ Hak in op bestaande antwoord() functie voor fout-tracking в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
(function(){
  var origAntwoord = window.antwoord;
  window.antwoord = function(i){
    // Roep origineel aan
    if(typeof origAntwoord === 'function') origAntwoord(i);
    // Na antwoord: check of het fout was en registreer
    try{
      var v = window._vrPool && window._vrPool[window.vrI];
      if(v && i !== v.c){
        registreerFout(v.q || '', v.u || '');
      }
    }catch(e){}
  };

  // Ook voor de checkRk rekensom-functie
  var origCheckRk = window.checkRk;
  window.checkRk = function(){
    if(typeof origCheckRk === 'function') origCheckRk();
    // Na checkRk: kijk of het antwoord fout was via feedback element
    try{
      var fb = document.getElementById('rk-fb');
      if(fb && fb.classList.contains('fout')){
        var v = window._rkPool && window._rkPool[window.rkI];
        if(v) registreerFout(v.v || '', v.u || '');
      }
    }catch(e){}
  };
})();

// в”Җв”Җ Uitbreiden docent-dashboard met foutencategorieГ«n в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
(function(){
  var origDdRender = window.ddRender;
  window.ddRender = function(){
    if(typeof origDdRender === 'function') origDdRender();
    // Voeg foutencategorieГ«n sectie toe aan het dashboard
    var body = document.getElementById('dd-body');
    if(!body) return;
    try{
      var da = JSON.parse(localStorage.getItem('docent_analytics')||'{}');
      var fc = da.foutenCategorie || {};
      var crD = da.causaal || {};
      var fcArr = Object.values(fc).sort(function(a,b){ return b.fouten - a.fouten; });
      var crArr = Object.values(crD).sort(function(a,b){ return (a.successen/Math.max(a.totaal,1)) - (b.successen/Math.max(b.totaal,1)); });

      var extra = '';

      // FoutencategorieГ«n tabel
      if(fcArr.length){
        extra += '<div style="margin-top:1rem;margin-bottom:.8rem">';
        extra += '<div style="font-weight:800;font-size:.88rem;margin-bottom:.55rem;color:#1a2e4a">вҡ пёҸ Rekenstappen waar leerlingen vastlopen</div>';
        extra += '<table style="width:100%;border-collapse:collapse;background:#fafafa;border-radius:10px;overflow:hidden">';
        extra += '<thead><tr style="background:#f0f0f0"><th style="padding:.45rem .6rem;font-size:.75rem;text-align:left;font-weight:700;color:#555">Categorie</th><th style="text-align:center;padding:.45rem .6rem;font-size:.75rem;font-weight:700;color:#555">Fouten</th><th style="text-align:center;padding:.45rem .6rem;font-size:.75rem;font-weight:700;color:#555">Laatste fout</th></tr></thead><tbody>';
        fcArr.slice(0,5).forEach(function(f){
          var kleur = f.fouten >= 10 ? '#c0392b' : f.fouten >= 5 ? '#e67e22' : '#27ae60';
          extra += '<tr><td style="padding:.45rem .6rem;font-size:.82rem">'+ddEsc(f.naam)+'</td>'
            +'<td style="padding:.45rem .6rem;font-size:.82rem;text-align:center;font-weight:700;color:'+kleur+'">'+f.fouten+'</td>'
            +'<td style="padding:.45rem .6rem;font-size:.78rem;text-align:center;color:#aaa">'+ddEsc(f.laatste||f.eerste||'-')+'</td></tr>';
        });
        extra += '</tbody></table></div>';
      }

      // Causale redeneer-tool resultaten
      if(crArr.length){
        extra += '<div style="margin-bottom:.8rem">';
        extra += '<div style="font-weight:800;font-size:.88rem;margin-bottom:.55rem;color:#1a2e4a">рҹ”— Oorzaak &amp; Gevolg вҖ” succespercentages</div>';
        extra += '<table style="width:100%;border-collapse:collapse;background:#fafafa;border-radius:10px;overflow:hidden">';
        extra += '<thead><tr style="background:#f0f0f0"><th style="padding:.45rem .6rem;font-size:.75rem;text-align:left;font-weight:700;color:#555">Scenario</th><th style="text-align:center;padding:.45rem .6rem;font-size:.75rem;font-weight:700;color:#555">Pogingen</th><th style="text-align:center;padding:.45rem .6rem;font-size:.75rem;font-weight:700;color:#555">Succes</th></tr></thead><tbody>';
        crArr.forEach(function(cr){
          var pct = cr.totaal > 0 ? Math.round((cr.successen/cr.totaal)*100) : 0;
          var kleur = pct >= 70 ? '#27ae60' : pct >= 40 ? '#e67e22' : '#c0392b';
          extra += '<tr><td style="padding:.45rem .6rem;font-size:.82rem">'+ddEsc(cr.naam)+'</td>'
            +'<td style="padding:.45rem .6rem;font-size:.82rem;text-align:center">'+cr.totaal+'</td>'
            +'<td style="padding:.45rem .6rem;font-size:.82rem;text-align:center;font-weight:700;color:'+kleur+'">'+pct+'%</td></tr>';
        });
        extra += '</tbody></table></div>';
      }

      if(extra) body.insertAdjacentHTML('beforeend', extra);
    }catch(e){}
  };
})();

