var aiHuidigScenario = null;
var aiPogingen = 0, aiGoed = 0, aiFout = 0;

function aiLaadScherm(){
  var nv = NV || 'tl';
  var gefilterd = AI_SCENARIOS.filter(function(s){ return s.niveau.indexOf(nv) > -1 || s.niveau.indexOf('tl') > -1; });
  var wrap = document.getElementById('ai-scenario-wrap');
  if(!wrap) return;
  wrap.innerHTML = '';
  gefilterd.forEach(function(s, i){
    var el = document.createElement('button');
    el.style.cssText = 'background:var(--bg2);border:2px solid var(--border);border-radius:12px;padding:.75rem 1rem;text-align:left;cursor:pointer;font-family:"DM Sans",sans-serif;font-size:.87rem;color:var(--fg);transition:border .2s';
    el.onmouseover = function(){ this.style.borderColor='#2980b9'; };
    el.onmouseout = function(){ this.style.borderColor='var(--border)'; };
    el.innerHTML = '<div style="font-weight:700;margin-bottom:.2rem">Scenario '+(i+1)+': '+ddEsc(s.context.substring(0,55))+'...</div>'
      +'<div style="font-size:.78rem;color:var(--muted)">'+ddEsc(s.domein)+' В· '+ddEsc(s.bloom)+'</div>';
    el.onclick = (function(sc){ return function(){ aiKiesScenario(sc); }; })(s);
    wrap.appendChild(el);
  });
}

function aiKiesScenario(sc){
  aiHuidigScenario = sc;
  document.getElementById('ai-scenario-wrap').style.display = 'none';
  document.getElementById('ai-vraag-wrap').style.display = 'block';
  document.getElementById('ai-context-box').innerHTML = '<strong>рҹ“° Situatie:</strong> '+ddEsc(sc.context);
  document.getElementById('ai-vraag-tekst').textContent = sc.vraag;
  document.getElementById('ai-antwoord').value = '';
  document.getElementById('ai-feedback-wrap').style.display = 'none';
  document.getElementById('ai-loading').style.display = 'none';
}

function aiNieuwScenario(){
  document.getElementById('ai-scenario-wrap').style.display = 'grid';
  document.getElementById('ai-vraag-wrap').style.display = 'none';
  aiHuidigScenario = null;
}

function aiStuurIn(){
  var antwoord = (document.getElementById('ai-antwoord').value || '').trim();
  if(!antwoord || antwoord.length < 20){
    alert('Schrijf eerst een redenering (minstens 20 tekens).');
    return;
  }
  if(!aiHuidigScenario) return;

  document.getElementById('ai-loading').style.display = 'block';
  document.getElementById('ai-feedback-wrap').style.display = 'none';
  aiPogingen++;
  aiUpdateScore();

  var sc = aiHuidigScenario;
  var systeemPrompt = 'Je bent een Nederlandse economieleraar die leerlingen beoordeelt op causaal redeneren. ' +
    'Je beoordeelt antwoorden beknopt en constructief in eenvoudig Nederlands (jij-vorm). ' +
    'Geef ALTIJD feedback in dit formaat:\n' +
    '1. Oordeel: вң… Goed / вҡ пёҸ Gedeeltelijk / вқҢ Onvolledig\n' +
    '2. Wat klopt: [max 2 zinnen]\n' +
    '3. Wat mist of kan beter: [max 2 zinnen]\n' +
    '4. Modelantwoord: [beknopt]\n' +
    'Maximaal 120 woorden. Geen markdown headers.';

  var gebruikersBericht = 'Situatie: ' + sc.context + '\n' +
    'Vraag: ' + sc.vraag + '\n' +
    'Antwoord van leerling: ' + antwoord + '\n\n' +
    'Verwachte stappen in de keten: ' + sc.stappen.join(' вҶ’ ');

  fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      model: 'claude-sonnet-4-20250514',
      max_tokens: 400,
      system: systeemPrompt,
      messages: [{ role: 'user', content: gebruikersBericht }]
    })
  })
  .then(function(r){ return r.json(); })
  .then(function(data){
    document.getElementById('ai-loading').style.display = 'none';
    var tekst = (data.content && data.content[0] && data.content[0].text) || 'Geen feedback ontvangen.';
    var isGoed = tekst.indexOf('вң…') > -1;
    var isGedeeltelijk = tekst.indexOf('вҡ пёҸ') > -1;
    if(isGoed) aiGoed++; else aiFout++;
    aiUpdateScore();
    var hdrKleur = isGoed ? '#27ae60' : isGedeeltelijk ? '#e67e22' : '#e74c3c';
    var hdrTekst = isGoed ? 'вң… Goede redenering!' : isGedeeltelijk ? 'вҡ пёҸ Gedeeltelijk goed' : 'вқҢ Redenering onvolledig';
    document.getElementById('ai-feedback-header').style.background = hdrKleur;
    document.getElementById('ai-feedback-header').style.color = '#fff';
    document.getElementById('ai-feedback-header').textContent = hdrTekst;
    document.getElementById('ai-feedback-body').innerHTML = tekst.replace(/\n/g,'<br>');
    document.getElementById('ai-feedback-wrap').style.display = 'block';
  })
  .catch(function(){
    document.getElementById('ai-loading').style.display = 'none';
    document.getElementById('ai-feedback-header').style.background = '#e74c3c';
    document.getElementById('ai-feedback-header').style.color = '#fff';
    document.getElementById('ai-feedback-header').textContent = 'вҡ пёҸ Verbindingsfout';
    document.getElementById('ai-feedback-body').textContent = 'AI is tijdelijk niet beschikbaar. Vergelijk je antwoord zelf met het modelantwoord: ' + aiHuidigScenario.modelantwoord;
    document.getElementById('ai-feedback-wrap').style.display = 'block';
    aiFout++;
    aiUpdateScore();
  });
}

function aiUpdateScore(){
  var el1 = document.getElementById('ai-score-pogingen');
  var el2 = document.getElementById('ai-score-goed');
  var el3 = document.getElementById('ai-score-fout');
  if(el1) el1.textContent = aiPogingen + ' poging' + (aiPogingen === 1 ? '' : 'en');
  if(el2) el2.textContent = aiGoed + ' вң”';
  if(el3) el3.textContent = aiFout + ' вң–';
}

// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
// VRAAG-AANBOD SIMULATIE
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ
var SIM_LABELS = {'-2':'sterk lager','-1':'lager','0':'normaal','1':'hoger','2':'sterk hoger'};
var SIM_BELEID_LABELS = {'-2':'hoge belasting','-1':'lichte belasting','0':'geen','1':'kleine subsidie','2':'grote subsidie'};

// Scenario-vragen bij specifieke configuraties
var SIM_VRAGEN = [
  { a:-1, v:0, b:0, vraag:'Het aanbod daalt. Wat gebeurt er met de prijs?', opties:['Prijs daalt','Prijs stijgt','Prijs blijft gelijk'], correct:1, uitleg:'Minder aanbod bij gelijke vraag вҶ’ schaarste вҶ’ prijs stijgt.' },
  { a:0, v:1, b:0, vraag:'De vraag stijgt. Wat is het effect op de hoeveelheid?', opties:['Hoeveelheid daalt','Hoeveelheid blijft gelijk','Hoeveelheid stijgt'], correct:2, uitleg:'Meer vraag вҶ’ markt reageert met meer productie вҶ’ evenwichtshoeveelheid stijgt.' },
  { a:0, v:0, b:-1, vraag:'Er wordt een belasting geheven op dit product. Wie draagt de belasting?', opties:['Alleen de producent','Alleen de consument','Zowel producent als consument'], correct:2, uitleg:'Belasting verhoogt de prijs voor consumenten Г©n verlaagt de opbrengst voor producenten. De last wordt gedeeld.' },
  { a:0, v:0, b:1, vraag:'De overheid geeft subsidie. Wat verandert aan de aanbodlijn?', opties:['Aanbodlijn verschuift naar rechts (meer aanbod)','Aanbodlijn verschuift naar links','Vraaglijn verschuift naar rechts'], correct:0, uitleg:'Subsidie verlaagt productiekosten вҶ’ meer aanbod bij elke prijs вҶ’ aanbodlijn naar rechts.' },
  { a:1, v:0, b:0, vraag:'Technologie verbetert de productie. Hoe noem je dit effect?', opties:['Verschuiving van de vraaglijn','Verschuiving van de aanbodlijn','Beweging langs de aanbodlijn'], correct:1, uitleg:'Betere technologie verlaagt kosten вҶ’ meer aanbod bij dezelfde prijs вҶ’ aanbodlijn verschuift (geen beweging langs de lijn!).' },
  { a:0, v:-1, b:0, vraag:'Inkomens dalen door een recessie. Wat is het directe effect op de markt?', opties:['Vraag daalt вҶ’ prijs daalt','Vraag stijgt вҶ’ prijs daalt','Aanbod daalt вҶ’ prijs stijgt'], correct:0, uitleg:'Lagere inkomens вҶ’ minder koopkracht вҶ’ minder vraag вҶ’ bij gelijk aanbod daalt de prijs.' }
];

var simHuidigeVraag = null;

function simUpdate(){
  var a = parseInt(document.getElementById('sim-aanbod').value);
  var v = parseInt(document.getElementById('sim-vraag').value);
  var b = parseInt(document.getElementById('sim-beleid').value);

  document.getElementById('sim-a-lbl').textContent = SIM_LABELS[a] || 'normaal';
  document.getElementById('sim-v-lbl').textContent = SIM_LABELS[v] || 'normaal';
  document.getElementById('sim-b-lbl').textContent = SIM_BELEID_LABELS[b] || 'geen';

  // BasiscoГ¶rdinaten evenwicht (midden SVG: Q=115, P=75)
  var basisQ = 115, basisP = 75;
  // Aanbodshock: meer aanbod вҶ’ lager evenwichtsprijs, meer Q
  var dP = -a * 12 + v * 12 + b * 8; // prijs effect
  var dQ = a * 10 + v * 10 - b * 6; // hoeveelheids effect

  var eq = { x: Math.min(175, Math.max(45, basisQ + dQ)), y: Math.min(130, Math.max(20, basisP + dP)) };

  // Aanbodlijn: van links-laag naar rechts-hoog, verschuift horizontaal
  var aShift = a * 18 + b * 10;
  var vShift = v * 18;

  document.getElementById('sim-a-lijn').setAttribute('x1', 50 + aShift);
  document.getElementById('sim-a-lijn').setAttribute('x2', 180 + aShift);
  document.getElementById('sim-v-lijn').setAttribute('x1', 50 + vShift);
  document.getElementById('sim-v-lijn').setAttribute('x2', 180 + vShift);

  document.getElementById('sim-punt').setAttribute('cx', eq.x);
  document.getElementById('sim-punt').setAttribute('cy', eq.y);
  document.getElementById('sim-hline').setAttribute('x2', eq.x);
  document.getElementById('sim-hline').setAttribute('y1', eq.y);
  document.getElementById('sim-hline').setAttribute('y2', eq.y);
  document.getElementById('sim-vline').setAttribute('x1', eq.x);
  document.getElementById('sim-vline').setAttribute('x2', eq.x);
  document.getElementById('sim-vline').setAttribute('y1', eq.y);
  document.getElementById('sim-p-label').setAttribute('y', eq.y + 3);
  document.getElementById('sim-q-label').setAttribute('x', eq.x);

  // Prijs en hoeveelheid als index (100 = normaal)
  var prijsIdx = Math.round(100 + dP * -1.5);
  var qIdx = Math.round(100 + dQ * 1.2);

  var uitkomstTxt = '';
  if(a === 0 && v === 0 && b === 0){
    uitkomstTxt = '<span style="color:#27ae60;font-weight:700">вң… Evenwicht</span><br>Vraag = Aanbod. Geen overschot, geen tekort.';
  } else {
    var pTxt = dP < -3 ? 'рҹ”ҙ Prijs stijgt' : dP > 3 ? 'рҹҹў Prijs daalt' : 'рҹҹЎ Prijs weinig veranderd';
    var qTxt = dQ > 3 ? 'рҹ“Ҳ Meer verhandeld' : dQ < -3 ? 'рҹ“ү Minder verhandeld' : 'вҶ”пёҸ Hoeveelheid nauwelijks veranderd';
    uitkomstTxt = pTxt + '<br>' + qTxt + '<br><span style="font-size:.8rem;color:var(--muted)">Prijsindex: ~'+prijsIdx+' | Hoeveelheidsindex: ~'+qIdx+'</span>';
  }
  document.getElementById('sim-uitkomst').innerHTML = uitkomstTxt;

  // Zoek passende redeneer-vraag
  simZoekVraag(a, v, b);
}

function simZoekVraag(a, v, b){
  var match = null;
  for(var i = 0; i < SIM_VRAGEN.length; i++){
    var q = SIM_VRAGEN[i];
    if(Math.abs(q.a - a) <= 1 && Math.abs(q.v - v) <= 1 && Math.abs(q.b - b) <= 1 && !match) match = q;
  }
  if(!match && (a !== 0 || v !== 0 || b !== 0)){
    match = SIM_VRAGEN[Math.floor(Math.random() * SIM_VRAGEN.length)];
  }
  if(match && match !== simHuidigeVraag){
    simHuidigeVraag = match;
    document.getElementById('sim-vraag-tekst').textContent = match.vraag;
    document.getElementById('sim-feedback-tekst').style.display = 'none';
    var wrap = document.getElementById('sim-antwoord-wrap');
    wrap.innerHTML = '';
    match.opties.forEach(function(opt, idx){
      var btn = document.createElement('button');
      btn.textContent = opt;
      btn.style.cssText = 'background:var(--bg);border:2px solid #f59e0b;border-radius:20px;padding:.4rem .9rem;font-size:.83rem;font-family:"DM Sans",sans-serif;cursor:pointer;color:var(--fg);transition:background .15s';
      btn.onclick = (function(i, b){ return function(){ simCheckAntwoord(i, b); }; })(idx, btn);
      wrap.appendChild(btn);
    });
  } else if(a === 0 && v === 0 && b === 0){
    document.getElementById('sim-vraag-tekst').textContent = 'Versleep een schuifregelaar om een vraag te zien.';
    document.getElementById('sim-antwoord-wrap').innerHTML = '';
    document.getElementById('sim-feedback-tekst').style.display = 'none';
    simHuidigeVraag = null;
  }
}

function simScenario(a, v, b){
  document.getElementById('sim-aanbod').value = a;
  document.getElementById('sim-vraag').value = v;
  document.getElementById('sim-beleid').value = b;
  simUpdate();
}

function simCheckAntwoord(idx, btn){
  if(!simHuidigeVraag) return;
  var isGoed = idx === simHuidigeVraag.correct;
  var fb = document.getElementById('sim-feedback-tekst');
  fb.style.background = isGoed ? '#d1fae5' : '#fee2e2';
  fb.style.color = isGoed ? '#065f46' : '#991b1b';
  fb.innerHTML = (isGoed ? 'вң… Correct! ' : 'вқҢ Niet helemaal. ') + simHuidigeVraag.uitleg;
  fb.style.display = 'block';
  // Kleur alle knoppen
  var wrap = document.getElementById('sim-antwoord-wrap');
  Array.from(wrap.children).forEach(function(b, i){
    b.style.background = i === simHuidigeVraag.correct ? '#d1fae5' : (i === idx && !isGoed ? '#fee2e2' : 'var(--bg)');
    b.style.borderColor = i === simHuidigeVraag.correct ? '#27ae60' : (i === idx && !isGoed ? '#e74c3c' : '#f59e0b');
    b.disabled = true;
  });
}


/* в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ */


