// в”Җв”Җ BEGRIPPEN SUBMENU TOGGLE в”Җв”Җ
function toggleBegrippenMenu(e) {
  e.stopPropagation();
  const menu = document.getElementById('begrippen-submenu');
  const pijl = document.getElementById('begrippen-pijl');
  const wrap = document.getElementById('begrippen-wrap');
  if (!menu) return;
  const open = menu.style.display === 'block';
  menu.style.display = open ? 'none' : 'block';
  if (pijl) pijl.style.transform = open ? 'rotate(0deg)' : 'rotate(180deg)';
  if (wrap) wrap.setAttribute('aria-expanded', String(!open));
}
// Sluit submenu bij klik buiten
document.addEventListener('click', function(e) {
  const menu = document.getElementById('begrippen-submenu');
  const wrap = document.getElementById('begrippen-wrap');
  if (menu && menu.style.display === 'block' && wrap && !wrap.contains(e.target)) {
    menu.style.display = 'none';
    const pijl = document.getElementById('begrippen-pijl');
    if (pijl) pijl.style.transform = 'rotate(0deg)';
    wrap.setAttribute('aria-expanded', 'false');
  }
});


