// в•җв•җ NIEUWSTICKER v2.0 вҖ” live via rss2json (geen API-key nodig) в•җв•җ
// Bron: NOS Economie RSS-feed, omgezet naar JSON via rss2json.com (gratis tier)
const NIEUWS_RSS_URL = 'https://api.rss2json.com/v1/api.json?rss_url=https%3A%2F%2Ffeeds.nos.nl%2Fnosnieuwseconomie';
const NIEUWS_MAX     = 8;   // max aantal koppen in de ticker

// Fallback: 3 algemene economische koppen als de fetch mislukt
const NIEUWS_FALLBACK = [
  { title: 'Economie draait op volle toeren вҖ” werkloosheid op historisch laag niveau', url: 'https://www.nos.nl/economie' },
  { title: 'ECB bewaakt inflatiedoelstelling van 2% вҖ” rente blijft bepalend thema', url: 'https://www.nos.nl/economie' },
  { title: 'OverheidsfinanciГ«n onder druk: begrotingstekort en staatsschuld in debat', url: 'https://www.nos.nl/economie' },
];

async function laadNieuwsTicker() {
  const track = document.getElementById('nieuws-track');
  if (!track) return;

  let items = [];

  // Stap 1: probeer live nieuws op te halen via rss2json
  try {
    const resp = await fetch(NIEUWS_RSS_URL);
    if (resp.ok) {
      const data = await resp.json();
      if (data.status === 'ok' && Array.isArray(data.items) && data.items.length > 0) {
        items = data.items
          .slice(0, NIEUWS_MAX)
          .map(item => ({
            title: item.title.trim(),
            url:   item.link || 'https://www.nos.nl/economie'
          }));
      }
    }
  } catch (e) {
    // Geen internet of CORS-blokkering вҖ” valt automatisch terug op fallback
  }

  // Stap 2: bij mislukking of lege respons вҶ’ gebruik fallback
  if (items.length === 0) items = NIEUWS_FALLBACK;

  // Bouw de scrollende inhoud: dupliceer voor naadloze loop
  const maakItems = () => items.map(item =>
    `<a href="${ddEsc(item.url)}" target="_blank" rel="noopener noreferrer">${ddEsc(item.title)}</a><span class="sep">в—Ҷ</span>`
  ).join('');

  track.innerHTML = maakItems() + maakItems(); // dubbel voor vloeiende loop

  // Pas animatieduur aan op totale tekstlengte вҖ” langere teksten scrollen trager
  const totaalTekens = items.reduce((s, i) => s + i.title.length, 0);
  const duur = Math.max(30, Math.round(totaalTekens * 0.28));
  track.style.animationDuration = duur + 's';

  // Datum-label in de balk (behoud originele opmaak)
  const label = document.getElementById('nieuws-label');
  if (label) {
    const nu    = new Date();
    const datum = nu.toLocaleDateString('nl-NL', { weekday: 'short', day: 'numeric', month: 'short' });
    label.innerHTML = `рҹ“° Nieuws <span style="font-weight:400;opacity:.7;margin-left:4px">${datum}</span>`;
  }
}

// Laad bij start, ververs elk uur
document.addEventListener('DOMContentLoaded', () => {
  laadNieuwsTicker();
  setInterval(laadNieuwsTicker, 60 * 60 * 1000);
});


