(function(){
  const SB_URL = 'https://tarwtanlcinfstjfrdhd.supabase.co';
  const SB_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InRhcnd0YW5sY2luZnN0amZyZGhkIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzMyNDgwMTMsImV4cCI6MjA4ODgyNDAxM30.nj77xbc7vAm-FyYNIQsKS1RXLAr6A5n_sOEbi0MxHz4';
  // Initialiseer Supabase client
  let _sb = null;
  function getSB(){
    if(!_sb){
      try { _sb = supabase.createClient(SB_URL, SB_KEY); } catch(e){ console.warn('Supabase niet beschikbaar',e); }
    }
    return _sb;
  }

  // Sleutels die worden opgeslagen
  const VLA_KEYS = ['vla_scores','vla_done','vla_mode','vla_level','vla_streak',
    'vla_streak_last','vla_dm','vla_klascode','vla_er_progress'];

  function verzamelData(){
    const data = {};
    VLA_KEYS.forEach(k => {
      const v = localStorage.getItem(k);
      if(v !== null) data[k] = v;
    });
    // Pak ook alle vla_ sleutels die dynamisch zijn aangemaakt
    for(let i=0; i<localStorage.length; i++){
      const k = localStorage.key(i);
      if(k && k.startsWith('vla_') && !(k in data)) data[k] = localStorage.getItem(k);
    }
    return data;
  }

  function genereerCode(){
    const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789'; // geen verwarrende tekens
    let code = 'VLA';
    for(let i=0;i<3;i++) code += chars[Math.floor(Math.random()*chars.length)];
    return code;
  }

  function setFeedback(msg, type){
    const el = document.getElementById('kluis-feedback');
    if(!el) return;
    el.textContent = msg;
    el.className = type === 'ok' ? 'ok' : (type === 'err' ? 'err' : '');
  }

  window.openKluisModal = function(){
    const overlay = document.getElementById('kluis-modal-overlay');
    if(overlay) overlay.style.display = 'flex';
    document.getElementById('kluis-gegenereerde-code').textContent = 'вҖ”вҖ”';
    document.getElementById('kluis-code-input').value = '';
    setFeedback('','');
  };

  window.sluitKluisModal = function(){
    const overlay = document.getElementById('kluis-modal-overlay');
    if(overlay) overlay.style.display = 'none';
  };

  window.genereerKluiscode = async function(){
    const sb = getSB();
    if(!sb){ setFeedback('вқҢ Geen verbinding met de cloud. Probeer het later.','err'); return; }
    const codeEl = document.getElementById('kluis-gegenereerde-code');
    codeEl.textContent = 'вҖҰ';
    setFeedback('','');
    try {
      const code = genereerCode();
      const data = verzamelData();
      const { error } = await sb.from('kluisjes').upsert(
        { kluis_code: code, voortgang_data: data },
        { onConflict: 'kluis_code' }
      );
      if(error) throw error;
      codeEl.textContent = code;
      setFeedback('вң… Code opgeslagen! Noteer hem вҖ” hij is 24 uur geldig.','ok');
    } catch(e){
      codeEl.textContent = 'вҖ”вҖ”';
      setFeedback('вқҢ Opslaan mislukt: ' + (e.message || 'onbekende fout'),'err');
    }
  };

  window.laadKluiscode = async function(){
    const sb = getSB();
    if(!sb){ setFeedback('вқҢ Geen verbinding met de cloud. Probeer het later.','err'); return; }
    const code = (document.getElementById('kluis-code-input').value || '').trim().toUpperCase();
    if(code.length < 3){ setFeedback('вҡ пёҸ Vul een geldige kluiscode in.','err'); return; }
    setFeedback('Gegevens ophalenвҖҰ','');
    try {
      const { data, error } = await sb
        .from('kluisjes')
        .select('voortgang_data')
        .eq('kluis_code', code)
        .single();
      if(error || !data) throw new Error('Code niet gevonden');
      const vd = data.voortgang_data;
      if(typeof vd !== 'object' || vd === null) throw new Error('Ongeldige data');
      // Schrijf naar localStorage
      Object.entries(vd).forEach(([k,v]) => localStorage.setItem(k, v));
      setFeedback('вң… Voortgang geladen! De pagina wordt herladenвҖҰ','ok');
      setTimeout(() => { window.location.reload(); }, 1200);
    } catch(e){
      const msg = e.message === 'Code niet gevonden'
        ? 'вқҢ Code niet gevonden. Controleer of je hem goed hebt overgetypt.'
        : 'вқҢ Ophalen mislukt: ' + (e.message || 'onbekende fout');
      setFeedback(msg,'err');
    }
  };

  // Sluit modal met Escape-toets
  document.addEventListener('keydown', e => {
    if(e.key === 'Escape') window.sluitKluisModal();
  });
})();
